#[derive(Clone)]
pub struct TypableCommand {
    pub name: &'static str,
    pub aliases: &'static [&'static str],
    pub doc: &'static str,
    // params, flags, helper, completer
    pub fun: fn(&mut compositor::Context, Args, PromptEvent) -> anyhow::Result<()>,
    /// What completion methods, if any, does this command have?
    pub completer: CommandCompleter,
    pub signature: Signature,
}

#[derive(Clone)]
pub struct CommandCompleter {
    // Arguments with specific completion methods based on their position.
    positional_args: &'static [Completer],

    // All remaining arguments will use this completion method, if set.
    var_args: Completer,
}

impl CommandCompleter {
    const fn none() -> Self {
        Self {
            positional_args: &[],
            var_args: completers::none,
        }
    }

    const fn positional(completers: &'static [Completer]) -> Self {
        Self {
            positional_args: completers,
            var_args: completers::none,
        }
    }

    const fn all(completer: Completer) -> Self {
        Self {
            positional_args: &[],
            var_args: completer,
        }
    }

    fn for_argument_number(&self, n: usize) -> &Completer {
        match self.positional_args.get(n) {
            Some(completer) => completer,
            _ => &self.var_args,
        }
    }
}

fn exit(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }

    if doc!(cx.editor).is_modified() {
        write_impl(
            cx,
            args.first(),
            WriteOptions {
                force: false,
                auto_format: !args.has_flag(WRITE_NO_FORMAT_FLAG.name),
                code_actions: !args.has_flag(WRITE_NO_CODE_ACTIONS_FLAG.name),
            },
        )?;
    }
    cx.block_try_flush_writes()?;
    quit(cx, Args::default(), event)
}

fn force_exit(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }

    if doc!(cx.editor).is_modified() {
        write_impl(
            cx,
            args.first(),
            WriteOptions {
                force: true,
                auto_format: !args.has_flag(WRITE_NO_FORMAT_FLAG.name),
                code_actions: !args.has_flag(WRITE_NO_CODE_ACTIONS_FLAG.name),
            },
        )?;
    }
    cx.block_try_flush_writes()?;
    quit(cx, Args::default(), event)
}

fn quit(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    log::debug!("quitting...");

    if event != PromptEvent::Validate {
        return Ok(());
    }

    // last view and we have unsaved changes
    if cx.editor.tree.views().count() == 1 {
        if let Err(err) = buffers_remaining_impl(cx.editor) {
            // vim `confirm`: don't refuse — ask, and act on the answer.
            if confirm_unsaved(cx, false) {
                return Ok(());
            }
            return Err(err);
        }
    }

    cx.block_try_flush_writes()?;
    cx.editor.close(view!(cx.editor).id);

    Ok(())
}

/// vim `confirm`: a command that would abandon unsaved buffers raises a dialog
/// instead of failing. Returns whether the dialog was raised (the caller must
/// then report no error: the answer decides what happens).
///
/// The prompt is pushed through the job queue because a typable command has no
/// direct handle on the compositor. `all` picks which quit the answer resumes.
fn confirm_unsaved(cx: &mut compositor::Context, all: bool) -> bool {
    // The `:confirm {cmd}` modifier forces the dialog on for this one command.
    if !vim_opt_bool("confirm") && !cmd_mods().confirm {
        return false;
    }
    let names: Vec<String> = cx
        .editor
        .documents()
        .filter(|doc| doc.is_modified())
        .map(|doc| doc.display_name().into_owned())
        .collect();
    if names.is_empty() {
        return false;
    }
    let question = format!(
        "Save changes to {}? [y]es/[n]o/[c]ancel: ",
        names.join(", ")
    );
    let call: job::Callback = job::Callback::EditorCompositor(Box::new(
        move |_editor: &mut Editor, compositor: &mut Compositor| {
            let prompt = Prompt::new(
                question.into(),
                None,
                ui::completers::none,
                move |cx: &mut compositor::Context, input: &str, event: PromptEvent| {
                    if event != PromptEvent::Validate {
                        return;
                    }
                    let answer = input.trim().chars().next().unwrap_or('c');
                    let write = WriteAllOptions {
                        force: false,
                        write_scratch: false,
                        auto_format: true,
                        code_actions: false,
                    };
                    let result = match answer.to_ascii_lowercase() {
                        // Write every modified buffer, then quit as asked.
                        'y' => write_all_impl(cx, write).and_then(|()| force_quit_scope(cx, all)),
                        // Quit, dropping the changes.
                        'n' => force_quit_scope(cx, all),
                        // Anything else cancels, as vim's dialog does.
                        _ => {
                            cx.editor.set_status("cancelled");
                            Ok(())
                        }
                    };
                    if let Err(err) = result {
                        cx.editor.set_error(err.to_string());
                    }
                },
            );
            compositor.push(Box::new(prompt));
        },
    ));
    cx.jobs.callback(async move { Ok(call) });
    true
}

/// Ask for the argument a command needs and then run it, as emacs' minibuffer and
/// vim's `:` line do. This is what makes the zero-argument form of an
/// argument-taking command usable from a *key*: `M-:` (eval-expression) or
/// `C-x i` (insert-file) carry no argument, so without a prompt they could only
/// fail. `command` is the `:`-name to run with the typed text appended, parsed by
/// that command's own signature (so a raw-tail command still gets its tail raw).
///
/// The prompt is pushed through the job queue because a typable command has no
/// direct handle on the compositor (same route as [`confirm_unsaved`]).
fn prompt_for_arg(
    cx: &mut compositor::Context,
    question: &'static str,
    command: &'static str,
    completer: Completer,
) {
    let call: job::Callback = job::Callback::EditorCompositor(Box::new(
        move |_editor: &mut Editor, compositor: &mut Compositor| {
            let prompt = Prompt::new(
                question.into(),
                None,
                completer,
                move |cx: &mut compositor::Context, input: &str, event: PromptEvent| {
                    if event != PromptEvent::Validate {
                        return;
                    }
                    let input = input.trim();
                    if input.is_empty() {
                        cx.editor.set_status("cancelled");
                        return;
                    }
                    let Some(cmd) = TYPABLE_COMMAND_MAP.get(command) else {
                        cx.editor.set_error(format!(":{command} is not registered"));
                        return;
                    };
                    if let Err(err) = execute_command(cx, cmd, input, PromptEvent::Validate) {
                        cx.editor.set_error(err.to_string());
                    }
                },
            );
            compositor.push(Box::new(prompt));
        },
    ));
    cx.jobs.callback(async move { Ok(call) });
}

/// Close the current view (or every view) without the unsaved-buffer check — the
/// vim `confirm` dialog has already asked.
fn force_quit_scope(cx: &mut compositor::Context, all: bool) -> anyhow::Result<()> {
    if all {
        return quit_all_impl(cx, true);
    }
    cx.block_try_flush_writes()?;
    cx.editor.close(view!(cx.editor).id);
    Ok(())
}

fn force_quit(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }

    cx.block_try_flush_writes()?;
    cx.editor.close(view!(cx.editor).id);

    Ok(())
}

/// vim `:visual` / `:vi` — "When used in Ex mode: Leave Ex-mode, go back to
/// Normal mode. Otherwise same as `:edit`" (editing.txt).
///
/// Both halves, because it is one command in vim: in Ex mode it is the only way
/// out (`gQ` re-opens the `:` line after everything else, Esc included), and
/// outside it, it edits.
fn ex_visual(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    if cx.editor.ex_mode {
        cx.editor.ex_mode = false;
        // Leaving is the whole command here; vim ignores a file argument on the
        // way out rather than editing it.
        return Ok(());
    }
    if args.is_empty() {
        bail!("usage: :visual <file> (outside Ex mode, :visual edits a file)");
    }
    open(cx, args, event)
}

fn open(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }

    open_impl(cx, args, Action::Replace)
}

/// vim `:close` — close the current window (split). Unlike `:quit`, it refuses to
/// close the last window rather than quitting the editor.
fn window_close(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    if cx.editor.tree.views().count() == 1 {
        anyhow::bail!("cannot close last window");
    }
    cx.editor.close(view!(cx.editor).id);
    Ok(())
}

/// vim `:only` — make the current window the only one by closing every other
/// split. The current view and its buffer stay open.
fn window_only(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let this = view!(cx.editor).id;
    let others: Vec<_> = cx
        .editor
        .tree
        .views()
        .map(|(v, _)| v.id)
        .filter(|&id| id != this)
        .collect();
    for id in others {
        cx.editor.close(id);
    }
    Ok(())
}

// ---------------------------------------------------------------------------
// Vim command modifiers (`:h :command-modifiers`): `:vertical split`,
// `:tab drop`, `:silent w`, `:noautocmd e`, `:confirm q`, `:sandbox !cmd`.
// A modifier does not act on its own: it prefixes another Ex command and changes
// *how* that command runs. Each is a command taking the rest of the line raw; it
// publishes its flag in `CMD_MODS` and dispatches the remainder, so modifiers
// chain (`:silent! noautocmd vert new`) by re-entering the dispatcher. Every
// field below names the one consumer that reads it — a modifier with no consumer
// would be a lie, so there is none.
// ---------------------------------------------------------------------------

/// The command modifiers in effect for the Ex command currently running.
#[derive(Clone, Copy, Default, PartialEq, Eq, Debug)]
struct CmdMods {
    /// `:vertical` / `:horizontal` — force the direction of a window the command
    /// opens. Consumed by [`split_mod`].
    split: Option<SplitDir>,
    /// `:tab` — open a new tab page instead of splitting. Consumed by [`split_mod`].
    tab: bool,
    /// `:silent` — discard the command's status message. Consumed by
    /// `run_with_modifiers`.
    silent: bool,
    /// `:silent!` — also swallow the command's error. Consumed by `run_with_modifiers`.
    silent_bang: bool,
    /// `:noautocmd` — don't fire autocommands. Consumed by [`fire_autocmd`].
    noautocmd: bool,
    /// `:confirm` — force 'confirm' on for this command. Consumed by [`confirm_unsaved`].
    confirm: bool,
    /// `:sandbox` — refuse to shell out or write a file. Consumed by
    /// [`sandbox_check`] (`:!`, `:make`, `:grep`, `:w`, …).
    sandbox: bool,
    /// `:aboveleft`/`:leftabove`/`:topleft` (before) and `:belowright`/
    /// `:rightbelow`/`:botright` (after) — which side of the current window a
    /// window the command opens lands on, overriding `splitbelow`/`splitright`.
    /// Consumed by [`apply_placement`].
    placement: Option<Placement>,
    /// `:topleft` / `:botright` — push the new window as far as it goes in the
    /// placement direction, not just past the current one. Consumed by
    /// [`apply_placement`].
    placement_extreme: bool,
    /// `:keepalt` — the command leaves the alternate file (`C-^`) alone.
    /// Consumed by [`snapshot_keeps`] / [`restore_keeps`].
    keepalt: bool,
    /// `:keepjumps` — the command leaves the jumplist alone. Consumed by
    /// [`snapshot_keeps`] / [`restore_keeps`].
    keepjumps: bool,
    /// `:keepmarks` / `:lockmarks` — the command leaves every mark (named and the
    /// auto-marks `.`/`[`/`]`) where it was. Consumed by [`snapshot_keeps`] /
    /// [`restore_keeps`].
    keepmarks: bool,
    /// `:keeppatterns` — the command leaves the last search pattern alone.
    /// Consumed by [`snapshot_keeps`] / [`restore_keeps`].
    keeppatterns: bool,
    /// `:noswapfile` — the command doesn't touch the recovery swap file. Consumed
    /// by `:edit` (no E325 recovery check) and `:write` (the saved buffer's swap
    /// file is left in place).
    noswapfile: bool,
}

/// The direction `:vertical` / `:horizontal` force a window-opening command into.
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
enum SplitDir {
    Vertical,
    Horizontal,
}

/// Which side of the current window `:aboveleft` & co. put a new one on. `Before`
/// is up/left, `After` is down/right — vim's placement modifiers name both the
/// horizontal and the vertical case at once, and which one applies is decided by
/// the split the command performs.
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
enum Placement {
    Before,
    After,
}

thread_local! {
    /// Modifiers of the Ex command currently running (empty for a bare command).
    static CMD_MODS: std::cell::Cell<CmdMods> = const { std::cell::Cell::new(CmdMods {
        split: None,
        tab: false,
        silent: false,
        silent_bang: false,
        noautocmd: false,
        confirm: false,
        sandbox: false,
        placement: None,
        placement_extreme: false,
        keepalt: false,
        keepjumps: false,
        keepmarks: false,
        keeppatterns: false,
        noswapfile: false,
    }) };
}

fn cmd_mods() -> CmdMods {
    CMD_MODS.with(|m| m.get())
}

/// Merge one modifier into the ones already in effect, so a chain accumulates
/// (`:silent! noautocmd vert new` reaches `:new` with all three set). `:unsilent`
/// is the only one that *clears* — it cancels an enclosing `:silent`. Pure —
/// unit tested.
fn merge_cmd_mod(mods: CmdMods, kind: ModKind, bang: bool) -> CmdMods {
    let mut m = mods;
    match kind {
        ModKind::Vertical => m.split = Some(SplitDir::Vertical),
        ModKind::Horizontal => m.split = Some(SplitDir::Horizontal),
        ModKind::Tab => m.tab = true,
        ModKind::Silent => {
            m.silent = true;
            m.silent_bang = bang;
        }
        ModKind::Unsilent => {
            m.silent = false;
            m.silent_bang = false;
        }
        ModKind::NoAutocmd => m.noautocmd = true,
        ModKind::Confirm => m.confirm = true,
        ModKind::Sandbox => m.sandbox = true,
        // Placement: the innermost modifier wins (vim keeps the last one), and
        // `:topleft`/`:botright` additionally push the window to the far edge.
        ModKind::AboveLeft => {
            m.placement = Some(Placement::Before);
            m.placement_extreme = false;
        }
        ModKind::BelowRight => {
            m.placement = Some(Placement::After);
            m.placement_extreme = false;
        }
        ModKind::TopLeft => {
            m.placement = Some(Placement::Before);
            m.placement_extreme = true;
        }
        ModKind::BotRight => {
            m.placement = Some(Placement::After);
            m.placement_extreme = true;
        }
        ModKind::KeepAlt => m.keepalt = true,
        ModKind::KeepJumps => m.keepjumps = true,
        ModKind::KeepMarks => m.keepmarks = true,
        ModKind::KeepPatterns => m.keeppatterns = true,
        ModKind::NoSwapFile => m.noswapfile = true,
    }
    m
}

/// Which modifier a `:`-command is.
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
enum ModKind {
    Vertical,
    Horizontal,
    Tab,
    Silent,
    Unsilent,
    NoAutocmd,
    Confirm,
    Sandbox,
    AboveLeft,
    BelowRight,
    TopLeft,
    BotRight,
    KeepAlt,
    KeepJumps,
    KeepMarks,
    KeepPatterns,
    NoSwapFile,
}

/// One view's alternate-file state: the view, the two documents `C-^` picks the
/// alternate from, and the access history that feeds them.
type AltState = (
    zmax_view::ViewId,
    [Option<zmax_view::DocumentId>; 2],
    Vec<zmax_view::DocumentId>,
);

/// The editor state the `:keep…` modifiers protect, captured before the wrapped
/// command runs. Each field is `Some` only when its modifier asked for it, so a
/// bare command captures nothing.
#[derive(Default)]
struct KeepState {
    /// `:keepjumps` — every view's jumplist.
    jumps: Option<Vec<(zmax_view::ViewId, zmax_view::view::JumpList)>>,
    /// `:keepalt` — every view's alternate-file state (`C-^` / `:balt` read
    /// `last_modified_docs`; `docs_access_history` feeds it).
    alt: Option<Vec<AltState>>,
    /// `:keepmarks` / `:lockmarks` — every document's marks.
    marks: Option<Vec<(zmax_view::DocumentId, HashMap<char, usize>)>>,
    /// `:keeppatterns` — the last-search register's contents (`None` inside the
    /// `Some` when no search has been made yet).
    search: Option<(char, Option<Vec<String>>)>,
}

/// Capture the state the `:keep…` modifiers in `mods` promise not to change.
fn snapshot_keeps(editor: &Editor, mods: CmdMods) -> KeepState {
    let mut keep = KeepState::default();
    if mods.keepjumps {
        keep.jumps = Some(
            editor
                .tree
                .views()
                .map(|(view, _)| (view.id, view.jumps.clone()))
                .collect(),
        );
    }
    if mods.keepalt {
        keep.alt = Some(
            editor
                .tree
                .views()
                .map(|(view, _)| {
                    (
                        view.id,
                        view.last_modified_docs,
                        view.docs_access_history.clone(),
                    )
                })
                .collect(),
        );
    }
    if mods.keepmarks {
        keep.marks = Some(
            editor
                .documents()
                .map(|doc| (doc.id(), doc.marks().clone()))
                .collect(),
        );
    }
    if mods.keeppatterns {
        let name = editor.registers.last_search_register;
        let values = editor
            .registers
            .read(name, editor)
            .map(|values| values.map(|v| v.into_owned()).collect());
        keep.search = Some((name, values));
    }
    keep
}

/// Put back what [`snapshot_keeps`] captured, so the wrapped command's effect on
/// the jumplist / alternate file / marks / search pattern is undone while the rest
/// of what it did stands. Views and documents the command closed are skipped; ones
/// it opened keep whatever they were born with.
fn restore_keeps(editor: &mut Editor, keep: KeepState) {
    if let Some(jumps) = keep.jumps {
        for (id, list) in jumps {
            if editor.tree.contains(id) {
                editor.tree.get_mut(id).jumps = list;
            }
        }
    }
    if let Some(alt) = keep.alt {
        for (id, last_modified, history) in alt {
            if editor.tree.contains(id) {
                let view = editor.tree.get_mut(id);
                view.last_modified_docs = last_modified;
                view.docs_access_history = history;
            }
        }
    }
    if let Some(marks) = keep.marks {
        for (id, marks) in marks {
            let Some(doc) = editor.documents.get_mut(&id) else {
                continue;
            };
            let now: Vec<char> = doc.marks().keys().copied().collect();
            for mark in now {
                if !marks.contains_key(&mark) {
                    doc.remove_mark(mark);
                }
            }
            for (&mark, &pos) in &marks {
                doc.set_mark(mark, pos);
            }
        }
    }
    if let Some((name, values)) = keep.search {
        match values {
            Some(values) => {
                let _ = editor.registers.write(name, values);
            }
            None => {
                editor.registers.remove(name);
            }
        }
    }
}

/// Run the Ex command `line` with `kind` added to the modifiers already in
/// effect, restoring them after. `:silent` drops whatever status message the
/// command left (restoring the one that was on screen); `:silent!` additionally
/// swallows its error.
fn run_with_modifier(
    cx: &mut compositor::Context,
    kind: ModKind,
    bang: bool,
    line: &str,
) -> anyhow::Result<()> {
    let line = line.trim();
    if line.is_empty() {
        bail!("a command modifier needs a command to modify");
    }
    let outer = cmd_mods();
    let mods = merge_cmd_mod(outer, kind, bang);
    CMD_MODS.with(|m| m.set(mods));
    let saved = mods.silent.then(|| cx.editor.status_msg.take());
    let keep = snapshot_keeps(cx.editor, mods);
    // `:aboveleft` & co. can only be applied once the window exists, so remember
    // which windows there were and where the focus sat.
    let before: Vec<zmax_view::ViewId> = if mods.placement.is_some() {
        cx.editor.tree.views().map(|(v, _)| v.id).collect()
    } else {
        Vec::new()
    };
    let result = execute_command_line(cx, line, PromptEvent::Validate);
    if mods.placement.is_some() {
        apply_placement(cx.editor, mods, &before);
    }
    restore_keeps(cx.editor, keep);
    CMD_MODS.with(|m| m.set(outer));
    if let Some(saved) = saved {
        cx.editor.status_msg = saved;
        if mods.silent_bang {
            return Ok(());
        }
    }
    result
}

/// vim `:aboveleft` / `:leftabove` / `:belowright` / `:rightbelow` / `:topleft` /
/// `:botright` — put the window the wrapped command just opened on the side the
/// modifier names, whatever `splitbelow` / `splitright` would have done.
///
/// The split itself is `Editor::open`'s to make (it reads those two options), so
/// the placement is corrected here afterwards: if the new window landed on the
/// wrong side of its neighbour, it is swapped with it — which moves the window,
/// keeps the focus on it, and leaves the layout otherwise intact.
/// `:topleft`/`:botright` keep swapping until the window is at the far edge in
/// that direction (vim spans the whole editor there; zmax reaches the edge of
/// the row/column the window is in, which is the same thing whenever the split is
/// the outermost one).
fn apply_placement(editor: &mut Editor, mods: CmdMods, before: &[zmax_view::ViewId]) {
    let Some(placement) = mods.placement else {
        return;
    };
    let focus = editor.tree.focus;
    // Only a *new* window can be placed, and the command must have focused it
    // (every window-opening command does). `:tab {cmd}` opened a tab page instead:
    // the window is alone there, and there is nothing to place it against.
    if before.contains(&focus) || !editor.tree.contains(focus) {
        return;
    }
    let Some(new_area) = editor.tree.try_get(focus).map(|v| v.area) else {
        return;
    };
    // Which way the split went: a window stacked on top of / below its neighbour
    // shares its columns; one beside it shares its rows.
    let sibling = editor
        .tree
        .views()
        .find(|(v, _)| v.id != focus && before.contains(&v.id))
        .map(|(v, _)| v.area);
    let Some(sibling) = sibling else { return };
    let vertical_stack = sibling.x == new_area.x && sibling.width == new_area.width;
    let (toward, at_edge) = match (vertical_stack, placement) {
        (true, Placement::Before) => (zmax_view::tree::Direction::Up, new_area.y <= sibling.y),
        (true, Placement::After) => (zmax_view::tree::Direction::Down, new_area.y >= sibling.y),
        (false, Placement::Before) => (zmax_view::tree::Direction::Left, new_area.x <= sibling.x),
        (false, Placement::After) => (zmax_view::tree::Direction::Right, new_area.x >= sibling.x),
    };
    // `:aboveleft`/`:belowright` only need the new window on the right side of the
    // window it was split off; `:topleft`/`:botright` push it all the way out.
    if !at_edge {
        editor.tree.swap_split_in_direction(toward);
    }
    if mods.placement_extreme {
        // Bounded by the window count: every swap moves the window one slot, and
        // there is nowhere left to go once `swap_split_in_direction` finds nothing.
        let windows = editor.tree.views().count();
        for _ in 0..windows {
            if editor.tree.swap_split_in_direction(toward).is_none() {
                break;
            }
        }
    }
    editor.tree.recalculate();
}

/// Define a command modifier: it takes the rest of the line raw and runs it with
/// the modifier in effect.
macro_rules! cmd_mod {
    ($fn:ident, $kind:expr, $bang:literal) => {
        fn $fn(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
            if event != PromptEvent::Validate {
                return Ok(());
            }
            run_with_modifier(cx, $kind, $bang, &args.join(" "))
        }
    };
}

cmd_mod!(ex_mod_vertical, ModKind::Vertical, false);
cmd_mod!(ex_mod_horizontal, ModKind::Horizontal, false);
cmd_mod!(ex_mod_tab, ModKind::Tab, false);
cmd_mod!(ex_mod_silent, ModKind::Silent, false);
cmd_mod!(ex_mod_silent_bang, ModKind::Silent, true);
cmd_mod!(ex_mod_unsilent, ModKind::Unsilent, false);
cmd_mod!(ex_mod_noautocmd, ModKind::NoAutocmd, false);
cmd_mod!(ex_mod_confirm, ModKind::Confirm, false);
cmd_mod!(ex_mod_sandbox, ModKind::Sandbox, false);
cmd_mod!(ex_mod_aboveleft, ModKind::AboveLeft, false);
cmd_mod!(ex_mod_belowright, ModKind::BelowRight, false);
cmd_mod!(ex_mod_topleft, ModKind::TopLeft, false);
cmd_mod!(ex_mod_botright, ModKind::BotRight, false);
cmd_mod!(ex_mod_keepalt, ModKind::KeepAlt, false);
cmd_mod!(ex_mod_keepjumps, ModKind::KeepJumps, false);
cmd_mod!(ex_mod_keepmarks, ModKind::KeepMarks, false);
cmd_mod!(ex_mod_keeppatterns, ModKind::KeepPatterns, false);
cmd_mod!(ex_mod_noswapfile, ModKind::NoSwapFile, false);

/// Apply `:vertical` / `:horizontal` / `:tab` to the `action` a command is about
/// to open a window with. Non-window actions (`Replace`, `Load`) pass through
/// untouched, so `:vertical edit foo` does not split — exactly as in vim, where
/// a modifier only bites when the command opens a window. `:tab` opens the new
/// tab here (and the command then fills it), and is consumed so a command that
/// opens several windows only gets one tab.
fn split_mod(editor: &mut Editor, action: Action) -> Action {
    if !matches!(action, Action::HorizontalSplit | Action::VerticalSplit) {
        return action;
    }
    let mods = cmd_mods();
    if mods.tab {
        CMD_MODS.with(|m| {
            let mut cur = m.get();
            cur.tab = false;
            m.set(cur);
        });
        editor.new_tab();
        return Action::Replace;
    }
    match mods.split {
        Some(SplitDir::Vertical) => Action::VerticalSplit,
        Some(SplitDir::Horizontal) => Action::HorizontalSplit,
        None => action,
    }
}

/// vim `:sandbox {cmd}` — commands that shell out or write a file are refused
/// (E48). Called by every such command before it acts.
fn sandbox_check(what: &str) -> anyhow::Result<()> {
    if cmd_mods().sandbox {
        bail!("E48: Not allowed in sandbox: {what}");
    }
    Ok(())
}

fn open_impl(cx: &mut compositor::Context, args: Args, action: Action) -> anyhow::Result<()> {
    let action = split_mod(cx.editor, action);
    for arg in args {
        let (path, pos) = crate::args::parse_file(&arg);
        let path = zmax_stdx::path::expand_tilde(path);
        // If the path is a directory, open a file picker on that directory and update the status
        // message
        if let Ok(true) = std::fs::canonicalize(&path).map(|p| p.is_dir()) {
            let callback = async move {
                let call: job::Callback = job::Callback::EditorCompositor(Box::new(
                    move |editor: &mut Editor, compositor: &mut Compositor| {
                        let picker =
                            ui::file_picker(editor, path.into_owned()).with_default_action(action);
                        compositor.push(Box::new(overlaid(picker)));
                    },
                ));
                Ok(call)
            };
            cx.jobs.callback(callback);
        } else {
            // Otherwise, just open the file — a binary file opens in the hex
            // editor instead of being rejected.
            match cx.editor.open(&path, action) {
                Ok(_) => {}
                Err(zmax_view::DocumentOpenError::BinaryFile) => {
                    push_hex_view(cx, path.into_owned());
                    continue;
                }
                Err(e) => return Err(e.into()),
            }
            let (view, doc) = current!(cx.editor);
            // Only jump to an explicit `path:line:col`; for a bare `:e file` leave
            // the cursor where `open` placed it (the vim `` `" `` last-position
            // restore), rather than snapping it back to the top.
            if pos != zmax_core::Position::default() {
                let sel = Selection::point(pos_at_coords(doc.text().slice(..), pos, true));
                doc.set_selection(view.id, sel);
                align_view(doc, view, Align::Center);
            }
        }
    }
    // vim `undofile`: reload a matching persisted undo history for the buffer.
    let cfg = cx.editor.config();
    if cfg.undofile {
        let undo_dir = cfg.undo_dir.clone();
        let (_view, doc) = current!(cx.editor);
        crate::vim_undo::load(doc, &undo_dir);
    }
    // vim `swapfile`: warn if a swap file already exists (recovery, vim E325).
    // `:noswapfile edit …` opens the file without any swap-file handling, so the
    // recovery check is skipped too — and the buffer is remembered, so the
    // periodic swap writer never grows one for it behind the user's back either.
    if cmd_mods().noswapfile {
        let id = doc!(cx.editor).id();
        crate::vim_swap::set_no_swap(id);
    } else if cx.editor.config().swapfile {
        let exists = {
            let (_view, doc) = current_ref!(cx.editor);
            crate::vim_swap::swap_exists(doc)
        };
        if exists {
            cx.editor
                .set_error("swap file already exists (recovery) — :w overwrites it");
        }
    }
    // vim: entering a buffer swaps its `:setlocal` values into the option store
    // over the `:setglobal` defaults, so every option reader sees the buffer in
    // focus. Before the autocmds, which may themselves `:setlocal` (the
    // `autocmd BufRead *.rs setlocal sw=4` idiom) and must win over the swap.
    {
        let local = doc!(cx.editor).vim_local_opts.clone();
        vim_opts_enter_buffer(cx.editor, &local);
    }
    // vim autocmd: a file was read into / entered a window.
    fire_autocmd(cx, "BufReadPost");
    fire_autocmd(cx, "BufEnter");
    // vim `foldmethod=expr`: the new buffer's folds come from 'foldexpr'.
    apply_foldexpr(cx);
    Ok(())
}

/// vim `:pedit {file}` — edit `{file}` in the preview window: *the* window
/// 'previewwindow' names. When one is already open (this command opened it, a
/// `:ptag` did, or `:set previewwindow` marked a window as it) the file replaces
/// its contents rather than stacking another split — which is the whole point of
/// vim having one preview window instead of N. With none open, the split this
/// opens becomes it.
fn preview_edit(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    // vim: "The current window and cursor position isn't changed" (windows.txt).
    // A preview you have to step out of is not a preview — the point is to see
    // the file *while* staying where you are, which is why `CTRL-W P` exists to
    // reach it deliberately.
    let origin = cx.editor.tree.focus;
    match preview_view(cx.editor) {
        Some(id) => {
            cx.editor.focus(id);
            open_impl(cx, args, Action::Replace)?;
        }
        None => {
            open_impl(cx, args, Action::HorizontalSplit)?;
            mark_preview_window(cx.editor, true);
        }
    }
    apply_previewheight(cx.editor);
    // Both arms above land in the preview window (a split focuses what it opens),
    // so hand the focus back to where the command was run from.
    if cx.editor.tree.contains(origin) {
        cx.editor.focus(origin);
    }
    Ok(())
}

// --- vim 'previewwindow' -----------------------------------------------------
//
// 'previewwindow' is window-local in vim: it is on for exactly one window — the
// preview window — which `:pedit`/`:ptag` fill and `:pclose` closes. zmax holds
// that mark as the id of the window it names, so the option is not just stored:
// `:set previewwindow` moves the mark onto the focused window, `:set
// nopreviewwindow` takes it off, and `:set previewwindow?` answers for the window
// you are in. A window that is closed by other means drops the mark with it (the
// id no longer resolves), so a stale mark can never send `:pclose` at a window
// that has since become something else.
thread_local! {
    static PREVIEW_VIEW: std::cell::Cell<Option<zmax_view::ViewId>> =
        const { std::cell::Cell::new(None) };
}

/// The preview window, if the marked one is still open.
pub(crate) fn preview_view(editor: &Editor) -> Option<zmax_view::ViewId> {
    PREVIEW_VIEW
        .with(|p| p.get())
        .filter(|id| editor.tree.contains(*id))
}

/// vim `:set previewwindow?` — whether the focused window is the preview window.
fn is_preview_window(editor: &Editor) -> bool {
    preview_view(editor) == Some(editor.tree.focus)
}

/// vim `:set previewwindow` / `:set nopreviewwindow` — make the focused window
/// the preview window, or stop it being one.
fn mark_preview_window(editor: &Editor, on: bool) {
    PREVIEW_VIEW.with(|p| p.set(on.then_some(editor.tree.focus)));
}

/// vim `:pclose` — close the preview window. It closes *the* preview window from
/// wherever it is run, which is what makes the command worth having: the whole
/// point is to dismiss a preview you are not in. With no preview window open it
/// closes the focused split, which is what `:pclose` did before the mark existed.
fn ex_pclose(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    match preview_view(cx.editor) {
        Some(id) => {
            cx.editor.close(id);
            PREVIEW_VIEW.with(|p| p.set(None));
        }
        None => super::wclose(&mut editor_context(cx)),
    }
    Ok(())
}

/// vim `previewheight`: the preview window `:pedit` just opened is resized to
/// this many rows (vim opens the preview window that tall). Unset — the default —
/// leaves the split at whatever height the window tree gave it.
fn apply_previewheight(editor: &mut Editor) {
    let Some(rows) = vim_opt_num("previewheight").filter(|rows| *rows > 0) else {
        return;
    };
    let view = editor.tree.focus;
    let delta = rows as i16 - editor.tree.node_height(view) as i16;
    if delta != 0 {
        editor.tree.resize_vertical(view, delta);
    }
}

/// One entry of vim's 'path', resolved against the current buffer's directory and
/// the working directory: a directory to look in, and whether to search it
/// recursively (the `**` suffix).
#[derive(Debug, PartialEq, Eq)]
struct PathEntry {
    dir: std::path::PathBuf,
    recursive: bool,
}

/// Expand a vim 'path' value into the directories `:find` searches, in order.
/// Vim's forms: `.` = the current buffer's directory, an empty entry = the
/// working directory, `**` (alone or as a suffix) = search that directory
/// recursively, anything else = a literal directory (`~` expanded). Pure — unit
/// tested.
fn parse_path_option(
    spec: &str,
    bufdir: Option<&std::path::Path>,
    cwd: &std::path::Path,
) -> Vec<PathEntry> {
    let mut out = Vec::new();
    for raw in spec.split(',') {
        let entry = raw.trim();
        // vim allows `**` and `**N`; zmax walks the whole tree either way.
        let (base, recursive) = match entry.find("**") {
            Some(i) => (entry[..i].trim_end_matches('/'), true),
            None => (entry, false),
        };
        let dir = match base {
            "." => match bufdir {
                Some(d) => d.to_path_buf(),
                None => continue,
            },
            "" => cwd.to_path_buf(),
            other => {
                let p = zmax_stdx::path::expand_tilde(std::path::Path::new(other)).into_owned();
                if p.is_absolute() {
                    p
                } else {
                    cwd.join(p)
                }
            }
        };
        let e = PathEntry { dir, recursive };
        if !out.contains(&e) {
            out.push(e);
        }
    }
    out
}

/// The names `:find {name}` tries, in order: the name itself, then the name with
/// each vim `suffixesadd` suffix appended (`:set suffixesadd=.rs` lets `:find
/// main` open `main.rs`). Pure — unit tested.
fn find_candidate_names(name: &str, suffixesadd: &str) -> Vec<String> {
    let mut names = vec![name.to_string()];
    for suffix in suffixesadd
        .split(',')
        .map(str::trim)
        .filter(|s| !s.is_empty())
    {
        names.push(format!("{name}{suffix}"));
    }
    names
}

/// Whether `path` ends with the path components of `name`, honouring vim
/// `fileignorecase` (compare file names case-insensitively). Pure — unit tested.
fn path_ends_with_name(path: &std::path::Path, name: &str, ignore_case: bool) -> bool {
    if path.ends_with(name) {
        return true;
    }
    if !ignore_case {
        return false;
    }
    let tail: Vec<String> = std::path::Path::new(name)
        .components()
        .map(|c| c.as_os_str().to_string_lossy().to_lowercase())
        .collect();
    let have: Vec<String> = path
        .components()
        .map(|c| c.as_os_str().to_string_lossy().to_lowercase())
        .collect();
    have.len() >= tail.len() && have[have.len() - tail.len()..] == tail[..]
}

// ---------------------------------------------------------------------------
// Vimscript function options ('findfunc', 'tagfunc', 'includeexpr', …).
//
// These options name a *user Vimscript function/expression* the editor must call
// and take a typed value back from. The embedded vimlrs interpreter evaluates
// them: the call's result is parked in a vimlrs global and every field is then
// read back with its own expression (`len(…)`, `get(…, 'name')`), so a List or
// Dict result is decoded by the interpreter rather than by re-parsing a rendered
// string. Only the values these consumers need are read, and a failing call is
// reported — never silently swallowed.
// ---------------------------------------------------------------------------

/// The vimlrs global a function-option's result is parked in.
const VIML_RET: &str = "g:zmax_fnret";

/// Quote `s` as a VimL single-quoted string literal (`'` doubles itself).
fn viml_quote(s: &str) -> String {
    format!("'{}'", s.replace('\'', "''"))
}

/// Evaluate `expr` through vimlrs and return its rendered scalar value. (`:echo`
/// renders a String as itself and a Number in decimal, so a scalar round-trips
/// exactly; List/Dict results are never read this way — see [`viml_list_len`].)
fn viml_eval_scalar(cx: &mut compositor::Context, expr: &str) -> anyhow::Result<String> {
    crate::commands::scripting::eval_viml(cx, expr)
        .map(|s| s.trim_end_matches('\n').to_string())
        .map_err(|e| anyhow!("{e}"))
}

/// Run `call` and park its value in [`VIML_RET`], after any `pre` statements
/// (e.g. `let v:fname = 'x'`).
fn viml_call(cx: &mut compositor::Context, pre: &[String], call: &str) -> anyhow::Result<()> {
    for stmt in pre {
        viml_eval_scalar(cx, stmt)?;
    }
    viml_eval_scalar(cx, &format!("let {VIML_RET} = {call}"))?;
    Ok(())
}

/// The length of the List parked in [`VIML_RET`] (0 when it is not a List).
fn viml_list_len(cx: &mut compositor::Context) -> anyhow::Result<usize> {
    let n = viml_eval_scalar(cx, &format!("len({VIML_RET})"))?;
    n.trim()
        .parse::<usize>()
        .map_err(|_| anyhow!("expected a List, got `{n}`"))
}

/// Item `i` of the List in [`VIML_RET`], as a string.
fn viml_list_str(cx: &mut compositor::Context, i: usize) -> anyhow::Result<String> {
    viml_eval_scalar(cx, &format!("{VIML_RET}[{i}]"))
}

/// Key `key` of dict item `i` of the List in [`VIML_RET`], as a string.
fn viml_list_dict_str(cx: &mut compositor::Context, i: usize, key: &str) -> anyhow::Result<String> {
    viml_eval_scalar(cx, &format!("get({VIML_RET}[{i}], '{key}', '')"))
}

/// Run `call` and decode its List result into strings. A completion function may
/// return either a List of strings or a List of Dicts (vim's `complete-items`,
/// whose `word` key holds the text) — both shapes are decoded here, so every
/// caller (`completefunc`, `omnifunc`, `thesaurusfunc`) gets plain words.
fn viml_call_word_list(
    cx: &mut compositor::Context,
    pre: &[String],
    call: &str,
) -> anyhow::Result<Vec<String>> {
    viml_call(cx, pre, call)?;
    let n = viml_list_len(cx)?;
    let mut out = Vec::with_capacity(n);
    for i in 0..n {
        // `type()` 4 is a Dict — a `complete-items` entry, whose word is in `word`.
        let is_dict = viml_eval_scalar(cx, &format!("type({VIML_RET}[{i}]) == 4"))?;
        let word = if is_dict.trim() == "1" {
            viml_list_dict_str(cx, i, "word")?
        } else {
            viml_list_str(cx, i)?
        };
        if !word.trim().is_empty() {
            out.push(word.trim_end_matches('\n').to_string());
        }
    }
    Ok(out)
}

/// A completion function option (`completefunc`, `omnifunc`) under either of its
/// spellings, if it names a function.
fn complete_func_opt(full: &str, abbrev: &str) -> Option<String> {
    vim_opt_str_alias(full, abbrev)
        .map(|f| f.trim().to_string())
        .filter(|f| !f.is_empty())
}

/// vim `i_CTRL-X CTRL-U` / `i_CTRL-X CTRL-O` — the two-call protocol of
/// 'completefunc' / 'omnifunc': the function is first called `{Func}(1, '')` and
/// returns the *column* the completed text starts at, then `{Func}(0, base)` with
/// the text from that column and returns the matches. A negative first result
/// cancels the completion (vim: -1 "no completion", -2/-3 "leave the mode").
///
/// Returns `(start_char_index, candidates)`, or `None` when the option is unset.
pub(crate) fn complete_func_matches(
    cx: &mut compositor::Context,
    func: &str,
) -> anyhow::Result<Option<(usize, Vec<String>)>> {
    let (line_start, line_to_cursor) = {
        let (view, doc) = current_ref!(cx.editor);
        let text = doc.text().slice(..);
        let cursor = doc.selection(view.id).primary().cursor(text);
        let line = text.char_to_line(cursor);
        let start = text.line_to_char(line);
        (start, text.slice(start..cursor).to_string())
    };
    // Call 1: findstart — the column the completion starts at.
    viml_call(cx, &[], &format!("{func}(1, '')"))?;
    let col = viml_eval_scalar(cx, VIML_RET)?
        .trim()
        .parse::<i64>()
        .map_err(|_| anyhow!("'{func}' did not return a column"))?;
    if col < 0 {
        return Ok(None);
    }
    // vim's column is a *byte* index into the line; clamp it to the cursor.
    let col = (col as usize).min(line_to_cursor.len());
    let base = line_to_cursor
        .get(col..)
        .ok_or_else(|| anyhow!("'{func}' returned column {col}, not a character boundary"))?
        .to_string();
    let start = line_start + line_to_cursor[..col].chars().count();
    // Call 2: the matches for that base.
    let words = viml_call_word_list(cx, &[], &format!("{func}(0, {})", viml_quote(&base)))?;
    Ok(Some((start, words)))
}

/// vim 'thesaurusfunc' — `{Func}(0, base)` returns the related words for `base`,
/// replacing the 'thesaurus' files. `None` when the option is unset (the files
/// are then read, as before).
pub(crate) fn thesaurusfunc_words(
    cx: &mut compositor::Context,
    base: &str,
) -> Option<anyhow::Result<Vec<String>>> {
    let func = complete_func_opt("thesaurusfunc", "tsrfu")?;
    Some(viml_call_word_list(
        cx,
        &[],
        &format!("{func}(0, {})", viml_quote(base)),
    ))
}

/// vim 'formatexpr' — the expression `gq`/`gw` formats with, in preference to
/// 'formatprg' and the built-in reflow. It is evaluated with `v:lnum` (the first
/// line of the range), `v:count` (the number of lines) and `v:char` (empty, since
/// this is not an auto-format while typing) set, and it edits the buffer itself
/// (through the `setline`/`append` host functions). A `0` result means it
/// formatted; anything else means it declined and the caller falls back.
///
/// `None` when 'formatexpr' is unset, so `gq` keeps its existing behavior.
pub(crate) fn formatexpr_format(cx: &mut compositor::Context) -> Option<anyhow::Result<bool>> {
    let expr = vim_opt_str_alias("formatexpr", "fex")
        .map(|e| e.trim().to_string())
        .filter(|e| !e.is_empty())?;
    let (first, count) = {
        let (view, doc) = current_ref!(cx.editor);
        let text = doc.text().slice(..);
        let range = doc.selection(view.id).primary();
        let from = text.char_to_line(range.from());
        let to = text.char_to_line(range.to().max(range.from()));
        (from + 1, to.saturating_sub(from) + 1)
    };
    let pre = [
        format!("let v:lnum = {first}"),
        format!("let v:count = {count}"),
        "let v:char = ''".to_string(),
    ];
    Some((|| {
        viml_call(cx, &pre, &expr)?;
        let ret = viml_eval_scalar(cx, VIML_RET)?;
        // vim: "return non-zero if the expression does not do the formatting".
        Ok(ret.trim() == "0")
    })())
}

/// vim 'indentexpr' — the expression that computes a line's indent, with `v:lnum`
/// set to that line. Returns the indent *column*, or `None` when the option is
/// unset (`-1` from the expression means "keep the current indent", which is
/// `None` too).
pub(crate) fn indentexpr_column(
    cx: &mut compositor::Context,
    lnum: usize,
) -> Option<anyhow::Result<usize>> {
    let expr = vim_opt_str_alias("indentexpr", "inde")
        .map(|e| e.trim().to_string())
        .filter(|e| !e.is_empty())?;
    let res = (|| {
        viml_call(cx, &[format!("let v:lnum = {lnum}")], &expr)?;
        let col = viml_eval_scalar(cx, VIML_RET)?
            .trim()
            .parse::<i64>()
            .map_err(|e| anyhow!("'indentexpr' did not return a number: {e}"))?;
        Ok(col)
    })();
    match res {
        Ok(col) if col < 0 => None,
        Ok(col) => Some(Ok(col as usize)),
        Err(e) => Some(Err(e)),
    }
}

/// vim 'operatorfunc' — the function `g@` calls, with the kind of the region it
/// operates on (`'char'`, `'line'` or `'block'`). vim marks the region with `'[`
/// and `']` first; the function then reads the text through those marks. Returns
/// `None` when the option is unset.
pub(crate) fn operatorfunc_call(
    cx: &mut compositor::Context,
    kind: &str,
) -> Option<anyhow::Result<()>> {
    let func = complete_func_opt("operatorfunc", "opfunc")?;
    Some((|| {
        viml_call(cx, &[], &format!("{func}({})", viml_quote(kind)))?;
        Ok(())
    })())
}

// --- vim 'diffexpr' ---------------------------------------------------------
//
// 'diffexpr' replaces the built-in diff: vim writes the two texts to
// `v:fname_in` / `v:fname_new`, evaluates the expression, and reads the diff the
// expression wrote to `v:fname_out` — in the *normal* `diff(1)` format
// (`5,7c5,9`), which is what this parses back into hunks.
//
// The consumer, `ui::merge::align`, is pure (it has no interpreter context), so
// the command that opens the diff view runs the expression here and parks the
// hunks; `align` picks them up for exactly the pair of texts they were computed
// from and otherwise diffs the texts itself.

/// One hunk of a diff: the half-open, 0-based line range replaced in the old
/// text and the range that replaces it in the new one.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct DiffHunk {
    pub before_start: u32,
    pub before_end: u32,
    pub after_start: u32,
    pub after_end: u32,
}

thread_local! {
    /// The hunks the last 'diffexpr' run produced, tagged with the texts it ran
    /// on so a stale result can never be shown for a different pair.
    static DIFFEXPR_HUNKS: std::cell::RefCell<Option<(u64, Vec<DiffHunk>)>> =
        const { std::cell::RefCell::new(None) };
}

/// A cheap tag for a pair of texts, so a parked 'diffexpr' result is only used
/// for the pair it was computed from.
fn diff_text_key(base: &str, doc: &str) -> u64 {
    use std::hash::{Hash, Hasher};
    let mut h = std::collections::hash_map::DefaultHasher::new();
    base.hash(&mut h);
    doc.hash(&mut h);
    h.finish()
}

/// Parse the normal-format `diff(1)` output an expression wrote: each command is
/// `{old-range}{a|c|d}{new-range}`, where a range is `N` or `N,M` (1-based,
/// inclusive). Lines that are not a command (the `<`/`>`/`---` bodies) are
/// skipped. Pure — unit tested.
fn parse_normal_diff(out: &str) -> Vec<DiffHunk> {
    // `1,2` / `4` -> the 1-based inclusive pair.
    fn range(s: &str) -> Option<(u32, u32)> {
        match s.split_once(',') {
            Some((a, b)) => Some((a.trim().parse().ok()?, b.trim().parse().ok()?)),
            None => {
                let n = s.trim().parse().ok()?;
                Some((n, n))
            }
        }
    }
    let mut hunks = Vec::new();
    for line in out.lines() {
        let Some(op) = line.find(['a', 'c', 'd']) else {
            continue;
        };
        let (left, rest) = line.split_at(op);
        let kind = rest.as_bytes()[0];
        let Some((l1, l2)) = range(left) else {
            continue;
        };
        let Some((r1, r2)) = range(&rest[1..]) else {
            continue;
        };
        // `a` inserts *after* old line l1, so it replaces the empty range at that
        // index; `d` likewise leaves the empty range at new-line index r1.
        let (before_start, before_end) = match kind {
            b'a' => (l2, l2),
            _ => (l1.saturating_sub(1), l2),
        };
        let (after_start, after_end) = match kind {
            b'd' => (r2, r2),
            _ => (r1.saturating_sub(1), r2),
        };
        if before_start > before_end || after_start > after_end {
            continue;
        }
        hunks.push(DiffHunk {
            before_start,
            before_end,
            after_start,
            after_end,
        });
    }
    hunks
}

/// vim 'diffexpr': run the expression over `base`/`doc` and park the hunks it
/// produced for [`diffexpr_hunks`]. A no-op when the option is unset; a failing
/// expression is reported on the status line and leaves the built-in diff in
/// place rather than showing an empty one.
pub fn diffexpr_prepare(cx: &mut compositor::Context, base: &str, doc: &str) {
    DIFFEXPR_HUNKS.with(|h| *h.borrow_mut() = None);
    let Some(expr) = vim_opt_str_alias("diffexpr", "dex")
        .map(|e| e.trim().to_string())
        .filter(|e| !e.is_empty())
    else {
        return;
    };
    match run_diffexpr(cx, &expr, base, doc) {
        Ok(hunks) => {
            let key = diff_text_key(base, doc);
            DIFFEXPR_HUNKS.with(|h| *h.borrow_mut() = Some((key, hunks)));
        }
        Err(e) => cx.editor.set_error(format!("diffexpr: {e}")),
    }
}

/// The body of [`diffexpr_prepare`]: the two texts go to temporary files, the
/// expression is evaluated with `v:fname_in`/`v:fname_new`/`v:fname_out` set (as
/// vim does), and the file it wrote is parsed back.
fn run_diffexpr(
    cx: &mut compositor::Context,
    expr: &str,
    base: &str,
    doc: &str,
) -> anyhow::Result<Vec<DiffHunk>> {
    let stem = format!(
        "zmax-diff-{}-{}",
        std::process::id(),
        diff_text_key(base, doc)
    );
    let dir = std::env::temp_dir();
    let fname_in = dir.join(format!("{stem}.in"));
    let fname_new = dir.join(format!("{stem}.new"));
    let fname_out = dir.join(format!("{stem}.out"));
    std::fs::write(&fname_in, base)?;
    std::fs::write(&fname_new, doc)?;
    std::fs::write(&fname_out, "")?;
    let pre = [
        format!(
            "let v:fname_in = {}",
            viml_quote(&fname_in.to_string_lossy())
        ),
        format!(
            "let v:fname_new = {}",
            viml_quote(&fname_new.to_string_lossy())
        ),
        format!(
            "let v:fname_out = {}",
            viml_quote(&fname_out.to_string_lossy())
        ),
    ];
    let called = viml_call(cx, &pre, expr);
    let out = called.and_then(|()| Ok(std::fs::read_to_string(&fname_out)?));
    for path in [&fname_in, &fname_new, &fname_out] {
        let _ = std::fs::remove_file(path);
    }
    Ok(parse_normal_diff(&out?))
}

/// The hunks vim 'diffexpr' produced for this exact pair of texts, or `None` —
/// the option is unset, the expression failed, or these are not the texts it ran
/// on. Read by `ui::merge::align`.
pub fn diffexpr_hunks(base: &str, doc: &str) -> Option<Vec<DiffHunk>> {
    let key = diff_text_key(base, doc);
    DIFFEXPR_HUNKS.with(|h| {
        h.borrow()
            .as_ref()
            .filter(|(k, _)| *k == key)
            .map(|(_, hunks)| hunks.clone())
    })
}

// --- the static commands these options drive --------------------------------
//
// `i_CTRL-X CTRL-U` / `i_CTRL-X CTRL-O` / `g@` live here rather than next to the
// other `CTRL-X` sources in commands.rs because all three are just a call into
// the vimlrs bridge above; commands.rs only registers them.

/// Run a completion-function option (`completefunc` / `omnifunc`) and offer what
/// it returns, in the same picker as the other `CTRL-X` sources. With the option
/// unset the key keeps doing what it did before this source existed — zmax's
/// own LSP+word completion — rather than erroring the way vim does (vim has no
/// other completion to fall back on; zmax does, and it is what the key was
/// bound to).
fn complete_through_func(cx: &mut super::Context, full: &str, abbrev: &str, what: &str) {
    let Some(func) = complete_func_opt(full, abbrev) else {
        super::completion(cx);
        return;
    };
    let result = {
        let mut ccx = compositor::Context {
            editor: cx.editor,
            jobs: cx.jobs,
            scroll: None,
        };
        complete_func_matches(&mut ccx, &func)
    };
    match result {
        Ok(Some((start, candidates))) => super::complete_from(cx, start, candidates, what),
        // The function returned a negative column: it declined to complete here.
        Ok(None) => {}
        Err(e) => cx.editor.set_error(format!("{full}: {e}")),
    }
}

/// vim `i_CTRL-X CTRL-U`: complete with the 'completefunc' user function.
pub fn complete_user_func(cx: &mut super::Context) {
    complete_through_func(cx, "completefunc", "cfu", "user-defined");
}

/// vim `i_CTRL-X CTRL-O`: complete with the 'omnifunc' function — the
/// filetype-specific completion a `ftplugin` installs.
pub fn complete_omni_func(cx: &mut super::Context) {
    complete_through_func(cx, "omnifunc", "ofu", "omni");
}

/// vim `g@` — call 'operatorfunc' on the region. Vim runs it over the region a
/// following motion covers; zmax (like helix) already *has* the region as the
/// selection, so `g@` applies the function to the current selection. The `'[` and
/// `']` marks are set to its ends first, which is how the function reads the text.
pub fn operator_func(cx: &mut super::Context) {
    if complete_func_opt("operatorfunc", "opfunc").is_none() {
        cx.editor
            .set_error("E774: 'operatorfunc' is empty (:set operatorfunc={Func})");
        return;
    }
    let kind = {
        let (view, doc) = current!(cx.editor);
        let (from, to, starts_line, ends_line) = {
            let text = doc.text().slice(..);
            let range = doc.selection(view.id).primary();
            let (from, to) = (range.from(), range.to());
            let last = to.saturating_sub(1).max(from);
            // vim's region kind: whole lines are a `line` region, else `char`.
            let starts_line = from == text.line_to_char(text.char_to_line(from));
            let ends_line =
                to == text.len_chars() || to == text.line_to_char(text.char_to_line(last) + 1);
            (from, to, starts_line, ends_line)
        };
        doc.set_mark('[', from);
        doc.set_mark(']', to.saturating_sub(1).max(from));
        if starts_line && ends_line && to > from {
            "line"
        } else {
            "char"
        }
    };
    let result = {
        let mut ccx = compositor::Context {
            editor: cx.editor,
            jobs: cx.jobs,
            scroll: None,
        };
        operatorfunc_call(&mut ccx, kind)
    };
    if let Some(Err(e)) = result {
        cx.editor.set_error(format!("operatorfunc: {e}"));
    }
}

// ---------------------------------------------------------------------------
// Keys whose behavior *is* an option.
//
// The `:` prompt (ui/prompt.rs) and the insert-mode self-insert (commands.rs)
// handle their keys with a hand-written `match`, not the keymap trie, so the keys
// below cannot be a `keymap!` entry. What each of them does is read out of the
// `:set` store, which is here — so the body lives here and the key calls in.
// ---------------------------------------------------------------------------

/// vim `i_CTRL-^` / `c_CTRL-^` — toggle the use of the `:lmap` (Lang-Arg) table.
/// The switch is 'iminsert' for typed text and 'imsearch' for the command line;
/// both are on while unset (vim turns 'iminsert' on when a keymap is loaded), so
/// the first toggle turns the language keymap off. Returns the new state.
pub fn toggle_lang_arg(insert: bool) -> bool {
    let switch = if insert { "iminsert" } else { "imsearch" };
    let on = vim_opt_num(switch) != Some(0);
    vim_opt_store(switch, if on { "0" } else { "1" }.to_string());
    !on
}

/// vim `i_CTRL-^` — the Insert-mode key that turns the `:lmap` language keymap
/// off and on ('iminsert').
pub fn toggle_lang_keymap(cx: &mut super::Context) {
    let on = toggle_lang_arg(true);
    cx.editor.set_status(if on {
        "lmap on (iminsert=1)"
    } else {
        "lmap off (iminsert=0)"
    });
}

/// The body of vim's `CTRL-_`, shared by `i_CTRL-_` and `c_CTRL-_`: flip
/// 'revins' when 'allowrevins' lets the key do it. That gate is the whole of
/// what 'allowrevins' is — without it the key is inert in both modes, which is
/// why vim has the option at all. Returns the new state, or `None` when the
/// option left the key inert.
fn revins_toggled(editor: &mut Editor) -> Option<bool> {
    if !vim_opt_bool("allowrevins") {
        editor.set_error("CTRL-_ needs 'allowrevins' (:set allowrevins)");
        return None;
    }
    let on = !vim_opt_bool("revins");
    vim_opt_store("revins", bool_word(on));
    Some(on)
}

/// vim `i_CTRL-_` — toggle 'revins' (typed text is inserted right-to-left).
pub fn toggle_revins(cx: &mut super::Context) {
    if let Some(on) = revins_toggled(cx.editor) {
        cx.editor.set_status(if on {
            "-- INSERT (reverse) --"
        } else {
            "-- INSERT --"
        });
    }
}

/// vim `c_CTRL-_` — the same toggle from the command line, where 'revins' makes
/// each typed character land ahead of the last.
pub fn toggle_revins_cmdline(editor: &mut Editor) {
    if let Some(on) = revins_toggled(editor) {
        editor.set_status(if on {
            "command line: reverse insert"
        } else {
            "command line: insert"
        });
    }
}

/// vim `c_CTRL-\ e {expr}` — the command line is replaced by the result of
/// evaluating `{expr}`. Evaluated as an *expression*, not as a line of script,
/// so `"XYZ"` is a string rather than a comment and `'XYZ'` a literal rather
/// than a mark; it still sees the variables and functions a `:let` defined.
pub fn cmdline_eval_expr(cx: &mut compositor::Context, expr: &str) -> anyhow::Result<String> {
    crate::commands::scripting::eval_viml_expr(cx, expr)
        .map(|s| s.trim_end_matches('\n').to_string())
        .map_err(|e| anyhow!("{e}"))
}

/// vim `c_CTRL-\ e {expr}` — make the command line being typed the one the
/// expression sees: `getcmdline()` reads `line`, `getcmdpos()` reads the
/// cursor's 1-based byte position, and `getcmdtype()` reads `cmdtype`.
pub fn cmdline_publish_state(line: &str, cursor: usize, cmdtype: char) {
    crate::commands::scripting::viml_cmdline_publish(line, cursor + 1, cmdtype);
}

/// The command line's cursor after the expression ran, as a byte index — an
/// expression that called `setcmdpos()` moved it. `None` when nothing did.
pub fn cmdline_published_cursor() -> Option<usize> {
    crate::commands::scripting::viml_cmdline_pos().checked_sub(1)
}

/// vim `c_CTRL-\ e {expr}` — the expression is done: no command line is active,
/// so the three getters go back to reporting nothing.
pub fn cmdline_clear_state() {
    crate::commands::scripting::viml_cmdline_clear();
}

/// vim `c_CTRL-]` — expand the `:cabbrev` in front of the cursor: the (lhs, rhs)
/// pair to swap, or `None` when the text before the cursor ends in no
/// Command-line abbreviation.
pub fn cmdline_abbrev_expand(before: &str) -> Option<(String, String)> {
    with_abbrevs(|t| t.find_expansion(AbbrevMode::Command, before))
}

/// The live vim 'suffixes' (`:set suffixes=.bak,~,.o`), or vim's default. Read
/// once per completion, not once per candidate.
pub fn suffixes_spec() -> String {
    vim_opt_str_alias("suffixes", "su").unwrap_or_else(|| ".bak,~,.o,.h,.info,.swp,.obj".into())
}

/// vim 'suffixes' — "files with these suffixes … are put at the end of the list"
/// when several names match a wildcard. `true` = `name` ends in one of them, so
/// file completion ranks it after everything else. A `\,` in the option is a
/// literal comma. Pure — unit tested.
pub fn suffix_ranked_last(spec: &str, name: &str) -> bool {
    spec.replace("\\,", "\u{1}")
        .split(',')
        .map(|s| s.replace('\u{1}', ","))
        .any(|s| !s.is_empty() && name.ends_with(&s))
}

/// vim 'cedit' — the key that opens the command-line window from the command
/// line (vim's default is `CTRL-F`). The value is a key notation: `<C-F>`,
/// `CTRL-F`, `^F` or a bare character. Returns `(needs_ctrl, key)`, or `None`
/// when 'cedit' is empty — which is how vim turns the key off. Pure — unit
/// tested.
pub fn cedit_key() -> Option<(bool, char)> {
    parse_cedit(&vim_opt_str_alias("cedit", "cedit").unwrap_or_else(|| "CTRL-F".into()))
}

fn parse_cedit(spec: &str) -> Option<(bool, char)> {
    let s = spec.trim().trim_start_matches('\\');
    let s = s
        .strip_prefix('<')
        .and_then(|s| s.strip_suffix('>'))
        .unwrap_or(s);
    if s.is_empty() {
        return None;
    }
    // `^F` — the caret notation; `C-F` / `CTRL-F` — the `<>` notation's body.
    for prefix in ["^", "C-", "c-", "CTRL-", "ctrl-", "Ctrl-"] {
        if let Some(rest) = s.strip_prefix(prefix) {
            return rest
                .chars()
                .next()
                .filter(|_| rest.chars().count() == 1)
                .map(|c| (true, c.to_ascii_lowercase()));
        }
    }
    let mut chars = s.chars();
    match (chars.next(), chars.next()) {
        (Some(c), None) => Some((false, c)),
        _ => None,
    }
}

/// vim 'cinkeys' / 'indentkeys' — whether typing `c` re-indents the current line.
/// An item is a key, optionally prefixed: `0x` fires only when `x` is the first
/// non-blank on the line, `!x` fires without inserting `x` (not modelled: the key
/// is inserted anyway), `*x` fires *before* `x` is inserted, and `=word` / `o` /
/// `O` / `e` are the new-line cases the newline indenter already covers. Pure —
/// unit tested.
fn indent_key_fires(keys: &str, c: char, first_non_blank: bool) -> bool {
    for item in keys.split(',') {
        let item = item.trim();
        if item.is_empty() {
            continue;
        }
        // Strip the `!` (no-insert) and `*` (before-insert) prefixes: both still
        // name the key that triggers the re-indent.
        let item = item.trim_start_matches(['!', '*']);
        // `^X` is a control character (`^F`); zmax never types those as text.
        if item.starts_with('^') || matches!(item, "o" | "O" | "e") || item.starts_with('=') {
            continue;
        }
        match item.strip_prefix('0') {
            // `0x` — only when `x` is the first non-blank character of the line.
            Some(key) if !key.is_empty() => {
                if key.starts_with(c) && first_non_blank {
                    return true;
                }
            }
            _ => {
                if item.starts_with(c) {
                    return true;
                }
            }
        }
    }
    false
}

/// vim's default 'cinkeys'/'indentkeys' — the same list for both.
const DEFAULT_INDENT_KEYS: &str = "0{,0},0),0],:,0#,!^F,o,O,e";

/// vim 'cinkeys' / 'indentkeys': re-indent the current line when one of the listed
/// keys is typed. 'cinkeys' applies when 'cindent' is on, 'indentkeys' when
/// 'indentexpr' is set — the two indenters this hook drives. Called from
/// insert-mode self-insert, *after* the character is in the buffer (so a `}`
/// dedents the line it now sits on).
pub(crate) fn reindent_on_type(cx: &mut super::Context, c: char) {
    let indentexpr = vim_opt_str_alias("indentexpr", "inde").is_some_and(|e| !e.trim().is_empty());
    let cindent = zmax_core::indent::cindent_enabled();
    if !indentexpr && !cindent {
        return;
    }
    let keys = if indentexpr {
        vim_opt_str_alias("indentkeys", "indk")
    } else {
        vim_opt_str_alias("cinkeys", "cink")
    };
    let keys = keys.unwrap_or_else(|| DEFAULT_INDENT_KEYS.to_string());

    // The line as it now stands, and whether `c` is its first non-blank char.
    let (line, first_non_blank) = {
        let (view, doc) = current_ref!(cx.editor);
        let text = doc.text().slice(..);
        let cursor = doc.selection(view.id).primary().cursor(text);
        let line = text.char_to_line(cursor);
        let start = text.line_to_char(line);
        let typed = cursor.saturating_sub(1);
        let blank_before = (start..typed).all(|i| matches!(text.char(i), ' ' | '\t'));
        (line, blank_before)
    };
    if !indent_key_fires(&keys, c, first_non_blank) {
        return;
    }
    reindent_line(cx, line);
}

/// Re-indent one line with the indenter the options select: 'indentexpr' when it
/// is set (vim gives it precedence), else vim's C indenter. The line's leading
/// whitespace is replaced; the cursor keeps its position in the text.
fn reindent_line(cx: &mut super::Context, line: usize) {
    let from_expr = {
        let mut ccx = compositor::Context {
            editor: cx.editor,
            jobs: cx.jobs,
            scroll: None,
        };
        indentexpr_column(&mut ccx, line + 1)
    };
    let column = match from_expr {
        Some(Ok(col)) => Some(col),
        Some(Err(e)) => {
            cx.editor.set_error(format!("indentexpr: {e}"));
            return;
        }
        // No 'indentexpr': vim's C indenter, corrected for the line's own content
        // (a line that *starts* with a closing brace lines up with its opener).
        None => cindent_column_for_line(cx.editor, line),
    };
    let Some(column) = column else { return };

    let (view, doc) = current!(cx.editor);
    let tab_width = doc.tab_width();
    let indent_style = doc.indent_style;
    let text = doc.text();
    let start = text.line_to_char(line);
    let line_str = text.line(line).to_string();
    let blank = line_str
        .chars()
        .take_while(|c| matches!(c, ' ' | '\t'))
        .count();
    let want = match indent_style {
        zmax_core::indent::IndentStyle::Tabs => "\t".repeat(column / tab_width.max(1)),
        _ => " ".repeat(column),
    };
    if line_str[..blank] == want {
        return;
    }
    let cursor = doc.selection(view.id).primary().cursor(text.slice(..));
    let transaction = Transaction::change(
        text,
        [(start, start + blank, Some(Tendril::from(want.as_str())))].into_iter(),
    );
    let moved = transaction
        .changes()
        .map_pos(cursor, zmax_core::Assoc::After);
    doc.apply(&transaction, view.id);
    doc.set_selection(view.id, Selection::point(moved));
}

/// The column vim's C indenter gives `line`, corrected for the line's own first
/// character: a `}` / `)` / `]` closes a block, so it lines up with the line that
/// opened it rather than with the block's body. `None` when the line has nothing
/// before it to indent against.
fn cindent_column_for_line(editor: &Editor, line: usize) -> Option<usize> {
    let doc = doc!(editor);
    let text = doc.text().slice(..);
    if line == 0 {
        return None;
    }
    let tab_width = doc.tab_width();
    let base =
        zmax_core::indent::vim_indent_for_newline(text, line - 1, &doc.indent_style, tab_width)?;
    let base = zmax_core::indent::indentation_column(&base, tab_width);
    let content = text.line(line).to_string();
    let first = content.trim_start().chars().next()?;
    if !matches!(first, '}' | ')' | ']') {
        return Some(base);
    }
    // Line the closer up with the line its opener is on.
    let start = text.line_to_char(line);
    let closer = start + content.chars().take_while(|c| c.is_whitespace()).count();
    let open = zmax_core::match_brackets::find_matching_bracket_plaintext(text, closer)?;
    let open_line = text.char_to_line(open);
    Some(zmax_core::indent::indentation_column(
        &text.line(open_line).to_string(),
        tab_width,
    ))
}

/// vim 'findfunc' — `{Func}(cmdarg, cmdcomplete)` returns the list of file names
/// `:find` should offer. zmax takes the first (it opens one file). Returns None
/// when 'findfunc' is unset, so the built-in 'path' search runs instead.
fn findfunc_lookup(
    cx: &mut compositor::Context,
    name: &str,
) -> Option<anyhow::Result<std::path::PathBuf>> {
    let func = vim_opt_str("findfunc").filter(|f| !f.trim().is_empty())?;
    let call = format!("{}({}, v:false)", func.trim(), viml_quote(name));
    Some((|| {
        viml_call(cx, &[], &call)?;
        if viml_list_len(cx)? == 0 {
            bail!("E345: 'findfunc' found no file for \"{name}\"");
        }
        let first = viml_list_str(cx, 0)?;
        Ok(zmax_stdx::path::expand_tilde(std::path::Path::new(first.trim())).into_owned())
    })())
}

/// vim `:find` search: locate `name` in the 'path' (default `.,,` — the current
/// buffer's directory, then the working directory — plus zmax's fallback
/// recursive walk of the working directory, i.e. the common `set path+=**`).
/// `suffixesadd` supplies the suffixes tried after the bare name, and
/// `fileignorecase` makes the name match case-insensitively. When 'findfunc' is
/// set it replaces the whole search, as in vim.
fn find_in_path(cx: &mut compositor::Context, name: &str) -> Option<std::path::PathBuf> {
    let name = name.trim();
    if name.is_empty() {
        return None;
    }
    // vim 'findfunc': a user function supplies the file names instead of 'path'.
    if let Some(found) = findfunc_lookup(cx, name) {
        return match found {
            Ok(p) => Some(p),
            Err(e) => {
                cx.editor.set_error(format!("findfunc: {e}"));
                None
            }
        };
    }
    let cwd = zmax_stdx::env::current_working_dir();
    let bufdir = doc!(cx.editor)
        .path()
        .and_then(|p| p.parent().map(|p| p.to_path_buf()));
    let ignore_case = vim_opt_bool("fileignorecase");
    let names = find_candidate_names(
        name,
        &vim_opt_str_alias("suffixesadd", "sua").unwrap_or_default(),
    );

    // vim `path`. Unset, zmax uses vim's default `.,,` *plus* a recursive walk
    // of the working directory (the common `set path+=**`), so a bare file name is
    // still found. Once `path` is `:set`, it is honoured exactly — add `**` to it
    // for the recursive walk, as in vim.
    let explicit = vim_opt_str_alias("path", "pa");
    let spec = explicit.clone().unwrap_or_else(|| ".,,".to_string());
    let mut entries = parse_path_option(&spec, bufdir.as_deref(), &cwd);
    if explicit.is_none() {
        entries.push(PathEntry {
            dir: cwd.clone(),
            recursive: true,
        });
    }

    for entry in &entries {
        if !entry.recursive {
            for candidate in &names {
                let p = entry.dir.join(candidate);
                if p.is_file() {
                    return Some(p);
                }
            }
            // vim `fileignorecase`: retry the directory listing case-insensitively.
            if ignore_case {
                if let Ok(dir) = std::fs::read_dir(&entry.dir) {
                    for found in dir.flatten() {
                        let file_name = found.file_name();
                        let file_name = file_name.to_string_lossy().to_lowercase();
                        if names.iter().any(|n| n.to_lowercase() == file_name)
                            && found.path().is_file()
                        {
                            return Some(found.path());
                        }
                    }
                }
            }
            continue;
        }
        for found in ignore::WalkBuilder::new(&entry.dir).build().flatten() {
            let p = found.path();
            if p.is_file() && names.iter().any(|n| path_ends_with_name(p, n, ignore_case)) {
                return Some(p.to_path_buf());
            }
        }
    }
    None
}

/// Shared body of `:find` / `:sfind`: resolve `name` through [`find_in_path`] and
/// open it with `action` (`Replace` for `:find`, `HorizontalSplit` for `:sfind`).
fn find_open(cx: &mut compositor::Context, args: &Args, action: Action) -> anyhow::Result<()> {
    let action = split_mod(cx.editor, action);
    let name = args.join(" ");
    match find_in_path(cx, &name) {
        Some(p) => {
            cx.editor.open(&p, action)?;
            Ok(())
        }
        None => bail!("E345: Can't find file \"{}\" in path", name.trim()),
    }
}

/// vim `:find {file}` — find `{file}` in the 'path' and edit it.
fn ex_find(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    find_open(cx, &args, Action::Replace)
}

/// vim `:sfind {file}` — split the window and edit `{file}` found in the 'path'.
fn ex_sfind(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    find_open(cx, &args, Action::HorizontalSplit)
}

// ---------------------------------------------------------------------------
// Vim argument list (`:args`, `:next`, `:argadd`, …). One process-global list,
// held in a thread-local (commands run on the main thread, like the vimlrs
// bridge's hooks). The pure state machine is `zmax_core::arglist::ArgList`;
// these commands drive it and open `current_file()` whenever the index moves.
// ---------------------------------------------------------------------------

thread_local! {
    static ARGLIST: std::cell::RefCell<zmax_core::arglist::ArgList> =
        std::cell::RefCell::new(zmax_core::arglist::ArgList::new());
}

/// Run `f` against the global argument list.
fn with_arglist<R>(f: impl FnOnce(&mut zmax_core::arglist::ArgList) -> R) -> R {
    ARGLIST.with(|a| f(&mut a.borrow_mut()))
}

/// Open a file named in the argument list (expanding a leading `~`).
fn edit_arg_file(cx: &mut compositor::Context, file: &str) -> anyhow::Result<()> {
    edit_arg_file_with(cx, file, Action::Replace)
}

/// Open an arg-list file with a specific action — `Replace` for `:next`/`:prev`
/// etc., `HorizontalSplit` for the split variants (`:snext`/`:sprevious`/…).
fn edit_arg_file_with(
    cx: &mut compositor::Context,
    file: &str,
    action: Action,
) -> anyhow::Result<()> {
    let action = split_mod(cx.editor, action);
    // vim `autowrite`/`autowriteall`: leaving the buffer for another argument
    // writes it out first.
    vim_autowrite(cx)?;
    let path = zmax_stdx::path::expand_tilde(std::path::Path::new(file));
    cx.editor.open(&path, action)?;
    Ok(())
}

/// The `:s…` split variants of the arg-list navigators: split the window, then
/// edit the target argument in the new split (vim `:split | :next`, etc.).
fn arg_snext(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let count = arg_count(&args);
    match with_arglist(|a| a.next(count).map(str::to_string)) {
        Some(f) => edit_arg_file_with(cx, &f, Action::HorizontalSplit),
        None => bail!("Cannot go beyond last file"),
    }
}

fn arg_sprev(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let count = arg_count(&args);
    match with_arglist(|a| a.prev(count).map(str::to_string)) {
        Some(f) => edit_arg_file_with(cx, &f, Action::HorizontalSplit),
        None => bail!("Cannot go before first file"),
    }
}

fn arg_sfirst(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    match with_arglist(|a| a.first().map(str::to_string)) {
        Some(f) => edit_arg_file_with(cx, &f, Action::HorizontalSplit),
        None => bail!("argument list is empty"),
    }
}

fn arg_slast(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    match with_arglist(|a| a.last().map(str::to_string)) {
        Some(f) => edit_arg_file_with(cx, &f, Action::HorizontalSplit),
        None => bail!("argument list is empty"),
    }
}

fn arg_sargument(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let Some(n) = args.first().and_then(|s| s.parse::<usize>().ok()) else {
        bail!("sargument: needs a number");
    };
    match with_arglist(|a| a.goto(n).map(str::to_string)) {
        Some(f) => edit_arg_file_with(cx, &f, Action::HorizontalSplit),
        None => bail!("argument out of range"),
    }
}

/// Optional leading count argument (`:next 2`); defaults to 1.
fn arg_count(args: &Args) -> usize {
    args.first()
        .and_then(|s| s.parse::<usize>().ok())
        .unwrap_or(1)
}

/// `:args` — with no argument, echo the list; with file arguments, replace the
/// list and edit the first file.
fn args_cmd(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    if args.is_empty() {
        let shown = with_arglist(|a| {
            if a.is_empty() {
                "argument list is empty".to_string()
            } else {
                a.display()
            }
        });
        cx.editor.set_status(shown);
        return Ok(());
    }
    let files: Vec<String> = args.iter().map(|s| s.to_string()).collect();
    with_arglist(|a| a.set(files));
    let first = with_arglist(|a| a.current_file().map(str::to_string));
    if let Some(f) = first {
        edit_arg_file(cx, &f)?;
    }
    Ok(())
}

/// `:argadd {files}` — insert files after the current entry.
fn argadd(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    if args.is_empty() {
        bail!("argadd: needs at least one file");
    }
    let files: Vec<String> = args.iter().map(|s| s.to_string()).collect();
    with_arglist(|a| a.add(files));
    cx.editor.set_status(with_arglist(|a| {
        format!("{} files in the arg list", a.len())
    }));
    Ok(())
}

/// `:argedit {file}` — add the file after the current entry and edit it.
fn argedit(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let Some(file) = args.first().map(|s| s.to_string()) else {
        bail!("argedit: needs a file");
    };
    let f = with_arglist(|a| a.edit(file));
    edit_arg_file(cx, &f)
}

/// `:argdelete {patterns}` — remove entries matching the glob patterns.
fn argdelete(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    if args.is_empty() {
        bail!("argdelete: needs a pattern");
    }
    let pats: Vec<&str> = args.iter().map(|s| s.as_ref()).collect();
    let n = with_arglist(|a| a.delete_matching(&pats));
    cx.editor
        .set_status(format!("removed {n} from the arg list"));
    Ok(())
}

/// `:argdedupe` — remove duplicate entries.
fn argdedupe(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    with_arglist(|a| a.dedupe());
    cx.editor.set_status(with_arglist(|a| {
        format!("{} files in the arg list", a.len())
    }));
    Ok(())
}

/// `:next` — edit the next argument (E165 at the end).
fn arg_next(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let count = arg_count(&args);
    let file = with_arglist(|a| a.next(count).map(str::to_string));
    match file {
        Some(f) => edit_arg_file(cx, &f),
        None => bail!("Cannot go beyond last file"),
    }
}

/// `:previous` / `:Next` — edit the previous argument (E164 at the start).
fn arg_prev(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let count = arg_count(&args);
    let file = with_arglist(|a| a.prev(count).map(str::to_string));
    match file {
        Some(f) => edit_arg_file(cx, &f),
        None => bail!("Cannot go before first file"),
    }
}

/// vim `:wnext [file]` — write the current buffer (to `[file]` if given), then
/// edit the next file in the argument list (`:write` followed by `:next`).
fn write_next(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    fire_autocmd(cx, "BufWritePre");
    write_impl(
        cx,
        args.first(),
        WriteOptions {
            force: false,
            auto_format: true,
            code_actions: true,
        },
    )?;
    fire_autocmd(cx, "BufWritePost");
    match with_arglist(|a| a.next(1).map(str::to_string)) {
        Some(f) => edit_arg_file(cx, &f),
        None => bail!("E165: Cannot go beyond last file"),
    }
}

/// vim `:wprevious [file]` / `:wNext` — write the current buffer, then edit the
/// previous file in the argument list (`:write` followed by `:previous`).
fn write_prev(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    fire_autocmd(cx, "BufWritePre");
    write_impl(
        cx,
        args.first(),
        WriteOptions {
            force: false,
            auto_format: true,
            code_actions: true,
        },
    )?;
    fire_autocmd(cx, "BufWritePost");
    match with_arglist(|a| a.prev(1).map(str::to_string)) {
        Some(f) => edit_arg_file(cx, &f),
        None => bail!("E164: Cannot go before first file"),
    }
}

/// `:first` / `:rewind` — edit the first argument.
fn arg_first(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let file = with_arglist(|a| a.first().map(str::to_string));
    match file {
        Some(f) => edit_arg_file(cx, &f),
        None => bail!("argument list is empty"),
    }
}

/// `:last` — edit the last argument.
fn arg_last(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let file = with_arglist(|a| a.last().map(str::to_string));
    match file {
        Some(f) => edit_arg_file(cx, &f),
        None => bail!("argument list is empty"),
    }
}

/// `:argument N` — edit the Nth argument.
fn argument(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let Some(n) = args.first().and_then(|s| s.parse::<usize>().ok()) else {
        bail!("argument: needs a number");
    };
    let file = with_arglist(|a| a.goto(n).map(str::to_string));
    match file {
        Some(f) => edit_arg_file(cx, &f),
        None => bail!("no argument {n}"),
    }
}

/// `:argdo {cmd}` — run an Ex command on each file in the argument list.
fn argdo(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let cmd = args
        .iter()
        .map(|s| s.to_string())
        .collect::<Vec<_>>()
        .join(" ");
    if cmd.is_empty() {
        bail!("argdo: needs a command");
    }
    let files = with_arglist(|a| a.files().to_vec());
    for f in files {
        edit_arg_file(cx, &f)?;
        run_command_line(cx, &cmd);
    }
    Ok(())
}

/// `:all` — open a window for each file in the argument list.
fn arg_all(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let files = with_arglist(|a| a.files().to_vec());
    if files.is_empty() {
        bail!("argument list is empty");
    }
    for (i, f) in files.iter().enumerate() {
        if i > 0 {
            run_command_line(cx, "hsplit-new");
        }
        edit_arg_file(cx, f)?;
    }
    Ok(())
}

// ---------------------------------------------------------------------------
// Emacs compilation (`compile`, `recompile`, `next-error`, `previous-error`,
// `first-error`). One process-global error list plus the last shell command,
// held in a thread-local like ARGLIST above. `compile` runs the command
// synchronously as a local subprocess (capturing stdout+stderr), parses the
// output with the pure `zmax_core::compilation` engine, and stores the
// resulting error list; the navigation commands walk that list and open each
// entry's file at its reported line/column. This is the Emacs compilation side;
// Vim's quickfix (`:cnext`/`:cabove`/…) is separate and untouched.
// ---------------------------------------------------------------------------

thread_local! {
    static COMPILATION: std::cell::RefCell<zmax_core::compilation::CompilationList> =
        std::cell::RefCell::new(zmax_core::compilation::CompilationList::new());
    /// The last command handed to `:compile`, replayed by `:recompile`.
    static COMPILE_COMMAND: std::cell::RefCell<Option<String>> = const { std::cell::RefCell::new(None) };
}

/// Run `f` against the global compilation error list.
fn with_compilation<R>(f: impl FnOnce(&mut zmax_core::compilation::CompilationList) -> R) -> R {
    COMPILATION.with(|c| f(&mut c.borrow_mut()))
}

/// Run `command` through the editor's configured shell, capturing stdout and
/// stderr together (Emacs interleaves both into `*compilation*`), parse the
/// output into the global error list, and report the count on the status line.
fn run_compile(cx: &mut compositor::Context, command: &str) -> anyhow::Result<()> {
    run_compile_capture(cx, command).map(|_| ())
}

/// As [`run_compile`], returning the captured output so the caller can also route
/// it elsewhere (vim `makeef`).
fn run_compile_capture(cx: &mut compositor::Context, command: &str) -> anyhow::Result<String> {
    sandbox_check("shell command")?;
    let command = command.trim();
    if command.is_empty() {
        bail!("compile: needs a command");
    }
    // vim `shellcmdflag` / `shellquote` / `shellxquote`: the flags the shell is
    // invoked with and the quoting placed around the command.
    let shell = vim_shell_argv(&cx.editor.config().shell);
    if shell.is_empty() {
        bail!("compile: no shell configured");
    }
    let shell_cmd = vim_shell_quote(command);
    let output = std::process::Command::new(&shell[0])
        .args(&shell[1..])
        .arg(&shell_cmd)
        .output()
        .map_err(|e| anyhow::anyhow!("compile: failed to run `{command}`: {e}"))?;

    // Emacs' `*compilation*` shows stdout and stderr interleaved; most tools
    // print diagnostics to stderr, so scan both.
    let mut captured = decode_make_output(&output.stdout);
    captured.push_str(&decode_make_output(&output.stderr));

    with_compilation(|c| c.set_output(&captured));
    COMPILE_COMMAND.with(|last| *last.borrow_mut() = Some(command.to_string()));

    let count = with_compilation(|c| c.len());
    let status = output.status;
    cx.editor.set_status(match count {
        0 => format!("Compilation finished ({status}); no errors"),
        1 => format!("Compilation finished ({status}); 1 error"),
        n => format!("Compilation finished ({status}); {n} errors"),
    });
    Ok(captured)
}

/// The window a quickfix/error jump lands in, from vim `switchbuf`. `useopen`
/// reuses a window already showing the file, `split`/`vsplit` open a new one;
/// `newtab`/`usetab`/`uselast` have no zmax equivalent (one tab page, one
/// "last" window) and fall back to replacing the current window. Pure decision
/// half: [`switchbuf_action`]; the `useopen` window search needs the editor.
fn switchbuf_action(spec: &str) -> Action {
    let has = |flag: &str| spec.split(',').any(|s| s.trim() == flag);
    if has("vsplit") {
        Action::VerticalSplit
    } else if has("split") {
        Action::HorizontalSplit
    } else {
        Action::Replace
    }
}

/// Open `path` the way vim `switchbuf` says a quickfix/error jump should.
fn switchbuf_open(cx: &mut compositor::Context, path: &std::path::Path) -> anyhow::Result<()> {
    let spec = vim_opt_str("switchbuf").unwrap_or_default();
    if spec.split(',').any(|s| s.trim() == "useopen") {
        let target = zmax_stdx::path::canonicalize(path);
        let existing = cx.editor.tree.views().find_map(|(view, _)| {
            let doc = &cx.editor.documents[&view.doc];
            (doc.path() == Some(target.as_path())).then_some(view.id)
        });
        if let Some(id) = existing {
            cx.editor.focus(id);
            return Ok(());
        }
    }
    cx.editor.open(path, switchbuf_action(&spec))?;
    Ok(())
}

/// Open the file named by a compilation entry at its 1-based line/column,
/// converting to the editor's 0-based coordinates.
fn goto_compile_entry(
    cx: &mut compositor::Context,
    entry: &zmax_core::compilation::CompileEntry,
) -> anyhow::Result<()> {
    let path = zmax_stdx::path::expand_tilde(std::path::Path::new(&entry.file));
    // vim `switchbuf`: where the error jump opens the file.
    switchbuf_open(cx, &path)?;
    let scrolloff = cx.editor.config().scrolloff;
    let (view, doc) = current!(cx.editor);
    let coords = zmax_core::Position::new(
        entry.line.saturating_sub(1),
        entry.col.map(|c| c.saturating_sub(1)).unwrap_or(0),
    );
    let pos = Selection::point(pos_at_coords(doc.text().slice(..), coords, true));
    doc.set_selection(view.id, pos);
    // vim `:compile` error jumps scroll minimally, not centered.
    view.ensure_cursor_in_view(doc, scrolloff);
    Ok(())
}

/// `:compile {command}` — Emacs `compile` (`M-x compile`). Run the shell command,
/// collect its output, and build the error list. With no argument, replay the
/// last command (like `recompile`).
fn compile(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let command = args.join(" ");
    if command.trim().is_empty() {
        return recompile(cx, args, event);
    }
    run_compile(cx, &command)
}

/// `:recompile` — Emacs `recompile`: re-run the last `compile` command.
fn recompile(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let last = COMPILE_COMMAND.with(|c| c.borrow().clone());
    match last {
        Some(cmd) => run_compile(cx, &cmd),
        None => bail!("recompile: no previous compile command"),
    }
}

/// vim `:make [args]` — run the make program (vim `makeprg`, default `make`)
/// with `args`, collect its output into the error/quickfix list (shared with
/// `:compile` and `:cnext`/`:cc`/`:copen`), then jump to the first error, like
/// vim. Honors `autowrite`/`autowriteall` (write before building) and `makeef`
/// (also save the raw output to that file).
fn make(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    make_impl(cx, &args, false)
}

/// vim `:lmake [args]` — as `:make`, but the errors go to the *location list* of
/// the current window (`:lopen` / `:lnext` / `:ll`) instead of the compilation
/// list `:make` fills, exactly as vim splits the two.
fn ex_lmake(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    make_impl(cx, &args, true)
}

/// Shared body of `:make` / `:lmake`. `loclist` picks which list the build's
/// errors land in: the compilation list (`:make`, walked by `:next-error` /
/// `:cnext`) or the window's location list (`:lmake`).
fn make_impl(cx: &mut compositor::Context, args: &Args, loclist: bool) -> anyhow::Result<()> {
    // vim `autowrite`: `:make` writes the modified buffer before building.
    vim_autowrite(cx)?;
    let extra = args.join(" ");
    let extra = extra.trim();
    // vim `makeprg` (default `make`); `$*` is replaced by the `:make` arguments,
    // otherwise they are appended.
    let prog = vim_opt_str("makeprg").unwrap_or_else(|| "make".to_string());
    let command = if prog.contains("$*") {
        prog.replace("$*", extra)
    } else if extra.is_empty() {
        prog
    } else {
        format!("{prog} {extra}")
    };
    // vim `shellpipe` (default `2>&1| tee`): how the build's output is routed to
    // the error file. Only meaningful together with 'makeef' — that is the file
    // vim pipes into — so the redirection is appended when both are set.
    let errorfile = vim_opt_str("makeef");
    let shellpipe = vim_opt_str_alias("shellpipe", "sp").filter(|p| !p.trim().is_empty());
    let piped = errorfile.is_some() && shellpipe.is_some();
    let command = match (&errorfile, &shellpipe) {
        (Some(ef), Some(pipe)) => {
            let ef = shell_single_quote(ef);
            if pipe.contains("%s") {
                format!("{command} {}", pipe.replace("%s", &ef))
            } else {
                format!("{command} {pipe} {ef}")
            }
        }
        _ => command,
    };
    // `:lmake` must not disturb the compilation list, so it runs the build
    // through the plain capture instead of `run_compile_capture`.
    let output = if loclist {
        shell_capture(cx, &command)?
    } else {
        run_compile_capture(cx, &command)?
    };
    // vim `makeef`: the file `:make` leaves its raw output in. When 'shellpipe' is
    // set the shell already redirected it there; otherwise write it here.
    if let Some(ef) = errorfile.filter(|_| !piped) {
        let path = zmax_stdx::path::expand_tilde(std::path::Path::new(&ef));
        if let Err(e) = std::fs::write(&path, &output) {
            cx.editor
                .set_error(format!("makeef: cannot write {}: {e}", path.display()));
        }
    }
    if loclist {
        // A build with no diagnostics is a success, not an error: leave the
        // location list alone and say so (vim's `:lmake` likewise only jumps when
        // there is something to jump to).
        if crate::commands::qf_entries_from_text(&output).is_empty() {
            cx.editor.set_status("lmake finished; no errors");
            return Ok(());
        }
        return qf_populate(cx, QfKind::Location, &output, false, true);
    }
    // vim jumps to the first error after `:make`; only if the build reported any.
    if let Some(entry) = with_compilation(|c| c.first().cloned()) {
        goto_compile_entry(cx, &entry)?;
    }
    Ok(())
}

// ---------------------------------------------------------------------------
// Vim tag stack: `:tag`, `:tnext`/`:tprevious`/`:tfirst`/`:tlast`, `:pop`,
// `:tags` over a ctags `tags` file. Distinct from the `:Tags`/`:BTags` fzf
// pickers — this is exact-name jump-to-definition with a navigable stack,
// LSP-independent (works on any tree with a generated `tags` file).
// ---------------------------------------------------------------------------

/// One parsed `tags`-file entry: a symbol, the file defining it, and the ctags
/// address locating the definition inside that file.
#[derive(Clone)]
struct TagEntry {
    name: String,
    file: std::path::PathBuf,
    address: TagAddress,
}

#[derive(Clone)]
enum TagAddress {
    /// A 1-based line number (numeric `tags` address).
    Line(usize),
    /// A `/pattern/` address, reduced to the literal line body to search for.
    Pattern(String),
}

/// A location jumped *from*, pushed on `:tag` and restored by `:pop`.
#[derive(Clone)]
struct TagFrom {
    file: std::path::PathBuf,
    pos: usize,
}

enum TagMove {
    Next,
    Prev,
    First,
    Last,
}

thread_local! {
    /// The vim tag stack — locations pushed by `:tag`, popped by `:pop`.
    static TAG_STACK: std::cell::RefCell<Vec<TagFrom>> = const { std::cell::RefCell::new(Vec::new()) };
    /// Matches for the most recent `:tag {name}`, cycled by `:tnext`/`:tprevious`.
    static TAG_MATCHES: std::cell::RefCell<Vec<TagEntry>> = const { std::cell::RefCell::new(Vec::new()) };
    /// Index into `TAG_MATCHES` of the currently-shown match.
    static TAG_IDX: std::cell::Cell<usize> = const { std::cell::Cell::new(0) };
}

/// Locate the `tags` file like vim's default `tags=./tags,tags`: first `tags`
/// beside the current buffer, then `tags` in the working directory. Returns the
/// file and the directory relative entry paths resolve against.
/// Every tag name in the tags file that `tags` resolves to, or empty when there
/// is no tags file. For `i_CTRL-X_CTRL-]` (tag completion), which wants the names
/// and none of the addresses.
pub(crate) fn tag_names(editor: &Editor) -> Vec<String> {
    find_tags_file(editor)
        .map(|(file, base)| {
            parse_tags_file(&file, &base)
                .into_iter()
                .map(|t| t.name)
                .collect()
        })
        .unwrap_or_default()
}

fn find_tags_file(editor: &Editor) -> Option<(std::path::PathBuf, std::path::PathBuf)> {
    let (_view, doc) = current_ref!(editor);
    let buf_dir = doc.path().and_then(|p| p.parent()).map(|p| p.to_path_buf());
    let cwd = std::env::current_dir().ok();
    // vim `tags` (default `./tags,tags`): comma/space separated list; a `./`
    // prefix anchors the name to the current buffer's directory, an absolute
    // path is used as-is, anything else is relative to the working directory.
    let spec = vim_opt_str("tags").unwrap_or_else(|| "./tags,tags".to_string());
    // vim `cpoptions` flag `d`: "Using './' in the 'tags' option doesn't mean to
    // use the tags file relative to the current file, but the tags file in the
    // current directory."
    let dot_is_cwd = cpo_has('d');
    for entry in spec.split([',', ' ']).filter(|s| !s.is_empty()) {
        let (base, name): (Option<std::path::PathBuf>, &str) =
            if let Some(rest) = entry.strip_prefix("./") {
                (
                    if dot_is_cwd {
                        cwd.clone()
                    } else {
                        buf_dir.clone()
                    },
                    rest,
                )
            } else if std::path::Path::new(entry).is_absolute() {
                let p = std::path::PathBuf::from(entry);
                let dir = p.parent().map(|d| d.to_path_buf());
                if p.is_file() {
                    return Some((p, dir.unwrap_or_default()));
                }
                continue;
            } else {
                (cwd.clone(), entry)
            };
        if let Some(dir) = base {
            let f = dir.join(name);
            if f.is_file() {
                return Some((f, dir));
            }
        }
    }
    None
}

/// Parse a ctags `tags` file into entries, skipping `!_TAG_` metadata lines.
/// Relative entry paths are resolved against `base`.
fn parse_tags_file(path: &std::path::Path, base: &std::path::Path) -> Vec<TagEntry> {
    let text = match std::fs::read_to_string(path) {
        Ok(t) => t,
        Err(_) => return Vec::new(),
    };
    let mut out = Vec::new();
    for line in text.lines() {
        if line.is_empty() || line.starts_with("!_TAG_") {
            continue;
        }
        let mut it = line.splitn(3, '\t');
        let (name, file, rest) = match (it.next(), it.next(), it.next()) {
            (Some(n), Some(f), Some(r)) => (n, f, r),
            _ => continue,
        };
        let p = std::path::Path::new(file);
        let file_path = if p.is_absolute() {
            p.to_path_buf()
        } else {
            base.join(p)
        };
        out.push(TagEntry {
            name: name.to_string(),
            file: file_path,
            address: parse_tag_address(rest),
        });
    }
    out
}

/// Reduce a ctags address field (`42;"…`, `/^pattern$/;"…`, `?pattern?`) to a
/// line number or the literal text to search for.
fn parse_tag_address(rest: &str) -> TagAddress {
    // Drop the trailing `;"` extension field ctags appends.
    let field = rest.split(";\"").next().unwrap_or(rest).trim();
    if let Ok(n) = field.parse::<usize>() {
        return TagAddress::Line(n);
    }
    let bytes = field.as_bytes();
    if bytes.len() >= 2 && (bytes[0] == b'/' || bytes[0] == b'?') {
        let delim = bytes[0] as char;
        let end = field[1..]
            .rfind(delim)
            .map(|i| i + 1)
            .unwrap_or(field.len());
        let inner = &field[1..end];
        let inner = inner.trim_start_matches('^').trim_end_matches('$');
        let inner = inner.replace("\\/", "/").replace("\\\\", "\\");
        return TagAddress::Pattern(inner);
    }
    TagAddress::Pattern(field.to_string())
}

/// Open the entry's file and move the cursor to its address — the line number,
/// or the first line containing the pattern. Reused by every tag-jump command.
fn jump_to_tag(cx: &mut compositor::Context, entry: &TagEntry) -> anyhow::Result<()> {
    jump_to_tag_action(cx, entry, Action::Replace)
}

/// As [`jump_to_tag`] but opening with a chosen `Action` (e.g. a split for
/// `:stag`).
fn jump_to_tag_action(
    cx: &mut compositor::Context,
    entry: &TagEntry,
    action: Action,
) -> anyhow::Result<()> {
    jump_to_tag_action_preview(cx, entry, action, false)
}

/// `preview` marks this as a `:ptag`-family jump rather than a `:stag`-family
/// one. Both open a horizontal split, so the action alone cannot tell them apart,
/// and vim treats them as opposites: `:stag` splits and *moves* you there, while
/// `:ptag` "shows the found tag in a Preview window **without changing the current
/// buffer or cursor position**" (windows.txt:987). Only the preview family reuses
/// and marks the one preview window, and only it hands the focus back.
fn jump_to_tag_action_preview(
    cx: &mut compositor::Context,
    entry: &TagEntry,
    action: Action,
    preview: bool,
) -> anyhow::Result<()> {
    // vim shows every preview in the one preview window, so reuse it when it is
    // open instead of stacking another split, and mark the split it opens when it
    // is not.
    let origin = cx.editor.tree.focus;
    let reuse = preview.then(|| preview_view(cx.editor)).flatten();
    let action = match reuse {
        Some(id) => {
            cx.editor.focus(id);
            Action::Replace
        }
        None => split_mod(cx.editor, action),
    };
    // vim `:tag`/`:tselect`/`:tjump`/`:tnext` are jump commands: record where we
    // jumped from before opening the target (a cross-file open also pushes via
    // Editor::switch, but push_impl dedups the identical consecutive entry).
    {
        let (view, doc) = current!(cx.editor);
        super::push_jump(view, doc);
    }
    cx.editor.open(&entry.file, action)?;
    if preview {
        mark_preview_window(cx.editor, true);
    }
    let (view, doc) = current!(cx.editor);
    let text = doc.text();
    let last_line = text.len_lines().saturating_sub(1);
    let line_idx = match &entry.address {
        TagAddress::Line(n) => n.saturating_sub(1).min(last_line),
        TagAddress::Pattern(pat) => (0..text.len_lines())
            .find(|&i| {
                text.line(i)
                    .chars()
                    .collect::<String>()
                    .contains(pat.as_str())
            })
            .unwrap_or(0),
    };
    let pos = text.line_to_char(line_idx);
    doc.set_selection(view.id, Selection::point(pos));
    let scrolloff = cx.editor.config().scrolloff;
    let (view, doc) = current!(cx.editor);
    view.ensure_cursor_in_view(doc, scrolloff);
    // A `:ptag` leaves you where you were — the tag is placed in the preview
    // window above, then the focus goes back. Done last so the cursor lands in the
    // preview window rather than in the window we return to.
    if preview && cx.editor.tree.contains(origin) {
        cx.editor.focus(origin);
    }
    Ok(())
}

/// Push the current cursor location on the tag stack (the `:tag` "from").
fn push_tag_from(cx: &compositor::Context) {
    push_tag_from_editor(cx.editor);
}

/// [`push_tag_from`] against a bare [`Editor`], so the static `tag_jump` command
/// bound to normal-mode `CTRL-]` records its "from" through the same path the
/// `:tag` family uses, rather than keeping a second tag stack.
pub(crate) fn push_tag_from_editor(editor: &Editor) {
    // vim `tagstack`: `:set notagstack` makes `:tag` jump without recording where
    // it jumped from, so `:pop` has nothing to return to.
    if !vim_opt_bool("tagstack") {
        return;
    }
    let (view, doc) = current_ref!(editor);
    if let Some(file) = doc.path().map(|p| p.to_path_buf()) {
        let pos = doc
            .selection(view.id)
            .primary()
            .cursor(doc.text().slice(..));
        TAG_STACK.with(|s| s.borrow_mut().push(TagFrom { file, pos }));
    }
}

/// `:tag {name}` — jump to the definition of `name` from the `tags` file,
/// pushing the current location on the tag stack. Bare `:tag` re-jumps to the
/// current match.
fn tag_jump_cmd(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.join(" ");
    let name = name.trim();
    if name.is_empty() {
        let cur = TAG_MATCHES.with(|m| m.borrow().get(TAG_IDX.with(|i| i.get())).cloned());
        return match cur {
            Some(e) => jump_to_tag(cx, &e),
            None => bail!("no current tag"),
        };
    }
    let matches = resolve_tag_matches(cx, name)?;
    push_tag_from(cx);
    let n = matches.len();
    let first = matches[0].clone();
    TAG_MATCHES.with(|m| *m.borrow_mut() = matches);
    TAG_IDX.with(|i| i.set(0));
    jump_to_tag(cx, &first)?;
    cx.editor.set_status(format!("tag 1 of {n}: {name}"));
    Ok(())
}

/// Whether a tags-file entry named `entry` is the tag the user asked for, under
/// vim `tagcase` (`match` = case-sensitive, `ignore` = case-insensitive,
/// `followic` = follow `ignorecase`, `smart` = follow `ignorecase` unless the
/// typed name has an uppercase letter) and `taglength` (only the first N
/// characters are significant; 0 = the whole name). Pure — unit tested.
fn tag_name_matches(entry: &str, name: &str, tagcase: &str, ignorecase: bool, tl: usize) -> bool {
    let ignore = match tagcase {
        "ignore" => true,
        "match" => false,
        "smart" => ignorecase && !name.chars().any(char::is_uppercase),
        // vim's default `followic` (and `followscs`, which follows smartcase too).
        _ => ignorecase,
    };
    let cut = |s: &str| -> String {
        let s = if tl > 0 {
            s.chars().take(tl).collect::<String>()
        } else {
            s.to_string()
        };
        if ignore {
            s.to_lowercase()
        } else {
            s
        }
    };
    cut(entry) == cut(name)
}

/// vim 'tagfunc' — `{Func}(pattern, flags, info)` returns a List of Dicts with
/// `name` / `filename` / `cmd`, replacing the `tags`-file lookup. Returns None
/// when 'tagfunc' is unset, so the built-in tags-file search runs instead.
fn tagfunc_lookup(
    cx: &mut compositor::Context,
    name: &str,
) -> Option<anyhow::Result<Vec<TagEntry>>> {
    let func = vim_opt_str("tagfunc").filter(|f| !f.trim().is_empty())?;
    // vim passes the flags string ("c" = called from a normal-mode command, "i"
    // = insert-mode completion) and an info Dict; we always call from `:tag`.
    let call = format!("{}({}, 'c', {{}})", func.trim(), viml_quote(name));
    Some((|| {
        viml_call(cx, &[], &call)?;
        let n = viml_list_len(cx)?;
        let mut out = Vec::with_capacity(n);
        for i in 0..n {
            let tag = viml_list_dict_str(cx, i, "name")?;
            let file = viml_list_dict_str(cx, i, "filename")?;
            let cmd = viml_list_dict_str(cx, i, "cmd")?;
            if file.trim().is_empty() {
                continue;
            }
            out.push(TagEntry {
                name: if tag.is_empty() {
                    name.to_string()
                } else {
                    tag
                },
                file: zmax_stdx::path::expand_tilde(std::path::Path::new(file.trim())).into_owned(),
                address: parse_tag_address(cmd.trim()),
            });
        }
        if out.is_empty() {
            bail!("E426: tag not found: {name}");
        }
        Ok(out)
    })())
}

/// Read the `tags` file and return every entry whose name is exactly `name`.
/// Errors if there is no tags file or no match — shared by `:tag`/`:tselect`/
/// `:tjump`/`:stag`. Honors vim `tagfunc` (a user function replaces the whole
/// lookup), `tagrelative` (relative entry paths resolve against the tags file's
/// directory; with `notagrelative`, against the working directory), `tagcase`
/// and `taglength`.
fn resolve_tag_matches(cx: &mut compositor::Context, name: &str) -> anyhow::Result<Vec<TagEntry>> {
    // vim 'tagfunc': a user function supplies the matches instead of the file.
    if let Some(found) = tagfunc_lookup(cx, name) {
        return found;
    }
    let (file, base) =
        find_tags_file(cx.editor).ok_or_else(|| anyhow!("no tags file found (run `ctags -R`)"))?;
    let base = if vim_opt_bool("tagrelative") {
        base
    } else {
        std::env::current_dir().unwrap_or(base)
    };
    let tagcase = vim_opt_str("tagcase").unwrap_or_else(|| "followic".to_string());
    let ignorecase = vim_opt_bool("ignorecase");
    let tl = vim_opt_num("taglength").unwrap_or(0);
    let matches: Vec<TagEntry> = parse_tags_file(&file, &base)
        .into_iter()
        .filter(|e| tag_name_matches(&e.name, name, &tagcase, ignorecase, tl))
        .collect();
    if matches.is_empty() {
        bail!("tag not found: {name}");
    }
    Ok(matches)
}

/// Push a picker over `matches`; selecting one pushes the tag stack and opens the
/// match with `action` — `Replace` for `:tselect`/`:tjump`, `HorizontalSplit` for
/// the split/preview variants (`:stselect`, `:ptselect`, `:stjump`, `:ptjump`).
fn push_tag_picker(cx: &mut compositor::Context, matches: Vec<TagEntry>, action: Action) {
    let action = split_mod(cx.editor, action);
    TAG_MATCHES.with(|m| *m.borrow_mut() = matches.clone());
    TAG_IDX.with(|i| i.set(0));
    let callback = async move {
        let call: job::Callback = job::Callback::EditorCompositor(Box::new(
            move |_editor: &mut Editor, compositor: &mut Compositor| {
                let columns = [
                    ui::PickerColumn::new("tag", |e: &TagEntry, _: &()| e.name.as_str().into()),
                    ui::PickerColumn::new("file", |e: &TagEntry, _: &()| {
                        e.file.to_string_lossy().into_owned().into()
                    }),
                    ui::PickerColumn::new("where", |e: &TagEntry, _: &()| match &e.address {
                        TagAddress::Line(n) => n.to_string().into(),
                        TagAddress::Pattern(p) => p.as_str().into(),
                    }),
                ];
                let picker = ui::Picker::new(
                    columns,
                    0,
                    matches,
                    (),
                    move |cx, entry: &TagEntry, _action| {
                        push_tag_from(cx);
                        if let Err(e) = jump_to_tag_action(cx, entry, action) {
                            cx.editor.set_error(e.to_string());
                        }
                    },
                );
                compositor.push(Box::new(overlaid(picker)));
            },
        ));
        Ok(call)
    };
    cx.jobs.callback(callback);
}

/// `:tselect {name}` — list every matching tag in a picker; selecting one pushes
/// the tag stack and jumps to it.
fn tag_select(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.join(" ");
    let name = name.trim();
    if name.is_empty() {
        bail!("usage: :tselect <name>");
    }
    let matches = resolve_tag_matches(cx, name)?;
    push_tag_picker(cx, matches, Action::Replace);
    Ok(())
}

/// `:tjump {name}` — jump straight to the tag if there is a single match, else
/// present the `:tselect` picker (vim :tjump).
fn tag_jump_or_select(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.join(" ");
    let name = name.trim();
    if name.is_empty() {
        bail!("usage: :tjump <name>");
    }
    let matches = resolve_tag_matches(cx, name)?;
    if matches.len() == 1 {
        push_tag_from(cx);
        let first = matches[0].clone();
        TAG_MATCHES.with(|m| *m.borrow_mut() = matches);
        TAG_IDX.with(|i| i.set(0));
        jump_to_tag(cx, &first)?;
        cx.editor.set_status(format!("tag: {name}"));
        Ok(())
    } else {
        push_tag_picker(cx, matches, Action::Replace);
        Ok(())
    }
}

/// `:stag {name}` — open the tag's definition in a new horizontal split
/// (vim :stag).
/// vim `CTRL-W }` — `:ptag` the identifier under the cursor: show its definition
/// in the preview window without leaving the current one. Shares `:ptag`'s body,
/// so the preview-window reuse and the tag stack behave identically whether the
/// tag came from a command line or from the word under the cursor.
pub(crate) fn preview_tag_under_cursor(cx: &mut compositor::Context) -> anyhow::Result<()> {
    let name = word_under_cursor(cx.editor);
    if name.is_empty() {
        bail!("E349: No identifier under cursor");
    }
    tag_split_impl(cx, &name, true)
}

/// vim `CTRL-W g }` — `:ptjump` the identifier under the cursor. Same as
/// [`preview_tag_under_cursor`] but offers the match list when the tag is
/// ambiguous instead of taking the first, which is vim's `:tag`/`:tjump` split.
pub(crate) fn preview_tjump_under_cursor(cx: &mut compositor::Context) -> anyhow::Result<()> {
    let name = word_under_cursor(cx.editor);
    if name.is_empty() {
        bail!("E349: No identifier under cursor");
    }
    tag_split_jump_impl(cx, &name, true)
}

fn tag_split(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.join(" ");
    let name = name.trim();
    if name.is_empty() {
        bail!("usage: :stag <name>");
    }
    tag_split_impl(cx, name, false)
}

/// vim `:ptag` — the same jump as `:stag`, into the preview window, leaving the
/// cursor where it was. They are opposites in vim and were one command here.
fn tag_preview(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.join(" ");
    let name = name.trim();
    if name.is_empty() {
        bail!("usage: :ptag <name>");
    }
    tag_split_impl(cx, name, true)
}

fn tag_split_impl(cx: &mut compositor::Context, name: &str, preview: bool) -> anyhow::Result<()> {
    let matches = resolve_tag_matches(cx, name)?;
    push_tag_from(cx);
    let n = matches.len();
    let first = matches[0].clone();
    TAG_MATCHES.with(|m| *m.borrow_mut() = matches);
    TAG_IDX.with(|i| i.set(0));
    jump_to_tag_action_preview(cx, &first, Action::HorizontalSplit, preview)?;
    cx.editor.set_status(format!("tag 1 of {n}: {name}"));
    Ok(())
}

/// Shared mover for `:tnext`/`:tprevious`/`:tfirst`/`:tlast` over the current
/// tag's match list.
fn tag_move(cx: &mut compositor::Context, to: TagMove) -> anyhow::Result<()> {
    tag_move_action(cx, to, Action::Replace, false)
}

/// `tag_move` with an explicit action — `Replace` for `:tnext`/`:tprevious`,
/// `HorizontalSplit` for the preview variants (`:ptnext`/`:ptprevious`/…), which
/// show the match in a split ("preview window") instead of replacing the buffer.
/// `preview` distinguishes the `:ptnext` family from the `:tnext` family, exactly
/// as it does for `:ptag` vs `:stag` — both open a horizontal split, so the action
/// cannot tell them apart. vim's `:ptnext` is "`:tnext` in the preview window. See
/// |:ptag|" (tagsrch.txt:346), and `:ptag` is the one that leaves the cursor put,
/// so the whole `pt*` family reuses the preview window and stays.
fn tag_move_action(
    cx: &mut compositor::Context,
    to: TagMove,
    action: Action,
    preview: bool,
) -> anyhow::Result<()> {
    let n = TAG_MATCHES.with(|m| m.borrow().len());
    if n == 0 {
        bail!("no tags");
    }
    let cur = TAG_IDX.with(|i| i.get());
    let idx = match to {
        TagMove::Next => {
            if cur + 1 >= n {
                bail!("tag: at last match");
            }
            cur + 1
        }
        TagMove::Prev => {
            if cur == 0 {
                bail!("tag: at first match");
            }
            cur - 1
        }
        TagMove::First => 0,
        TagMove::Last => n - 1,
    };
    let entry = TAG_MATCHES.with(|m| m.borrow()[idx].clone());
    TAG_IDX.with(|i| i.set(idx));
    jump_to_tag_action_preview(cx, &entry, action, preview)?;
    cx.editor
        .set_status(format!("tag {} of {}: {}", idx + 1, n, entry.name));
    Ok(())
}

/// Preview-window variants of the tag navigators — show the tag match in a
/// horizontal split (zmax has no dedicated preview window; a split is the
/// faithful approximation).
fn ptag_next(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    tag_move_action(cx, TagMove::Next, Action::HorizontalSplit, true)
}

fn ptag_prev(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    tag_move_action(cx, TagMove::Prev, Action::HorizontalSplit, true)
}

fn ptag_first(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    tag_move_action(cx, TagMove::First, Action::HorizontalSplit, true)
}

fn ptag_last(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    tag_move_action(cx, TagMove::Last, Action::HorizontalSplit, true)
}

fn tag_next(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    tag_move(cx, TagMove::Next)
}

fn tag_previous(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    tag_move(cx, TagMove::Prev)
}

fn tag_first(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    tag_move(cx, TagMove::First)
}

fn tag_last(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    tag_move(cx, TagMove::Last)
}

/// `:pop` — pop the tag stack, returning to where the last `:tag` jumped from.
fn tag_pop(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    tag_pop_action(cx, Action::Replace)
}

/// `:ppop` — `:pop` in the preview window: pop the tag stack and show the popped
/// location in a horizontal split (zmax models vim's preview window as a
/// split), leaving the current window's buffer untouched.
fn tag_pop_preview(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    tag_pop_action(cx, Action::HorizontalSplit)
}

/// Shared body of `:pop` / `:ppop`: pop the tag stack and open the popped frame
/// with `action`.
fn tag_pop_action(cx: &mut compositor::Context, action: Action) -> anyhow::Result<()> {
    tag_pop_editor(cx.editor, action)
}

/// [`tag_pop_action`] against a bare [`Editor`], so the static `tag_pop` command
/// bound to normal-mode `CTRL-T` pops the one real tag stack instead of
/// approximating the jump with the jumplist.
pub(crate) fn tag_pop_editor(editor: &mut Editor, action: Action) -> anyhow::Result<()> {
    let action = split_mod(editor, action);
    let frame = TAG_STACK.with(|s| s.borrow_mut().pop());
    match frame {
        None => bail!("at bottom of tag stack"),
        Some(f) => {
            editor.open(&f.file, action)?;
            let (view, doc) = current!(editor);
            let pos = f.pos.min(doc.text().len_chars());
            doc.set_selection(view.id, Selection::point(pos));
            let scrolloff = editor.config().scrolloff;
            let (view, doc) = current!(editor);
            view.ensure_cursor_in_view(doc, scrolloff);
            Ok(())
        }
    }
}

/// `:stjump {name}` / `:ptjump {name}` — like `:tjump` (jump straight to a lone
/// match, else offer the `:tselect` picker) but open the match in a new
/// horizontal split. zmax models vim's preview window as a split, so `:ptjump`
/// lands in the same place as `:stjump`.
fn tag_split_jump(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.join(" ");
    let name = name.trim();
    if name.is_empty() {
        bail!("usage: :stjump <name>");
    }
    tag_split_jump_impl(cx, name, false)
}

/// vim `:ptjump` — `:tjump` into the preview window, cursor staying put.
fn tag_preview_jump(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.join(" ");
    let name = name.trim();
    if name.is_empty() {
        bail!("usage: :ptjump <name>");
    }
    tag_split_jump_impl(cx, name, true)
}

fn tag_split_jump_impl(
    cx: &mut compositor::Context,
    name: &str,
    preview: bool,
) -> anyhow::Result<()> {
    let matches = resolve_tag_matches(cx, name)?;
    if matches.len() == 1 {
        push_tag_from(cx);
        let first = matches[0].clone();
        TAG_MATCHES.with(|m| *m.borrow_mut() = matches);
        TAG_IDX.with(|i| i.set(0));
        jump_to_tag_action_preview(cx, &first, Action::HorizontalSplit, preview)?;
        cx.editor.set_status(format!("tag: {name}"));
        Ok(())
    } else {
        // The picker's pick lands in the split; an ambiguous `:ptjump` is a
        // deliberate choice, so vim's "don't move" does not apply to it.
        push_tag_picker(cx, matches, Action::HorizontalSplit);
        Ok(())
    }
}

/// `:stselect {name}` / `:ptselect {name}` — like `:tselect`, but the chosen match
/// opens in a new horizontal split (vim's preview window is a split here).
fn tag_split_select(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.join(" ");
    let name = name.trim();
    if name.is_empty() {
        bail!("usage: :stselect <name>");
    }
    let matches = resolve_tag_matches(cx, name)?;
    push_tag_picker(cx, matches, Action::HorizontalSplit);
    Ok(())
}

/// The 1-based line of a tag entry: the ctags line address, or the first line of
/// the tag's file containing the ctags search pattern. Used to turn tag matches
/// into jumpable location-list entries for `:ltag`.
fn tag_entry_line(entry: &TagEntry) -> usize {
    match &entry.address {
        TagAddress::Line(n) => (*n).max(1),
        TagAddress::Pattern(pat) => std::fs::read_to_string(&entry.file)
            .ok()
            .and_then(|text| text.lines().position(|l| l.contains(pat.as_str())))
            .map(|i| i + 1)
            .unwrap_or(1),
    }
}

/// vim `:ltag {name}` — jump to `{name}`'s tag like `:tag`, and put every matching
/// tag in the location list (so `:lopen`/`:lnext` walk the other matches).
fn tag_location_list(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.join(" ");
    let name = name.trim();
    if name.is_empty() {
        bail!("usage: :ltag <name>");
    }
    let matches = resolve_tag_matches(cx, name)?;
    let mut text = String::new();
    for e in &matches {
        let _ = writeln!(
            text,
            "{}:{}: {}",
            e.file.display(),
            tag_entry_line(e),
            e.name
        );
    }
    qf_populate(cx, QfKind::Location, &text, false, false)?;
    push_tag_from(cx);
    let first = matches[0].clone();
    let n = matches.len();
    TAG_MATCHES.with(|m| *m.borrow_mut() = matches);
    TAG_IDX.with(|i| i.set(0));
    jump_to_tag(cx, &first)?;
    cx.editor
        .set_status(format!("tag 1 of {n}: {name} (location list filled)"));
    Ok(())
}

/// `:tags` — summarise the tag stack (depth) and the current match.
fn tags_stack_list(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let depth = TAG_STACK.with(|s| s.borrow().len());
    let cur = TAG_MATCHES.with(|m| {
        let m = m.borrow();
        let idx = TAG_IDX.with(|i| i.get());
        m.get(idx).map(|e| (e.name.clone(), idx + 1, m.len()))
    });
    match cur {
        Some((name, i, n)) => cx.editor.set_status(format!(
            "tag stack {depth} deep; current: {name} ({i} of {n})"
        )),
        None => cx.editor.set_status(format!("tag stack {depth} deep")),
    }
    Ok(())
}

/// neovim `:Man {topic}` — open a man page in the run console (formatting
/// stripped with `col -bx`). `:Man 3 printf` selects a section.
fn man_topic(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let topic = args.join(" ");
    let topic = topic.trim();
    if topic.is_empty() {
        bail!("usage: :Man <topic>  (e.g. :Man ls, :Man 3 printf)");
    }
    spawn_into_run_console(cx, format!("man {topic} | col -bx"));
    Ok(())
}

/// vim `:messages` / `:mes` — show the message log (every status/error/warning
/// shown this session, newest last), the way emacs shows its `*Messages*` buffer.
fn messages_list(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    if cx.editor.messages.is_empty() {
        cx.editor.set_status("no messages");
        return Ok(());
    }
    let rows: Vec<(&'static str, String)> = cx
        .editor
        .messages
        .iter()
        .map(|(m, sev)| {
            let tag = match sev {
                zmax_core::diagnostic::Severity::Error => "E",
                zmax_core::diagnostic::Severity::Warning => "W",
                _ => " ",
            };
            (tag, m.to_string())
        })
        .collect();
    cx.editor.autoinfo = Some(zmax_view::info::Info::new("Messages", &rows));
    Ok(())
}

/// Where a `:redir` capture is sent.
enum RedirTarget {
    Register(char),
    File {
        path: std::path::PathBuf,
        append: bool,
    },
}

thread_local! {
    /// Active `:redir` capture: the target plus the message-log length when it
    /// started (everything logged since is captured at `:redir END`).
    static REDIR: std::cell::RefCell<Option<(RedirTarget, usize)>> =
        const { std::cell::RefCell::new(None) };
}

/// vim `:redir` — capture subsequent message output into a register or file:
/// `:redir @a` (register), `:redir > file` / `:redir >> file` (truncate/append),
/// then `:redir END` to stop and flush. The captured stream is the message log
/// (echoes, command statuses) — the same stream `:messages` shows.
fn redir(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let arg = args.join(" ");
    let arg = arg.trim();
    if arg.is_empty() {
        bail!("usage: :redir @{{reg}} | :redir > file | :redir >> file | :redir END");
    }
    if arg.eq_ignore_ascii_case("end") {
        let (target, start) = REDIR
            .with(|r| r.borrow_mut().take())
            .ok_or_else(|| anyhow!("redir: not currently redirecting"))?;
        let msgs = &cx.editor.messages;
        let start = start.min(msgs.len());
        let captured: String = msgs[start..]
            .iter()
            .map(|(m, _)| m.as_ref())
            .collect::<Vec<_>>()
            .join("\n");
        match target {
            RedirTarget::Register(reg) => {
                cx.editor.registers.write(reg, vec![captured])?;
                cx.editor.set_status(format!("redirection ended (@{reg})"));
            }
            RedirTarget::File { path, append } => {
                use std::io::Write as _;
                std::fs::OpenOptions::new()
                    .create(true)
                    .write(true)
                    .append(append)
                    .truncate(!append)
                    .open(&path)
                    .and_then(|mut f| writeln!(f, "{captured}"))
                    .map_err(|e| anyhow!("redir: {}: {e}", path.display()))?;
                cx.editor
                    .set_status(format!("redirection ended ({})", path.display()));
            }
        }
        return Ok(());
    }
    let expand =
        |s: &str| zmax_stdx::path::expand_tilde(std::path::Path::new(s.trim())).into_owned();
    let target = if let Some(rest) = arg.strip_prefix('@') {
        let reg = rest
            .trim()
            .chars()
            .next()
            .ok_or_else(|| anyhow!("redir: expected @{{reg}}"))?;
        RedirTarget::Register(reg)
    } else if let Some(rest) = arg.strip_prefix(">>") {
        RedirTarget::File {
            path: expand(rest),
            append: true,
        }
    } else if let Some(rest) = arg.strip_prefix('>') {
        RedirTarget::File {
            path: expand(rest),
            append: false,
        }
    } else {
        bail!("redir: expected @{{reg}}, > file, >> file, or END");
    };
    let start = cx.editor.messages.len();
    REDIR.with(|r| *r.borrow_mut() = Some((target, start)));
    Ok(())
}

/// `:next-error` — Emacs `next-error` (`M-g n`): visit the next error's location.
fn next_error(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let entry = with_compilation(|c| c.next().cloned());
    match entry {
        Some(e) => goto_compile_entry(cx, &e),
        None => bail!("Moved past last error"),
    }
}

/// `:previous-error` — Emacs `previous-error` (`M-g p`): visit the previous
/// error's location.
fn previous_error(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let entry = with_compilation(|c| c.previous().cloned());
    match entry {
        Some(e) => goto_compile_entry(cx, &e),
        None => bail!("Moved back before first error"),
    }
}

/// `:first-error` — Emacs `first-error`: visit the first error's location.
fn first_error(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let entry = with_compilation(|c| c.first().cloned());
    match entry {
        Some(e) => goto_compile_entry(cx, &e),
        None => bail!("No errors"),
    }
}

// ---------------------------------------------------------------------------
// Vim abbreviations (`:abbreviate`, `:iabbrev`, `:cabbrev`, their `un…`/`…clear`
// siblings). One process-global table in a thread-local, like ARGLIST above.
// The pure state machine is `zmax_core::abbrev::AbbrevTable`; these commands
// drive it. NOTE: Insert-mode/command-line *expansion* is not yet wired into the
// typing path (it needs an editor hook that fires on a non-keyword trigger char
// and rewrites the word before the cursor). Until then these commands maintain
// and list the table faithfully; `AbbrevTable::find_expansion` is the primitive
// the future hook will call.
// ---------------------------------------------------------------------------

use zmax_core::abbrev::{AbbrevMode, AbbrevTable};

thread_local! {
    static ABBREVS: std::cell::RefCell<AbbrevTable> = std::cell::RefCell::new(AbbrevTable::new());
}

/// Run `f` against the global abbreviation table.
fn with_abbrevs<R>(f: impl FnOnce(&mut AbbrevTable) -> R) -> R {
    ABBREVS.with(|a| f(&mut a.borrow_mut()))
}

/// Vim's one-column mode marker used when listing abbreviations.
fn abbrev_mode_marker(mode: AbbrevMode) -> char {
    match mode {
        AbbrevMode::Insert => 'i',
        AbbrevMode::Command => 'c',
        AbbrevMode::Both => '!',
    }
}

/// Render the table for `mode` as Vim's `:abbreviate` listing, optionally
/// restricted to entries whose lhs starts with `prefix`.
fn abbrev_list(mode: AbbrevMode, prefix: Option<&str>) -> String {
    let entries: Vec<_> = with_abbrevs(|t| t.entries(mode))
        .into_iter()
        .filter(|(lhs, ..)| prefix.is_none_or(|p| lhs.starts_with(p)))
        .collect();
    if entries.is_empty() {
        return "No abbreviation found".to_string();
    }
    entries
        .iter()
        .map(|(lhs, rhs, m)| format!("{}  {:<12} {}", abbrev_mode_marker(*m), lhs, rhs))
        .collect::<Vec<_>>()
        .join("\n")
}

/// Shared body for `:abbreviate` / `:iabbrev` / `:cabbrev`: no args lists all,
/// a lone lhs lists matching entries, and `{lhs} {rhs…}` defines a new one.
fn abbrev_define(
    cx: &mut compositor::Context,
    mode: AbbrevMode,
    args: &Args,
) -> anyhow::Result<()> {
    if args.len() < 2 {
        let prefix = args.first();
        cx.editor.set_status(abbrev_list(mode, prefix));
        return Ok(());
    }
    let lhs = args[0].to_string();
    let rhs = args
        .iter()
        .skip(1)
        .map(|s| s.to_string())
        .collect::<Vec<_>>()
        .join(" ");
    if !with_abbrevs(|t| t.add(mode, &lhs, &rhs)) {
        bail!("E474: Not a valid abbreviation: {lhs}");
    }
    Ok(())
}

/// Shared body for `:unabbreviate` / `:iunabbreviate` / `:cunabbreviate`.
fn abbrev_undefine(
    cx: &mut compositor::Context,
    mode: AbbrevMode,
    args: &Args,
) -> anyhow::Result<()> {
    let Some(lhs) = args.first().map(|s| s.to_string()) else {
        bail!("E474: Argument required");
    };
    if !with_abbrevs(|t| t.remove(mode, &lhs)) {
        bail!("E24: No such abbreviation: {lhs}");
    }
    let _ = cx;
    Ok(())
}

/// `:abbreviate` — list or define an abbreviation for Insert *and* Command-line.
fn abbreviate(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    abbrev_define(cx, AbbrevMode::Both, &args)
}

/// Emacs `list-abbrevs`: show every defined abbreviation in a scratch buffer.
fn list_abbrevs(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let text = abbrev_list(AbbrevMode::Both, None);
    cx.editor.new_file(Action::Replace);
    let (view, doc) = current!(cx.editor);
    let body = format!("{text}\n");
    let insert = Transaction::insert(
        doc.text(),
        &zmax_core::Selection::point(0),
        body.as_str().into(),
    );
    doc.apply(&insert, view.id);
    doc.append_changes_to_history(view);
    Ok(())
}

/// Emacs `define-global-abbrev`: define an abbrev in the global (both-modes)
/// table (`:define-global-abbrev NAME EXPANSION`).
fn define_global_abbrev(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.first().map(|s| s.to_string()).unwrap_or_default();
    let expansion = args
        .iter()
        .skip(1)
        .map(|s| s.to_string())
        .collect::<Vec<_>>()
        .join(" ");
    if name.is_empty() || expansion.is_empty() {
        bail!("define-global-abbrev: needs NAME EXPANSION");
    }
    with_abbrevs(|t| t.add(AbbrevMode::Both, &name, &expansion));
    cx.editor
        .set_status(format!("(global) \"{name}\" -> \"{expansion}\""));
    Ok(())
}

/// Emacs `abbrev-mode`: toggle (or with `on`/`off`/`enable`/`disable`/`1`/`0`,
/// set) the minor mode that auto-expands abbrevs when a word separator is typed.
fn ex_abbrev_mode(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let on = match args
        .first()
        .map(|s| s.trim().to_ascii_lowercase())
        .as_deref()
    {
        Some("on") | Some("enable") | Some("1") | Some("t") => true,
        Some("off") | Some("disable") | Some("0") | Some("nil") => false,
        _ => !cx.editor.abbrev_mode,
    };
    cx.editor.abbrev_mode = on;
    cx.editor.set_status(if on {
        "Abbrev mode enabled"
    } else {
        "Abbrev mode disabled"
    });
    Ok(())
}

/// Emacs `define-mode-abbrev` NAME EXPANSION: define an abbrev in the current
/// buffer's major-mode-local table (its language, or `fundamental` when none), so
/// `expand-abbrev` expands it only in that mode. The mode-local counterpart of
/// `define-global-abbrev`; it feeds the same store `expand-abbrev` reads.
fn define_mode_abbrev(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.first().map(|s| s.to_string()).unwrap_or_default();
    let expansion = args
        .iter()
        .skip(1)
        .map(|s| s.to_string())
        .collect::<Vec<_>>()
        .join(" ");
    if name.is_empty() || expansion.is_empty() {
        bail!("define-mode-abbrev: needs NAME EXPANSION");
    }
    let mode = current!(cx.editor)
        .1
        .language_name()
        .map(str::to_string)
        .unwrap_or_else(|| "fundamental".to_string());
    crate::emacs_abbrev::define_mode(&mode, &name, &expansion);
    cx.editor
        .set_status(format!("({mode}) \"{name}\" -> \"{expansion}\""));
    Ok(())
}

/// Emacs `kill-all-abbrevs`: remove every defined abbreviation.
fn kill_all_abbrevs(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    with_abbrevs(|t| {
        t.clear(AbbrevMode::Insert);
        t.clear(AbbrevMode::Command);
        t.clear(AbbrevMode::Both);
    });
    cx.editor.set_status("all abbreviations killed");
    Ok(())
}

/// `:iabbrev` — like `:abbreviate` but Insert mode only.
fn iabbrev(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    abbrev_define(cx, AbbrevMode::Insert, &args)
}

/// `:cabbrev` — like `:abbreviate` but Command-line mode only.
fn cabbrev(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    abbrev_define(cx, AbbrevMode::Command, &args)
}

// `:noreabbrev` / `:inoreabbrev` / `:cnoreabbrev` are the non-recursive forms of
// `:abbreviate` / `:iabbrev` / `:cabbrev`. Vim's `nore` prefix means the rhs is
// not itself subject to further mapping/abbreviation expansion. zmax
// abbreviations always expand to literal text (no recursive re-expansion), so
// the `nore` variants are behaviourally identical to the plain forms — they
// exist so muscle-memory `:noreabbrev` etc. work.

/// `:noreabbrev` — like `:abbreviate` (Insert + Command-line), non-recursive.
fn noreabbrev(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    abbrev_define(cx, AbbrevMode::Both, &args)
}

