/// `:spelldump` — open a buffer listing the user's known-good words (vim
/// `:spelldump` fills a window with the wordlist).
fn spell_dump(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let words = crate::spell::good_words();
    cx.editor.new_file(Action::Replace);
    let text = if words.is_empty() {
        "# no user spellgood words\n".to_string()
    } else {
        let mut t = words.join("\n");
        t.push('\n');
        t
    };
    let (view, doc) = current!(cx.editor);
    let insert = Transaction::insert(
        doc.text(),
        &zmax_core::Selection::point(0),
        text.as_str().into(),
    );
    doc.apply(&insert, view.id);
    doc.append_changes_to_history(view);
    Ok(())
}

/// `:spellinfo` — show where the spell wordlists live and their sizes.
fn spell_info(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    cx.editor.set_status(format!(
        "spell: {} good, {} bad words · {}",
        crate::spell::good_words().len(),
        crate::spell::bad_words().len(),
        zmax_loader::config_dir().display()
    ));
    Ok(())
}

/// vim `:mkspell[!] {outname} {infile} …` — compile word lists into the spell
/// dictionary `{outname}`. vim's output is a binary `.spl`; zmax's speller reads
/// hunspell/plain word lists, so the compiled dictionary is written where
/// 'spelllang' looks for one (`<config>/spell/{outname}.dic`) and
/// `:set spelllang={outname}` starts checking against it immediately. Every input
/// file's words are merged, deduplicated and sorted, `#` comment lines and
/// hunspell affix flags (`word/AB`) dropped.
fn ex_mkspell(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    sandbox_check("mkspell")?;
    let tokens: Vec<String> = args.iter().map(|a| a.to_string()).collect();
    let (out, inputs) = tokens
        .split_first()
        .ok_or_else(|| anyhow!("usage: :mkspell {{outname}} {{infile}} …"))?;
    // vim strips the `.spl` suffix from the output name; the dictionary is named
    // by the language, not the file.
    let name = out
        .trim()
        .trim_end_matches(".spl")
        .rsplit('/')
        .next()
        .unwrap_or("")
        .to_string();
    if name.is_empty() {
        bail!("mkspell: empty output name");
    }
    if inputs.is_empty() {
        bail!("usage: :mkspell {{outname}} {{infile}} … (no word list given)");
    }
    let mut merged = String::new();
    for file in inputs {
        let path = zmax_stdx::path::expand_tilde(std::path::Path::new(file.trim()));
        let text = std::fs::read_to_string(&path)
            .map_err(|e| anyhow!("mkspell: cannot read {}: {e}", path.display()))?;
        merged.push_str(&text);
        merged.push('\n');
    }
    let (path, words) =
        crate::spell::install_dict(&name, &merged).map_err(|e| anyhow!("mkspell: {e}"))?;
    cx.editor.set_status(format!(
        "mkspell: {words} word(s) written to {} (:set spelllang={name})",
        path.display()
    ));
    Ok(())
}

fn buffer_close_by_ids_impl(
    cx: &mut compositor::Context,
    doc_ids: &[DocumentId],
    force: bool,
) -> anyhow::Result<()> {
    cx.block_try_flush_writes()?;

    let (modified_ids, modified_names): (Vec<_>, Vec<_>) = doc_ids
        .iter()
        .filter_map(|&doc_id| {
            // Scratch buffers (no backing file) are disposable — closing one only
            // discards throwaway text, so never block on them the way an unsaved
            // *file* is blocked. This lets `SPC b x` / `:buffer-close` close a
            // `[scratch]` buffer without needing the `!` force form.
            let is_scratch = cx
                .editor
                .document(doc_id)
                .is_some_and(|d| d.path().is_none());
            let force = force || is_scratch;
            if let Err(CloseError::BufferModified(name)) = cx.editor.close_document(doc_id, force) {
                Some((doc_id, name))
            } else {
                None
            }
        })
        .unzip();

    if let Some(first) = modified_ids.first() {
        let current = doc!(cx.editor);
        // If the current document is unmodified, and there are modified
        // documents, switch focus to the first modified doc.
        if !modified_ids.contains(&current.id()) {
            cx.editor.switch(*first, Action::Replace);
        }
        bail!(
            "{} unsaved buffer{} remaining: {:?}",
            modified_names.len(),
            if modified_names.len() == 1 { "" } else { "s" },
            modified_names,
        );
    }

    Ok(())
}

fn buffer_gather_paths_impl(editor: &mut Editor, args: Args) -> Vec<DocumentId> {
    // No arguments implies current document
    if args.is_empty() {
        let doc_id = view!(editor).doc;
        return vec![doc_id];
    }

    let mut nonexistent_buffers = vec![];
    let mut document_ids = vec![];
    for arg in args {
        let doc_id = editor.documents().find_map(|doc| {
            let arg_path = Some(Path::new(arg.as_ref()));
            if doc.path() == arg_path || doc.relative_path() == arg_path {
                Some(doc.id())
            } else {
                None
            }
        });

        match doc_id {
            Some(doc_id) => document_ids.push(doc_id),
            None => nonexistent_buffers.push(format!("'{}'", arg)),
        }
    }

    if !nonexistent_buffers.is_empty() {
        editor.set_error(format!(
            "cannot close non-existent buffers: {}",
            nonexistent_buffers.join(", ")
        ));
    }

    document_ids
}

fn buffer_close(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }

    let document_ids = buffer_gather_paths_impl(cx.editor, args);
    buffer_close_by_ids_impl(cx, &document_ids, false)
}

fn force_buffer_close(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }

    let document_ids = buffer_gather_paths_impl(cx.editor, args);
    buffer_close_by_ids_impl(cx, &document_ids, true)
}

fn buffer_gather_others_impl(editor: &mut Editor, skip_visible: bool) -> Vec<DocumentId> {
    if skip_visible {
        let visible_document_ids = editor
            .tree
            .views()
            .map(|view| &view.0.doc)
            .collect::<HashSet<_>>();
        editor
            .documents()
            .map(|doc| doc.id())
            .filter(|doc_id| !visible_document_ids.contains(doc_id))
            .collect()
    } else {
        let current_document = &doc!(editor).id();
        editor
            .documents()
            .map(|doc| doc.id())
            .filter(|doc_id| doc_id != current_document)
            .collect()
    }
}

fn buffer_close_others(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }

    let document_ids = buffer_gather_others_impl(cx.editor, args.has_flag("skip-visible"));
    buffer_close_by_ids_impl(cx, &document_ids, false)
}

