/// `:delmarks {marks}` — delete the listed named marks (vim `:delmarks`/`:delm`).
fn del_marks(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let spec: String = args.join("");
    let spec = spec.trim();
    ensure!(
        !spec.is_empty(),
        ":delmarks requires marks (or use :delmarks! for all)"
    );
    let n = {
        let doc = doc_mut!(cx.editor);
        spec.chars()
            .filter(|c| !c.is_whitespace() && *c != ',')
            .filter(|&c| doc.remove_mark(c))
            .count()
    };
    cx.editor.set_status(format!("deleted {n} mark(s)"));
    Ok(())
}

/// `:project-replace {pattern} {replacement}` / `:replace-in-files` — JetBrains "Replace in Files":
/// regex-replace across every workspace file that matches `pattern` (ripgrep finds the
/// files; `$1`-style capture refs work in the replacement), writing changed files and reloading any
/// open buffers. Destructive across the working tree — recoverable via git.
fn project_replace(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let pattern = args[0].to_string();
    let replacement = args[1].to_string();
    run_project_replace(cx, pattern, replacement)
}

/// Core of `:project-replace` / Emacs `project-query-replace-regexp`: replace
/// every regex match of `pattern` with `replacement` across the project's
/// tracked files (found via `rg -l`), off-thread, then reload affected buffers.
/// Shared by the typable command and the static `project_query_replace_regexp`.
pub(crate) fn run_project_replace(
    cx: &mut compositor::Context,
    pattern: String,
    replacement: String,
) -> anyhow::Result<()> {
    let re = regex::Regex::new(&pattern).map_err(|e| anyhow!("invalid pattern: {e}"))?;
    let root = zmax_loader::find_workspace().0;
    cx.editor.set_status("project-replace: searching…");
    cx.jobs.callback(async move {
        let res =
            tokio::task::spawn_blocking(move || -> (usize, usize, Vec<std::path::PathBuf>) {
                let out = std::process::Command::new("rg")
                    .arg("-l")
                    .arg("--null")
                    .arg("-e")
                    .arg(&pattern)
                    .current_dir(&root)
                    .output();
                let files: Vec<std::path::PathBuf> = match out {
                    Ok(o) if o.status.success() => String::from_utf8_lossy(&o.stdout)
                        .split('\0')
                        .filter(|s| !s.is_empty())
                        .map(|s| root.join(s))
                        .collect(),
                    _ => Vec::new(),
                };
                let mut changed = Vec::new();
                let mut total = 0usize;
                for path in files {
                    let Ok(content) = std::fs::read_to_string(&path) else {
                        continue;
                    };
                    let count = re.find_iter(&content).count();
                    if count == 0 {
                        continue;
                    }
                    let new = re.replace_all(&content, replacement.as_str());
                    if new != content && std::fs::write(&path, new.as_bytes()).is_ok() {
                        total += count;
                        changed.push(path);
                    }
                }
                (changed.len(), total, changed)
            })
            .await
            .map_err(|e| anyhow!("project-replace task: {e}"))?;
        let (nfiles, total, paths) = res;
        Ok(job::Callback::Editor(Box::new(
            move |editor: &mut Editor| {
                crate::commands::reload_docs_for_paths(editor, &paths);
                editor.set_status(format!(
                    "project-replace: {total} replacement(s) in {nfiles} file(s)"
                ));
            },
        )))
    });
    Ok(())
}

