/// `:arduino-new-sketch <name>` — scaffold a new sketch (`arduino-cli sketch new`)
/// in the workspace and open its `.ino` (Arduino IDE File → New Sketch).
fn arduino_new_sketch(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.join(" ");
    let name = name.trim();
    if name.is_empty() {
        bail!("usage: :arduino-new-sketch <name>");
    }
    require_tool(embedded::ARDUINO_CLI)?;
    let root = zmax_loader::find_workspace().0;
    let output = std::process::Command::new(embedded::ARDUINO_CLI)
        .args(["sketch", "new", name])
        .current_dir(&root)
        .output()
        .map_err(|e| anyhow!("sketch new: {e}"))?;
    if !output.status.success() {
        bail!(
            "sketch new failed: {}",
            String::from_utf8_lossy(&output.stderr).trim()
        );
    }
    let ino = root.join(name).join(format!("{name}.ino"));
    cx.editor.open(&ino, Action::Replace)?;
    cx.editor
        .set_status(format!("Created sketch `{name}` → {}", ino.display()));
    Ok(())
}

/// Stream a read-only embedded backend command (board/core/lib listings) into
/// the jumpable Run console. `in_project` prefixes `cd <sketch-dir>` for
/// project-scoped `pio` calls that must run where `platformio.ini` lives.
fn embedded_browse(cx: &mut compositor::Context, argv: Vec<String>, in_project: bool) {
    let cmd = if in_project {
        let dir = embedded::load().sketch_dir();
        format!(
            "cd {} && {}",
            embedded::shell_join(&[dir.to_string_lossy().into_owned()]),
            embedded::shell_join(&argv)
        )
    } else {
        embedded::shell_join(&argv)
    };
    spawn_into_run_console(cx, cmd);
}

