// --- Quickfix / location list (`:copen`, `:cnext`, `:lopen`, … ) -----------
use crate::commands::QfKind;

/// The concrete type `build_qf_picker` pushes — the layer `:cclose`/`:lclose`
/// must remove. (`Compositor::remove_type` matches on the type name, so this has
/// to name the same type the picker was built as.)
type QfPicker = crate::ui::overlay::Overlay<ui::Picker<zmax_view::editor::QfEntry, ()>>;

/// vim `:cclose` / `:lclose` — close the quickfix / location-list window. zmax
/// shows it as a picker overlay, so closing it means removing that layer; when it
/// is not on screen, say so rather than pretending.
fn qf_close_window(cx: &mut compositor::Context, what: &'static str) {
    let call = job::Callback::EditorCompositor(Box::new(
        move |editor: &mut Editor, compositor: &mut Compositor| {
            if compositor.find::<QfPicker>().is_some() {
                compositor.remove_type::<QfPicker>();
                editor.set_status(format!("{what} window closed"));
            } else {
                editor.set_status(format!("no {what} window open"));
            }
        },
    ));
    cx.jobs.callback(async move { Ok(call) });
}

/// vim `:cbottom` / `:lbottom` — scroll the quickfix / location-list window to its
/// last entry. zmax shows that window as a picker, so "scrolled to the bottom"
/// means its cursor sits on the last entry; like vim, nothing is jumped to (the
/// entry is selected, not opened).
fn qf_scroll_bottom(cx: &mut compositor::Context, what: &'static str) {
    let call = job::Callback::EditorCompositor(Box::new(
        move |editor: &mut Editor, compositor: &mut Compositor| match compositor.find::<QfPicker>()
        {
            Some(picker) => {
                picker.content.to_end();
                editor.set_status(format!("{what}: at the last entry"));
            }
            None => editor.set_error(format!("no {what} window open")),
        },
    ));
    cx.jobs.callback(async move { Ok(call) });
}

fn ex_cbottom(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    qf_scroll_bottom(cx, "quickfix");
    Ok(())
}

fn ex_lbottom(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    qf_scroll_bottom(cx, "location list");
    Ok(())
}

/// Open the quickfix/location-list window (a picker overlay) from a typable.
fn qf_open_window(cx: &mut compositor::Context, kind: QfKind) {
    let call = job::Callback::EditorCompositor(Box::new(move |editor, compositor| {
        compositor.push(crate::commands::build_qf_picker(editor, kind));
    }));
    cx.jobs.callback(async move { Ok(call) });
}

/// Parse `text` into list entries (replacing or appending), report the count,
/// and optionally jump to the first entry. Shared by the `:c*`/`:l*` populators.
fn qf_populate(
    cx: &mut compositor::Context,
    kind: QfKind,
    text: &str,
    append: bool,
    jump: bool,
) -> anyhow::Result<()> {
    let entries = crate::commands::qf_entries_from_text(text);
    if entries.is_empty() && !append {
        bail!("no valid entries found (expected `path:line[:col]` lines)");
    }
    let n = crate::commands::qf_set_entries(cx.editor, kind, entries, append);
    cx.editor.set_status(format!(
        "{} entr{} added",
        n,
        if n == 1 { "y" } else { "ies" }
    ));
    if jump {
        crate::commands::qf_jump_nth(cx.editor, kind, Some(1));
    }
    Ok(())
}

/// The whole current buffer as a string (source for `:cbuffer`/`:lbuffer`).
fn current_buffer_text(cx: &compositor::Context) -> String {
    doc!(cx.editor).text().to_string()
}

/// Optional leading `[count]` for the cursor-relative motions; defaults to 1.
fn qf_dir_count(args: &Args) -> usize {
    args.first()
        .and_then(|s| s.parse::<usize>().ok())
        .unwrap_or(1)
}

macro_rules! qf_nav_cmd {
    ($name:ident, $kind:expr, $body:expr) => {
        fn $name(
            cx: &mut compositor::Context,
            args: Args,
            event: PromptEvent,
        ) -> anyhow::Result<()> {
            if event != PromptEvent::Validate {
                return Ok(());
            }
            let _ = &args;
            let f: fn(&mut compositor::Context, &Args) -> anyhow::Result<()> = $body;
            f(cx, &args)
        }
    };
}

