// --- Tabpages (`:tabnew`, `:tabnext`, `:tabclose`, …) ----------------------

fn tab_new(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let path = args.join(" ");
    let path = path.trim();
    cx.editor.new_tab();
    if !path.is_empty() {
        cx.editor.open(
            std::path::Path::new(path),
            zmax_view::editor::Action::Replace,
        )?;
    }
    Ok(())
}

fn tab_next(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    match args.first().and_then(|s| s.parse::<usize>().ok()) {
        Some(n) if n >= 1 => cx.editor.switch_tab(n - 1),
        _ => cx.editor.goto_next_tabpage(),
    }
    Ok(())
}

fn tab_previous(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    cx.editor.goto_previous_tabpage();
    Ok(())
}

/// Which tab page gets the focus after `:tabclose`, from nvim 'tabclose':
/// `left` focuses the tab to the left of the closed one, `uselast` the
/// last-accessed tab. Empty (the default) keeps zmax's own choice. Pure —
/// unit tested.
fn tabclose_focus(spec: &str) -> Option<&'static str> {
    let has = |flag: &str| spec.split(',').any(|s| s.trim() == flag);
    if has("uselast") {
        Some("uselast")
    } else if has("left") {
        Some("left")
    } else {
        None
    }
}

fn tab_close(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    // nvim `tabclose`: which tab is focused after this one closes.
    let spec = vim_opt_str_alias("tabclose", "tcl").unwrap_or_default();
    let closed = cx.editor.current_tab();
    cx.editor.close_tab();
    match tabclose_focus(&spec) {
        Some("uselast") => {
            cx.editor.tab_history_back();
        }
        Some("left") => {
            let to = closed.saturating_sub(1);
            if to < cx.editor.tab_count() {
                cx.editor.switch_tab(to);
            }
        }
        _ => {}
    }
    Ok(())
}

fn tab_only(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    cx.editor.tab_only();
    Ok(())
}

/// emacs `tab-rename` — set (or clear, when empty) the current tab's name.
fn ex_tab_rename(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.join(" ");
    let name = name.trim();
    cx.editor
        .rename_current_tab((!name.is_empty()).then(|| name.to_string()));
    cx.editor.set_status(if name.is_empty() {
        "Tab name cleared".to_string()
    } else {
        format!("Tab renamed to {name}")
    });
    Ok(())
}

/// emacs `tab-switch` — switch to a tab by name or 1-based number.
fn ex_tab_switch(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let input = args.join(" ");
    let input = input.trim();
    if input.is_empty() {
        bail!("tab-switch: needs a tab name or number");
    }
    let by_name = cx
        .editor
        .tab_names()
        .into_iter()
        .find(|(_, n)| n.as_deref() == Some(input))
        .map(|(i, _)| i);
    match by_name.or_else(|| input.parse::<usize>().ok().map(|n| n.saturating_sub(1))) {
        Some(idx) => cx.editor.switch_tab(idx),
        None => bail!("no tab named '{input}'"),
    }
    Ok(())
}

/// emacs `tab-undo` — reopen the most recently closed tab.
fn ex_tab_undo(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    if !cx.editor.reopen_closed_tab() {
        cx.editor.set_error("no closed tab to reopen");
    }
    Ok(())
}

/// emacs `tab-bar-history-back` — return to the previously visited tab.
fn ex_tab_history_back(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    if !cx.editor.tab_history_back() {
        cx.editor.set_status("no earlier tab in history");
    }
    Ok(())
}

/// emacs `tab-bar-history-forward` — re-visit a tab left via history-back.
fn ex_tab_history_forward(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    if !cx.editor.tab_history_forward() {
        cx.editor.set_status("no later tab in history");
    }
    Ok(())
}

fn tab_first(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    cx.editor.switch_tab(0);
    Ok(())
}

fn tab_last(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let n = cx.editor.tab_count();
    cx.editor.switch_tab(n.saturating_sub(1));
    Ok(())
}

fn tab_move(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let to = match args.first().and_then(|s| s.parse::<usize>().ok()) {
        Some(n) => n,
        None => cx.editor.tab_count().saturating_sub(1),
    };
    cx.editor.move_current_tab(to);
    Ok(())
}

fn tab_do(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let cmd = args.join(" ");
    if cmd.trim().is_empty() {
        bail!("usage: :tabdo <command>");
    }
    for i in 0..cx.editor.tab_count() {
        cx.editor.switch_tab(i);
        run_command_line(cx, &cmd);
    }
    Ok(())
}

fn tabs_list(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let call = job::Callback::EditorCompositor(Box::new(|editor, compositor| {
        compositor.push(crate::commands::build_tabs_picker(editor));
    }));
    cx.jobs.callback(async move { Ok(call) });
    Ok(())
}

// --- Quickfix/location extensions: :cdo, :clist, history, add-variants -----

/// `:cdo`/`:cfdo`/`:ldo`/`:lfdo` — run an ex-command on each list entry (or the
/// first entry of each file).
fn qf_do(
    cx: &mut compositor::Context,
    kind: QfKind,
    per_file: bool,
    args: &Args,
) -> anyhow::Result<()> {
    let cmd = args.join(" ");
    if cmd.trim().is_empty() {
        bail!("usage: :cdo <command>");
    }
    let entries = crate::commands::qf_snapshot(cx.editor, kind);
    if entries.is_empty() {
        bail!("list is empty");
    }
    let mut seen_files = std::collections::HashSet::new();
    for (i, e) in entries.iter().enumerate() {
        if per_file && !seen_files.insert(e.path.clone()) {
            continue;
        }
        crate::commands::qf_jump_nth(cx.editor, kind, Some(i + 1));
        run_command_line(cx, &cmd);
    }
    Ok(())
}

