/// `:outline-hide-by-heading-regexp <regex>` — Emacs
/// `outline-hide-by-heading-regexp`: fold the subtree of every heading whose
/// heading line matches the regexp.
fn outline_hide_by_heading_regexp(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let pattern = args.join(" ");
    let pattern = pattern.trim();
    if pattern.is_empty() {
        anyhow::bail!("usage: :outline-hide-by-heading-regexp <regex>");
    }
    let re = regex::Regex::new(pattern).map_err(|e| anyhow!("invalid pattern: {e}"))?;
    let (_, doc) = current!(cx.editor);
    let text = doc.text().to_string();
    let total = doc.text().len_lines();
    let hs = zmax_core::outline::headings(&text);
    let lines: Vec<&str> = text.split('\n').collect();
    let matches: Vec<bool> = hs
        .iter()
        .map(|h| lines.get(h.line).is_some_and(|l| re.is_match(l)))
        .collect();
    let folds = zmax_core::outline::matching_subtree_bodies(&hs, total, |i| matches[i]);
    for (first, last) in folds {
        doc.folds_mut().create(first, last);
        doc.folds_mut().close(first);
    }
    doc.folds_mut().clamp(total.saturating_sub(1));
    Ok(())
}

/// `:highlight-regexp <regex>` — Emacs `highlight-regexp`: add a persistent
/// Hi-Lock highlight for the regexp.
fn highlight_regexp(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let pattern = args.join(" ");
    let pattern = pattern.trim();
    // Emacs prompts for the regexp (this is a key-bound command), so a bare
    // `:highlight-regexp` asks instead of failing.
    if pattern.is_empty() {
        prompt_for_arg(
            cx,
            "Regexp to highlight: ",
            "highlight-regexp",
            completers::none,
        );
        return Ok(());
    }
    crate::hi_lock::add(pattern, false).map_err(|e| anyhow!("highlight-regexp: {e}"))?;
    cx.editor.set_status(format!("Highlighting /{pattern}/"));
    Ok(())
}

/// `:highlight-phrase <phrase>` — Emacs `highlight-phrase`: highlight the phrase,
/// treating runs of whitespace as `\s+` (so line breaks still match).
fn highlight_phrase(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let phrase = args.join(" ");
    let phrase = phrase.trim();
    if phrase.is_empty() {
        prompt_for_arg(
            cx,
            "Phrase to highlight: ",
            "highlight-phrase",
            completers::none,
        );
        return Ok(());
    }
    // hi-lock-process-phrase: collapse whitespace to \s+ over the escaped phrase.
    let escaped = regex::escape(phrase);
    let collapsed = regex::Regex::new(r"\\?\s+")
        .unwrap()
        .replace_all(&escaped, r"\s+")
        .into_owned();
    crate::hi_lock::add(&collapsed, false).map_err(|e| anyhow!("highlight-phrase: {e}"))?;
    cx.editor
        .set_status(format!("Highlighting phrase \"{phrase}\""));
    Ok(())
}

