/// Build a SQL `IN`-list — `('a', 'b', 'c')` — from the non-blank selected lines,
/// single-quoting each (doubling any embedded `'`). Pure — unit tested.
fn sql_in_list(input: &str) -> String {
    let items: Vec<String> = input
        .lines()
        .map(str::trim)
        .filter(|l| !l.is_empty())
        .map(|l| format!("'{}'", l.replace('\'', "''")))
        .collect();
    format!("({})", items.join(", "))
}

