/// Sort the lines of `input` by character length (shortest first), breaking ties
/// lexically for determinism. Pure — unit tested.
fn sort_by_length(input: &str) -> String {
    let mut lines: Vec<&str> = input.lines().collect();
    lines.sort_by(|a, b| {
        a.chars()
            .count()
            .cmp(&b.chars().count())
            .then_with(|| a.cmp(b))
    });
    lines.join("\n")
}

