/// Join the lines of `input` into a single CSV row, RFC-4180 quoting any field that
/// contains a comma, quote, or newline (embedded quotes doubled). Pure — unit tested.
fn lines_to_csv_row(input: &str) -> String {
    input
        .lines()
        .map(|l| {
            if l.contains([',', '"', '\n']) {
                format!("\"{}\"", l.replace('"', "\"\""))
            } else {
                l.to_string()
            }
        })
        .collect::<Vec<_>>()
        .join(",")
}

