/// Resolve a `:cd` argument through vim's `cdpath`: a relative directory that
/// doesn't exist under the working directory is looked for under each `cdpath`
/// entry (an empty entry means the working directory itself). Pure — unit tested.
fn resolve_cdpath(
    arg: &Path,
    cwd: &Path,
    cdpath: Option<&str>,
    exists: impl Fn(&Path) -> bool,
) -> PathBuf {
    if arg.is_absolute() || arg.starts_with("./") || arg.starts_with("../") {
        return arg.to_path_buf();
    }
    let Some(cdpath) = cdpath else {
        return arg.to_path_buf();
    };
    if exists(&cwd.join(arg)) {
        return arg.to_path_buf();
    }
    for entry in cdpath.split(',').map(str::trim) {
        let base = if entry.is_empty() {
            cwd.to_path_buf()
        } else {
            zmax_stdx::path::expand_tilde(Path::new(entry)).into_owned()
        };
        let candidate = base.join(arg);
        if exists(&candidate) {
            return candidate;
        }
    }
    arg.to_path_buf()
}

/// Helper function to parse the first argument as a directory. Honors vim
/// `cdpath`: a relative directory that isn't under the working directory is
/// looked up in each `cdpath` entry.
#[inline]
fn parse_first_arg_as_dir(args: &Args, last_cwd: Option<PathBuf>) -> anyhow::Result<PathBuf> {
    match args.first().map(AsRef::as_ref) {
        Some("-") => last_cwd.ok_or_else(|| anyhow!("No previous working directory")),
        Some(path) => {
            let expanded = zmax_stdx::path::expand_tilde(Path::new(path)).into_owned();
            Ok(resolve_cdpath(
                &expanded,
                &zmax_stdx::env::current_working_dir(),
                vim_opt_str_alias("cdpath", "cd").as_deref(),
                |p| p.is_dir(),
            ))
        }
        None => Ok(home_dir()?),
    }
}

/// Helper function to apply a directory change for an already-parsed Path ref
#[inline]
fn apply_directory_change(cx: &mut compositor::Context, dir: &Path) -> anyhow::Result<()> {
    cx.editor.set_cwd(dir).map_err(|err| {
        anyhow!(
            "Could not change working directory to '{}': {err}",
            dir.display()
        )
    })?;

    cx.editor.set_status(format!(
        "Current working directory is now {}",
        zmax_stdx::env::current_working_dir().display()
    ));

    Ok(())
}

fn change_current_directory(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }

    // vim `cdhome`: with `:set nocdhome`, a bare `:cd` reports the working
    // directory instead of going home (vim's non-Unix behaviour).
    if args.is_empty() && !vim_opt_bool("cdhome") {
        cx.editor
            .set_status(zmax_stdx::env::current_working_dir().display().to_string());
        return Ok(());
    }

    let dir = parse_first_arg_as_dir(&args, cx.editor.get_last_cwd().map(|p| p.to_path_buf()))?;

    apply_directory_change(cx, &dir)
}

fn show_directory_stack(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }

    let serialized_stack = cx
        .editor
        .dir_stack
        .iter()
        .map(|p| p.display().to_string())
        .collect::<Vec<_>>()
        .join(" ");

    if !serialized_stack.is_empty() {
        cx.editor.set_status(serialized_stack);
    } else {
        cx.editor.set_error("Stack is empty");
    }

    Ok(())
}

fn push_directory(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }

    // avoid an unbounded directory stack and reallocs for perf
    if cx.editor.dir_stack.len() == cx.editor.dir_stack.capacity() {
        cx.editor.dir_stack.pop_back();
    }

    cx.editor
        .dir_stack
        .push_front(zmax_stdx::env::current_working_dir());

    change_current_directory(cx, args, event)
}

fn pop_directory(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }

    if let Some(dir) = cx.editor.dir_stack.pop_front() {
        apply_directory_change(cx, &dir)?;
    } else {
        cx.editor.set_error("Stack is empty");
    }

    Ok(())
}

fn show_current_directory(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }

    let cwd = zmax_stdx::env::current_working_dir();
    let message = format!("Current working directory is {}", cwd.display());

    if cwd.exists() {
        cx.editor.set_status(message);
    } else {
        cx.editor.set_error(format!("{} (deleted)", message));
    }
    Ok(())
}

