/// Per-image display transform for image-mode — rotation degrees, horizontal /
/// vertical flip, and a scale percent — so `image-rotate`/`image-flip-*` and the
/// `image-increase-size`/`image-transform-*` scale commands accumulate on the
/// current image.
#[allow(clippy::type_complexity)] // 5-tuple image-transform state holder
static IMAGE_XFORM: std::sync::Mutex<Option<(std::path::PathBuf, i32, bool, bool, u32)>> =
    std::sync::Mutex::new(None);

/// The current buffer's file if it is an image, else `None`.
pub(crate) fn current_image_path(cx: &compositor::Context) -> Option<std::path::PathBuf> {
    let path = doc!(cx.editor).path()?.to_path_buf();
    crate::commands::is_image_path(&path).then_some(path)
}

/// The stored transform for `path` (identity + 100% scale if none / a different
/// image).
pub(crate) fn image_xform_of(path: &std::path::Path) -> (i32, bool, bool, u32) {
    match &*IMAGE_XFORM.lock().unwrap() {
        Some((p, r, fh, fv, sc)) if p == path => (*r, *fh, *fv, *sc),
        _ => (0, false, false, 100),
    }
}

/// Display the current image (emacs `image-mode` / `image-toggle-display`).
fn ex_image_display(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let Some(path) = current_image_path(cx) else {
        bail!("image-mode: current buffer is not an image file");
    };
    let (r, fh, fv, sc) = image_xform_of(&path);
    crate::commands::display_images_in_terminal(cx.editor, &[path], r, fh, fv, sc);
    // Put the viewer's keymap on top, so Emacs's `i`/`s` transform prefixes reach
    // the same helpers this typable does. Without it the image renders but every
    // key falls through to the buffer underneath. `image-mode` is also the
    // toggle, so re-running it must not stack a second copy.
    let call: job::Callback = job::Callback::EditorCompositor(Box::new(
        |_editor: &mut Editor, compositor: &mut Compositor| {
            if compositor
                .find_id::<crate::ui::image::Image>("image")
                .is_none()
            {
                compositor.push(Box::new(crate::ui::image::Image::new()));
            }
        },
    ));
    cx.jobs.callback(async move { Ok(call) });
    Ok(())
}

/// Shared rotate/flip: update the transform for the current image and redisplay.
pub(crate) fn image_transform(
    cx: &mut compositor::Context,
    rotate_delta: i32,
    toggle_h: bool,
    toggle_v: bool,
) -> anyhow::Result<()> {
    let Some(path) = current_image_path(cx) else {
        bail!("image-mode: current buffer is not an image file");
    };
    let (mut r, mut fh, mut fv, sc) = image_xform_of(&path);
    r = (r + rotate_delta).rem_euclid(360);
    fh ^= toggle_h;
    fv ^= toggle_v;
    *IMAGE_XFORM.lock().unwrap() = Some((path.clone(), r, fh, fv, sc));
    crate::commands::display_images_in_terminal(cx.editor, &[path], r, fh, fv, sc);
    Ok(())
}

/// Set the current image's scale to `percent` (clamped to a sane 1..=1000 range,
/// matching emacs `image-transform-set-percent`/`-set-scale`) and redisplay.
pub(crate) fn image_set_scale(cx: &mut compositor::Context, percent: u32) -> anyhow::Result<()> {
    let Some(path) = current_image_path(cx) else {
        bail!("image-mode: current buffer is not an image file");
    };
    let (r, fh, fv, _) = image_xform_of(&path);
    let sc = percent.clamp(1, 1000);
    *IMAGE_XFORM.lock().unwrap() = Some((path.clone(), r, fh, fv, sc));
    crate::commands::display_images_in_terminal(cx.editor, &[path], r, fh, fv, sc);
    cx.editor.set_status(format!("image scale: {sc}%"));
    Ok(())
}

fn ex_image_rotate(
    cx: &mut compositor::Context,
    _a: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    image_transform(cx, 90, false, false)
}

fn ex_image_flip_h(
    cx: &mut compositor::Context,
    _a: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    image_transform(cx, 0, true, false)
}

fn ex_image_flip_v(
    cx: &mut compositor::Context,
    _a: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    image_transform(cx, 0, false, true)
}

/// emacs `image-increase-size` (`+`): scale up by 25% (image-mode-scale-factor).
fn ex_image_increase_size(
    cx: &mut compositor::Context,
    _a: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let Some(path) = current_image_path(cx) else {
        bail!("image-mode: current buffer is not an image file");
    };
    let (.., sc) = image_xform_of(&path);
    image_set_scale(cx, (sc * 5 / 4).max(sc + 1))
}

/// emacs `image-decrease-size` (`-`): scale down by 20%.
fn ex_image_decrease_size(
    cx: &mut compositor::Context,
    _a: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let Some(path) = current_image_path(cx) else {
        bail!("image-mode: current buffer is not an image file");
    };
    let (.., sc) = image_xform_of(&path);
    image_set_scale(cx, (sc * 4 / 5).max(1))
}

/// emacs `image-transform-set-percent`: set the scale to the given percentage.
fn ex_image_set_percent(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let pct: u32 = args
        .first()
        .and_then(|s| s.trim().trim_end_matches('%').parse().ok())
        .context("usage: :image-transform-set-percent <n>")?;
    image_set_scale(cx, pct)
}

/// emacs `image-transform-set-scale`: set the scale from a multiplier (e.g. 1.5).
fn ex_image_set_scale(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let factor: f64 = args
        .first()
        .and_then(|s| s.trim().parse().ok())
        .context("usage: :image-transform-set-scale <factor>")?;
    if !(factor.is_finite() && factor > 0.0) {
        bail!("image-transform-set-scale: factor must be positive");
    }
    image_set_scale(cx, (factor * 100.0).round() as u32)
}

/// emacs `image-transform-fit-to-window`: fit the image to the window. The
/// terminal viewers already fit to the terminal, so this resets the scale to
/// 100% (viewer-fitted) while keeping any rotation/flip.
fn ex_image_fit_to_window(
    cx: &mut compositor::Context,
    _a: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    image_set_scale(cx, 100)
}

/// emacs `image-transform-reset-to-original` / `-reset-to-initial`: drop all
/// transforms (rotation, flip, scale) and redisplay the original image.
/// emacs `image-transform-reset-to-original`: drop every rotate/flip/scale.
pub(crate) fn image_transform_reset_all(cx: &mut compositor::Context) -> anyhow::Result<()> {
    let Some(path) = current_image_path(cx) else {
        bail!("image-mode: current buffer is not an image file");
    };
    *IMAGE_XFORM.lock().unwrap() = Some((path.clone(), 0, false, false, 100));
    crate::commands::display_images_in_terminal(cx.editor, &[path], 0, false, false, 100);
    cx.editor.set_status("image: transforms reset");
    Ok(())
}

fn ex_image_transform_reset(
    cx: &mut compositor::Context,
    _a: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    image_transform_reset_all(cx)
}

/// Open the next/previous image file in the current file's directory (emacs
/// `image-next-file`/`image-previous-file`).
fn image_step_file(cx: &mut compositor::Context, delta: isize) -> anyhow::Result<()> {
    let Some(cur) = doc!(cx.editor).path().map(|p| p.to_path_buf()) else {
        bail!("image: no file");
    };
    let dir = cur.parent().unwrap_or_else(|| std::path::Path::new("."));
    let mut imgs: Vec<std::path::PathBuf> = std::fs::read_dir(dir)
        .map(|rd| {
            rd.filter_map(|e| e.ok().map(|e| e.path()))
                .filter(|p| crate::commands::is_image_path(p))
                .collect()
        })
        .unwrap_or_default();
    imgs.sort();
    if imgs.is_empty() {
        bail!("image: no image files in {}", dir.display());
    }
    let idx = imgs.iter().position(|p| *p == cur).unwrap_or(0);
    let next = (idx as isize + delta).rem_euclid(imgs.len() as isize) as usize;
    cx.editor.open(&imgs[next], Action::Replace)?;
    cx.editor
        .set_status(format!("image: {}", imgs[next].display()));
    Ok(())
}

fn ex_image_next_file(
    cx: &mut compositor::Context,
    _a: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    image_step_file(cx, 1)
}

fn ex_image_previous_file(
    cx: &mut compositor::Context,
    _a: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    image_step_file(cx, -1)
}

/// emacs `image-mode-copy-file-name-as-kill`: copy the image's path to the
/// clipboard register.
fn ex_image_copy_name(
    cx: &mut compositor::Context,
    _a: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let Some(path) = doc!(cx.editor)
        .path()
        .map(|p| p.to_string_lossy().into_owned())
    else {
        bail!("image: no file");
    };
    cx.editor.registers.write('+', vec![path.clone()])?;
    cx.editor.set_status(format!("copied {path}"));
    Ok(())
}

// --- emacs doc-view: render a PDF/PS/DVI/EPUB page in the terminal ------------

/// doc-view per-document state: `(path, current page, render dpi)`.
static DOCVIEW: std::sync::Mutex<Option<(std::path::PathBuf, u32, u32)>> =
    std::sync::Mutex::new(None);
/// Optional crop slice `(x, y, w, h)` in pixels for the current doc-view page
/// (emacs `doc-view-set-slice`/`-reset-slice`).
#[allow(clippy::type_complexity)] // optional crop-slice state holder
static DOCVIEW_SLICE: std::sync::Mutex<Option<(std::path::PathBuf, (u32, u32, u32, u32))>> =
    std::sync::Mutex::new(None);
const DOCVIEW_DEFAULT_DPI: u32 = 100;

/// The stored crop slice for `path`, if any.
fn docview_slice_of(path: &std::path::Path) -> Option<(u32, u32, u32, u32)> {
    match &*DOCVIEW_SLICE.lock().unwrap() {
        Some((p, s)) if p == path => Some(*s),
        _ => None,
    }
}

/// The current buffer's file if it is a doc-view document, else `None`.
fn current_doc_path(cx: &compositor::Context) -> Option<std::path::PathBuf> {
    let path = doc!(cx.editor).path()?.to_path_buf();
    crate::commands::is_docview_path(&path).then_some(path)
}

/// The stored `(page, dpi)` for `path` (defaults to page 1 at the default dpi).
fn docview_state(path: &std::path::Path) -> (u32, u32) {
    match &*DOCVIEW.lock().unwrap() {
        Some((p, page, dpi)) if p == path => (*page, *dpi),
        _ => (1, DOCVIEW_DEFAULT_DPI),
    }
}

/// The document's page count via `pdfinfo`, if available (PDF only).
fn docview_page_count(path: &std::path::Path) -> Option<u32> {
    let out = std::process::Command::new("pdfinfo")
        .arg(path)
        .output()
        .ok()?;
    String::from_utf8_lossy(&out.stdout)
        .lines()
        .find_map(|l| l.strip_prefix("Pages:"))
        .and_then(|n| n.trim().parse().ok())
}

/// Store `(page, dpi)` for `path` and queue the render+display.
fn docview_show(cx: &mut compositor::Context, path: &std::path::Path, page: u32, dpi: u32) {
    let page = page.max(1);
    *DOCVIEW.lock().unwrap() = Some((path.to_path_buf(), page, dpi));
    let slice = docview_slice_of(path);
    crate::commands::display_doc_page_in_terminal(cx.editor, path, page, dpi, slice);
    cx.editor.set_status(format!("doc-view: page {page}"));
}

/// emacs `doc-view-mode`/`-toggle-display`: render the current page.
fn ex_docview_mode(
    cx: &mut compositor::Context,
    _a: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let Some(path) = current_doc_path(cx) else {
        bail!("doc-view: current buffer is not a document (PDF/PS/DVI/EPUB)");
    };
    let (page, dpi) = docview_state(&path);
    docview_show(cx, &path, page, dpi);
    // Put the viewer's keymap on top, so Emacs's DocView keys (n/p/SPC/DEL/+/-/
    // M-</M->/C-x [/C-x ]) reach the same commands this typable does. Without it
    // the page renders but every key falls through to the buffer underneath.
    // `doc-view-mode` is also the toggle, so re-running it must not stack a
    // second copy of the overlay.
    let call: job::Callback = job::Callback::EditorCompositor(Box::new(
        |_editor: &mut Editor, compositor: &mut Compositor| {
            if compositor
                .find_id::<crate::ui::docview::DocView>("docview")
                .is_none()
            {
                compositor.push(Box::new(crate::ui::docview::DocView::new()));
            }
        },
    ));
    cx.jobs.callback(async move { Ok(call) });
    Ok(())
}

/// Shared page-step for next/previous/first/last/goto.
pub(crate) fn docview_step(cx: &mut compositor::Context, to: DocPage) -> anyhow::Result<()> {
    let Some(path) = current_doc_path(cx) else {
        bail!("doc-view: current buffer is not a document");
    };
    let (page, dpi) = docview_state(&path);
    let count = docview_page_count(&path);
    let target = match to {
        DocPage::Next => page + 1,
        DocPage::Prev => page.saturating_sub(1).max(1),
        DocPage::First => 1,
        DocPage::Last => count.unwrap_or(page),
        DocPage::Goto(n) => n,
    };
    let target = match count {
        Some(c) => target.clamp(1, c.max(1)),
        None => target.max(1),
    };
    docview_show(cx, &path, target, dpi);
    Ok(())
}

pub(crate) enum DocPage {
    Next,
    Prev,
    First,
    Last,
    Goto(u32),
}

fn ex_docview_next(cx: &mut compositor::Context, _a: Args, e: PromptEvent) -> anyhow::Result<()> {
    if e != PromptEvent::Validate {
        return Ok(());
    }
    docview_step(cx, DocPage::Next)
}
fn ex_docview_prev(cx: &mut compositor::Context, _a: Args, e: PromptEvent) -> anyhow::Result<()> {
    if e != PromptEvent::Validate {
        return Ok(());
    }
    docview_step(cx, DocPage::Prev)
}
fn ex_docview_first(cx: &mut compositor::Context, _a: Args, e: PromptEvent) -> anyhow::Result<()> {
    if e != PromptEvent::Validate {
        return Ok(());
    }
    docview_step(cx, DocPage::First)
}
fn ex_docview_last(cx: &mut compositor::Context, _a: Args, e: PromptEvent) -> anyhow::Result<()> {
    if e != PromptEvent::Validate {
        return Ok(());
    }
    docview_step(cx, DocPage::Last)
}
fn ex_docview_goto(cx: &mut compositor::Context, args: Args, e: PromptEvent) -> anyhow::Result<()> {
    if e != PromptEvent::Validate {
        return Ok(());
    }
    let n: u32 = args
        .first()
        .and_then(|s| s.parse().ok())
        .ok_or_else(|| anyhow!("doc-view-goto-page: needs a page number"))?;
    docview_step(cx, DocPage::Goto(n))
}

/// emacs `doc-view-enlarge`/`-shrink`: change the render resolution and redisplay.
pub(crate) fn docview_zoom(cx: &mut compositor::Context, delta: i32) -> anyhow::Result<()> {
    let Some(path) = current_doc_path(cx) else {
        bail!("doc-view: current buffer is not a document");
    };
    let (page, dpi) = docview_state(&path);
    let new_dpi = (dpi as i32 + delta).clamp(25, 600) as u32;
    docview_show(cx, &path, page, new_dpi);
    Ok(())
}
fn ex_docview_enlarge(
    cx: &mut compositor::Context,
    _a: Args,
    e: PromptEvent,
) -> anyhow::Result<()> {
    if e != PromptEvent::Validate {
        return Ok(());
    }
    docview_zoom(cx, 25)
}
fn ex_docview_shrink(cx: &mut compositor::Context, _a: Args, e: PromptEvent) -> anyhow::Result<()> {
    if e != PromptEvent::Validate {
        return Ok(());
    }
    docview_zoom(cx, -25)
}

/// emacs `diff-buffer-with-file`: show the differences between the current
/// buffer's (possibly unsaved) contents and the file it visits on disk. Writes
/// the buffer to a temp file and runs the external `diff -u` (emacs
/// `diff-command`), showing the unified diff in a scratch buffer.
fn ex_diff_buffer_with_file(
    cx: &mut compositor::Context,
    _a: Args,
    e: PromptEvent,
) -> anyhow::Result<()> {
    if e != PromptEvent::Validate {
        return Ok(());
    }
    let (path, text) = {
        let doc = doc!(cx.editor);
        let Some(path) = doc.path().map(|p| p.to_path_buf()) else {
            bail!("diff-buffer-with-file: buffer is not visiting a file");
        };
        (path, doc.text().to_string())
    };
    if !path.exists() {
        bail!(
            "diff-buffer-with-file: {} does not exist on disk",
            path.display()
        );
    }
    // A unique temp path (pid + a monotonic counter — no clock/rng needed).
    static SEQ: std::sync::atomic::AtomicU64 = std::sync::atomic::AtomicU64::new(0);
    let n = SEQ.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
    let tmp = std::env::temp_dir().join(format!("zmax-diff-{}-{n}.tmp", std::process::id()));
    if let Err(err) = std::fs::write(&tmp, text.as_bytes()) {
        bail!("diff-buffer-with-file: cannot write temp file: {err}");
    }
    let out = std::process::Command::new("diff")
        .arg("-u")
        .arg(&path)
        .arg(&tmp)
        .output();
    let _ = std::fs::remove_file(&tmp);
    match out {
        // diff exits 0 (identical) or 1 (differences); >1 is an error.
        Ok(o) if o.status.code() == Some(0) => {
            cx.editor.set_status(format!(
                "diff-buffer-with-file: no differences ({})",
                path.display()
            ));
        }
        Ok(o) if o.status.code() == Some(1) => {
            super::show_text_in_scratch(cx.editor, &String::from_utf8_lossy(&o.stdout));
        }
        Ok(o) => bail!("diff: {}", String::from_utf8_lossy(&o.stderr).trim()),
        Err(err) => bail!("diff: {err} (install diffutils)"),
    }
    Ok(())
}

/// emacs `doc-view-open-text`: extract the document text (`pdftotext`) to a
/// scratch buffer.
fn ex_docview_open_text(
    cx: &mut compositor::Context,
    _a: Args,
    e: PromptEvent,
) -> anyhow::Result<()> {
    if e != PromptEvent::Validate {
        return Ok(());
    }
    let Some(path) = current_doc_path(cx) else {
        bail!("doc-view: current buffer is not a document");
    };
    let out = std::process::Command::new("pdftotext")
        .arg(&path)
        .arg("-")
        .output();
    match out {
        Ok(o) if o.status.success() => {
            super::show_text_in_scratch(cx.editor, &String::from_utf8_lossy(&o.stdout));
        }
        Ok(o) => bail!("pdftotext: {}", String::from_utf8_lossy(&o.stderr).trim()),
        Err(e) => bail!("pdftotext: {e} (install poppler)"),
    }
    Ok(())
}

/// emacs `doc-view-search`: grep the extracted text for a pattern, show hits.
fn ex_docview_search(
    cx: &mut compositor::Context,
    args: Args,
    e: PromptEvent,
) -> anyhow::Result<()> {
    if e != PromptEvent::Validate {
        return Ok(());
    }
    let Some(path) = current_doc_path(cx) else {
        bail!("doc-view: current buffer is not a document");
    };
    let pattern = args.join(" ");
    if pattern.trim().is_empty() {
        bail!("doc-view-search: needs a pattern");
    }
    let out = std::process::Command::new("pdftotext")
        .arg(&path)
        .arg("-")
        .output();
    let text = match out {
        Ok(o) if o.status.success() => String::from_utf8_lossy(&o.stdout).into_owned(),
        Ok(o) => bail!("pdftotext: {}", String::from_utf8_lossy(&o.stderr).trim()),
        Err(e) => bail!("pdftotext: {e} (install poppler)"),
    };
    let hits: String = text
        .lines()
        .enumerate()
        .filter(|(_, l)| l.to_lowercase().contains(&pattern.to_lowercase()))
        .map(|(i, l)| format!("{}: {l}", i + 1))
        .collect::<Vec<_>>()
        .join("\n");
    let content = if hits.is_empty() {
        format!("doc-view-search '{pattern}': no matches\n")
    } else {
        format!("doc-view-search '{pattern}':\n{hits}\n")
    };
    super::show_text_in_scratch(cx.editor, &content);
    Ok(())
}

/// emacs `doc-view-clear-cache` / `doc-view-kill-proc`: forget the doc-view state
/// (zmax renders on demand, so there is no persistent process/cache to reap).
fn ex_docview_clear_cache(
    cx: &mut compositor::Context,
    _a: Args,
    e: PromptEvent,
) -> anyhow::Result<()> {
    if e != PromptEvent::Validate {
        return Ok(());
    }
    *DOCVIEW.lock().unwrap() = None;
    cx.editor.set_status("doc-view: cache cleared");
    Ok(())
}

/// emacs `doc-view-set-slice`: crop the displayed page to `X Y WIDTH HEIGHT`
/// (pixels) and redisplay.
fn ex_docview_set_slice(
    cx: &mut compositor::Context,
    args: Args,
    e: PromptEvent,
) -> anyhow::Result<()> {
    if e != PromptEvent::Validate {
        return Ok(());
    }
    let Some(path) = current_doc_path(cx) else {
        bail!("doc-view: current buffer is not a document");
    };
    let nums: Vec<u32> = args.iter().filter_map(|s| s.trim().parse().ok()).collect();
    let [x, y, w, h] = nums.as_slice() else {
        bail!("usage: :doc-view-set-slice X Y WIDTH HEIGHT (pixels)");
    };
    if *w == 0 || *h == 0 {
        bail!("doc-view-set-slice: width and height must be positive");
    }
    *DOCVIEW_SLICE.lock().unwrap() = Some((path.clone(), (*x, *y, *w, *h)));
    let (page, dpi) = docview_state(&path);
    docview_show(cx, &path, page, dpi);
    cx.editor
        .set_status(format!("doc-view slice: {w}x{h}+{x}+{y}"));
    Ok(())
}

/// emacs `doc-view-reset-slice`: drop the crop slice and redisplay the full page.
fn ex_docview_reset_slice(
    cx: &mut compositor::Context,
    _a: Args,
    e: PromptEvent,
) -> anyhow::Result<()> {
    if e != PromptEvent::Validate {
        return Ok(());
    }
    let Some(path) = current_doc_path(cx) else {
        bail!("doc-view: current buffer is not a document");
    };
    *DOCVIEW_SLICE.lock().unwrap() = None;
    let (page, dpi) = docview_state(&path);
    docview_show(cx, &path, page, dpi);
    cx.editor.set_status("doc-view: slice reset");
    Ok(())
}

/// Shared launcher for the Ex line-input commands `:append` / `:insert` /
/// `:change`. Computes the target span for the current line and opens the
/// [`crate::ui::ExInput`] mode, which collects lines until a lone `.`.
///
/// `kind`: "append" inserts after the current line, "insert" before it, "change"
/// replaces it. No explicit `{range}` is parsed — these operate on the current
/// line (the common no-range form); the mode inserts everything as one undo step.
fn ex_line_input(
    cx: &mut compositor::Context,
    event: PromptEvent,
    kind: &'static str,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let (view_id, doc_id, from, to, lead_newline) = {
        let (view, doc) = current!(cx.editor);
        let text = doc.text();
        let slice = text.slice(..);
        let cursor = doc.selection(view.id).primary().cursor(slice);
        let line = slice.char_to_line(cursor);
        let line_start = slice.line_to_char(line);
        let len = slice.len_chars();
        // Start of the next line, or end-of-buffer for the last line.
        let next_line_start = slice.line_to_char((line + 1).min(slice.len_lines()));
        let ends_with_nl = len == 0 || slice.char(len - 1) == '\n';
        let (from, to, lead_newline) = match kind {
            // After the current line. When appending past a final line with no
            // trailing newline, the block must start on its own line.
            "append" => {
                let at = next_line_start;
                (at, at, at == len && !ends_with_nl)
            }
            // Before the current line.
            "insert" => (line_start, line_start, false),
            // Replace the current line (its text and trailing newline).
            "change" => (line_start, next_line_start, false),
            _ => (line_start, line_start, false),
        };
        (view.id, doc.id(), from, to, lead_newline)
    };
    let comp = crate::ui::ExInput::new(doc_id, view_id, from, to, lead_newline, kind);
    let callback = async move {
        let call: job::Callback = job::Callback::EditorCompositor(Box::new(
            move |_editor: &mut Editor, compositor: &mut Compositor| {
                compositor.push(Box::new(comp));
            },
        ));
        Ok(call)
    };
    cx.jobs.callback(callback);
    Ok(())
}

/// vim `:append` — after the current line, read typed lines until a lone `.`.
fn ex_append(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    ex_line_input(cx, event, "append")
}

/// vim `:insert` — before the current line, read typed lines until a lone `.`.
fn ex_insert(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    ex_line_input(cx, event, "insert")
}

/// vim `:change` — replace the current line with typed lines (ended by a lone `.`).
fn ex_change(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    ex_line_input(cx, event, "change")
}

/// vim `:undojoin` — join the next change with the previous undo block, so a
/// single undo reverts both. Any in-progress change is committed first (making the
/// completed block the join target, as vim does), then the join is armed for the
/// next commit.
fn ex_undojoin(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let (view, doc) = current!(cx.editor);
    doc.append_changes_to_history(view);
    doc.set_undojoin_pending();
    Ok(())
}

/// Split vim `:sign` arguments into bare positionals (e.g. the id in `:sign place
/// 2 …`) and `key=value` pairs (`line=`, `name=`, `file=`, `group=`, `priority=`,
/// `text=`, `texthl=`).
fn parse_sign_args<'a>(
    toks: &[&'a str],
) -> (Vec<&'a str>, std::collections::HashMap<&'a str, &'a str>) {
    let mut positional = Vec::new();
    let mut kv = std::collections::HashMap::new();
    for &t in toks {
        match t.split_once('=') {
            Some((k, v)) => {
                kv.insert(k, v);
            }
            None => positional.push(t),
        }
    }
    (positional, kv)
}

/// Resolve the `file=` argument (or the current buffer) to a path for `:sign`
/// place/unplace/jump.
fn sign_target_path(
    cx: &compositor::Context,
    kv: &std::collections::HashMap<&str, &str>,
) -> anyhow::Result<std::path::PathBuf> {
    match kv.get("file") {
        Some(f) => Ok(zmax_stdx::path::expand_tilde(Path::new(f)).into_owned()),
        None => doc!(cx.editor)
            .path()
            .map(|p| p.to_path_buf())
            .ok_or_else(|| anyhow!("sign: no file (open a buffer or pass file=)")),
    }
}

/// vim `:sign {define|undefine|place|unplace|list|jump} …` — user-defined gutter
/// markers. Definitions name a glyph (`text=`) + highlight (`texthl=`);
/// placements put a named sign on a 1-based line of a file (default: the current
/// buffer). `:sign unplace *` clears all placements; `:sign jump {id} file={f}`
/// opens the file and moves to the sign.
fn ex_sign(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    use zmax_view::signs::{self, PlacedSign, SignDef, DEFAULT_PRIORITY};

    let toks: Vec<&str> = args
        .iter()
        .map(|s| s.as_ref())
        .filter(|s: &&str| !s.is_empty())
        .collect();
    let Some((&sub, rest)) = toks.split_first() else {
        bail!("usage: :sign define|undefine|place|unplace|list|jump …");
    };
    let (positional, kv) = parse_sign_args(rest);

    match sub {
        "define" => {
            let name = positional
                .first()
                .copied()
                .ok_or_else(|| anyhow!("usage: :sign define {{name}} text=.. [texthl=..]"))?;
            let def = SignDef {
                text: kv.get("text").copied().unwrap_or_default().to_string(),
                texthl: kv.get("texthl").map(|s| s.to_string()),
            };
            signs::define(name, def);
            cx.editor.set_status(format!("defined sign {name}"));
        }
        "undefine" => {
            let name = positional
                .first()
                .copied()
                .ok_or_else(|| anyhow!("usage: :sign undefine {{name}}"))?;
            if signs::undefine(name) {
                cx.editor.set_status(format!("undefined sign {name}"));
            } else {
                bail!("sign: unknown sign {name}");
            }
        }
        "place" => {
            let id = positional
                .first()
                .and_then(|s| s.parse::<i64>().ok())
                .ok_or_else(|| {
                    anyhow!("usage: :sign place {{id}} line={{n}} name={{name}} [file=]")
                })?;
            let name = kv
                .get("name")
                .copied()
                .ok_or_else(|| anyhow!("sign place: name= is required"))?;
            let line = kv
                .get("line")
                .and_then(|s| s.parse::<usize>().ok())
                .ok_or_else(|| anyhow!("sign place: line= is required"))?;
            let path = sign_target_path(cx, &kv)?;
            let sign = PlacedSign {
                id,
                group: kv.get("group").copied().unwrap_or_default().to_string(),
                // vim lines are 1-based; store 0-based.
                line: line.saturating_sub(1),
                name: name.to_string(),
                priority: kv
                    .get("priority")
                    .and_then(|s| s.parse::<i64>().ok())
                    .unwrap_or(DEFAULT_PRIORITY),
            };
            signs::place(&path, sign).map_err(|e| anyhow!("sign place: {e}"))?;
            cx.editor
                .set_status(format!("placed sign {id} on line {line}"));
        }
        "unplace" => {
            if positional.first() == Some(&"*") {
                let n = signs::unplace_all();
                cx.editor.set_status(format!("unplaced {n} sign(s)"));
            } else {
                let id = positional.first().and_then(|s| s.parse::<i64>().ok());
                let path = sign_target_path(cx, &kv)?;
                let n = signs::unplace(&path, id, kv.get("group").copied());
                cx.editor.set_status(format!("unplaced {n} sign(s)"));
            }
        }
        "list" => {
            let defs = signs::definitions();
            let mut out = String::from("--- Defined signs ---\n");
            for (name, d) in &defs {
                out.push_str(&format!("sign {name} text={}", d.text));
                if let Some(hl) = &d.texthl {
                    out.push_str(&format!(" texthl={hl}"));
                }
                out.push('\n');
            }
            if defs.is_empty() {
                out.push_str("(no signs defined)\n");
            }
            super::show_text_in_scratch(cx.editor, &out);
        }
        "jump" => {
            let id = positional
                .first()
                .and_then(|s| s.parse::<i64>().ok())
                .ok_or_else(|| anyhow!("usage: :sign jump {{id}} [group=] [file=]"))?;
            let path = sign_target_path(cx, &kv)?;
            let Some(sign) = signs::find(&path, id, kv.get("group").copied()) else {
                bail!("sign: id {id} not found");
            };
            // Open the file into the current window (a no-op if already current),
            // then move to the sign's line.
            cx.editor.open(&path, Action::Replace)?;
            goto_line_without_jumplist(cx.editor, NonZeroUsize::new(sign.line + 1), Movement::Move);
            let scrolloff = cx.editor.config().scrolloff;
            let (view, doc) = current!(cx.editor);
            view.ensure_cursor_in_view(doc, scrolloff);
        }
        _ => bail!("sign: unknown subcommand {sub}"),
    }
    Ok(())
}

/// vim `:doautocmd [group] {event} [fname]` — fire the autocommands registered
/// for `{event}` on the current buffer. zmax has no autocmd groups, so a
/// leading group token is ignored; the last non-flag token is taken as the event.
fn ex_doautocmd(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    // `:doautocmd User Foo` (group + event) → fire the event token; a bare
    // `:doautocmd BufWritePost` fires that. Ignore a trailing {fname}.
    let toks: Vec<&str> = args
        .iter()
        .map(|s| s.trim())
        .filter(|s| !s.is_empty())
        .collect();
    let Some(evt) = toks.first().copied() else {
        bail!("usage: :doautocmd {{event}}");
    };
    // If two tokens and the first looks like a group (User/augroup-style), prefer
    // the second as the event; otherwise the first token is the event.
    let evt = if toks.len() >= 2 && !evt.contains(|c: char| c.is_ascii_uppercase()) {
        toks[1]
    } else {
        evt
    };
    fire_autocmd(cx, evt);
    cx.editor.set_status(format!("autocmd {evt} fired"));
    Ok(())
}

/// vim `:doautoall {event}` — like `:doautocmd`, but fire the event's autocommands
/// for every loaded buffer (not just the current one). Switches to each document,
/// fires, then restores the original.
fn ex_doautoall(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let toks: Vec<&str> = args
        .iter()
        .map(|s| s.trim())
        .filter(|s| !s.is_empty())
        .collect();
    let Some(first) = toks.first().copied() else {
        bail!("usage: :doautoall {{event}}");
    };
    // `:doautoall User Foo` (group + event) → prefer the event token, matching
    // `:doautocmd`.
    let evt = if toks.len() >= 2 && !first.contains(|c: char| c.is_ascii_uppercase()) {
        toks[1]
    } else {
        first
    }
    .to_string();
    let ids: Vec<_> = cx.editor.documents().map(|d| d.id()).collect();
    let original = doc!(cx.editor).id();
    for id in &ids {
        cx.editor.switch(*id, Action::Replace);
        fire_autocmd(cx, &evt);
    }
    cx.editor.switch(original, Action::Replace);
    cx.editor
        .set_status(format!("autocmd {evt} fired for {} buffer(s)", ids.len()));
    Ok(())
}

/// vim `:drop {file}` — if a buffer already edits `{file}`, jump to it; otherwise
/// edit `{file}` in the current window.
fn ex_drop(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let name = args.join(" ");
    let name = name.trim();
    if name.is_empty() {
        bail!("usage: :drop {{file}}");
    }
    let path = zmax_stdx::path::expand_tilde(std::path::Path::new(name)).into_owned();
    let existing = cx.editor.documents().find_map(|doc| {
        let p = Some(path.as_path());
        if doc.path() == p || doc.relative_path() == Some(std::path::Path::new(name)) {
            Some(doc.id())
        } else {
            None
        }
    });
    match existing {
        Some(id) => {
            cx.editor.switch(id, Action::Replace);
            Ok(())
        }
        None => {
            cx.editor.open(&path, Action::Replace)?;
            Ok(())
        }
    }
}

/// vim `:let {name} = {expr}` — evaluate the assignment in the embedded vimlrs
/// interpreter, so the variable persists (readable by `:echo`, sourced plugins,
/// `&opt` bridges, etc.). Bare `:let` lists variables (vimlrs handles it).
fn vim_let(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let tail = args.join(" ");
    // vim `:lockvar`: a locked variable cannot be assigned to.
    if let Some(name) = first_locked(&let_targets(&tail)) {
        bail!("E741: Value is locked: {name}");
    }
    let src = format!("let {}", args.join(" "));
    match crate::commands::scripting::eval_viml(cx, src.trim_end()) {
        Ok(out) => {
            let out = out.trim();
            if !out.is_empty() {
                cx.editor.set_status(out.to_string());
            }
            Ok(())
        }
        Err(e) => Err(anyhow!("{e}")),
    }
}

/// Queue an external-`fzf` request (fzf.vim-style). The terminal layer hands the
/// TTY to `fzf` with `candidates` on stdin, then runs `sink` (a zmax `:`
/// command with `{}` = the picked line). Empty `candidates` lets `fzf` use its
/// own `$FZF_DEFAULT_COMMAND` (file walk).
/// Candidate-sourced fzf request (candidates piped on stdin).
fn queue_fzf(
    cx: &mut compositor::Context,
    prompt: &str,
    sink: &str,
    candidates: Vec<String>,
    options: Vec<String>,
    preview: bool,
) {
    cx.editor.pending_fzf = Some(zmax_view::editor::FzfRequest {
        candidates,
        prompt: prompt.to_string(),
        sink: sink.to_string(),
        options,
        preview,
        command: None,
    });
}

/// Command-sourced fzf request: fzf streams `command`'s output (fzf.vim `source`).
fn queue_fzf_cmd(
    cx: &mut compositor::Context,
    prompt: &str,
    sink: &str,
    command: String,
    options: Vec<String>,
    preview: bool,
) {
    cx.editor.pending_fzf = Some(zmax_view::editor::FzfRequest {
        candidates: Vec::new(),
        prompt: prompt.to_string(),
        sink: sink.to_string(),
        options,
        preview,
        command: Some(command),
    });
}

/// Sink for grep/jumplist picks (`file:line:col:text`) — open the file at the
/// line/col, dropping the trailing text.
fn fzf_goto(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let line = args.join(" ");
    let mut parts = line.splitn(4, ':');
    let file = parts.next().unwrap_or("").trim();
    if file.is_empty() {
        return Ok(());
    }
    fn numeric(s: Option<&str>) -> Option<&str> {
        s.filter(|t| !t.is_empty() && t.bytes().all(|b| b.is_ascii_digit()))
    }
    let mut target = file.to_string();
    if let Some(l) = numeric(parts.next()) {
        target.push(':');
        target.push_str(l);
        if let Some(c) = numeric(parts.next()) {
            target.push(':');
            target.push_str(c);
        }
    }
    run_command_line(cx, &format!("open {target}"));
    Ok(())
}

/// Sink for current-buffer line picks (`N: text`) — jump to line N.
fn fzf_line(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let line = args.join(" ");
    let num: String = line.chars().take_while(|c| c.is_ascii_digit()).collect();
    if !num.is_empty() {
        run_command_line(cx, &format!("goto {num}"));
    }
    Ok(())
}

/// fzf.vim `:Files` — fuzzy-find files (fzf walks the tree via its default
/// command) and open the pick, with a preview pane.
fn fzf_files(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event == PromptEvent::Validate {
        queue_fzf(cx, "Files", "open {}", Vec::new(), Vec::new(), true);
    }
    Ok(())
}

/// fzf.vim `:GFiles [?]` — fuzzy-find git files and open the pick. `:GFiles?`
/// (the `?` arg) picks from git *status* (changed files) instead of tracked files.
fn fzf_gfiles(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event == PromptEvent::Validate {
        let cmd = if args.join(" ").trim() == "?" {
            // `cut -c4-` strips the `XY ` porcelain prefix, keeping paths with spaces.
            "git status --porcelain | cut -c4-".to_string()
        } else {
            "git ls-files".to_string()
        };
        queue_fzf_cmd(cx, "GFiles", "open {}", cmd, Vec::new(), true);
    }
    Ok(())
}

/// fzf.vim `:Rg`/`:Ag` `[pattern]` — ripgrep across the tree, open the pick at its
/// line. With no pattern, matches every line (fuzzy-filter live in fzf).
fn fzf_rg(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let pat = args.join(" ");
    let pat = pat.trim();
    let needle = if pat.is_empty() {
        ".".to_string()
    } else {
        pat.replace('\'', "'\\''")
    };
    let cmd =
        format!("rg --column --line-number --no-heading --color=never --smart-case -- '{needle}'");
    queue_fzf_cmd(
        cx,
        "Rg",
        "fzf-goto {}",
        cmd,
        vec!["--no-sort".into()],
        false,
    );
    Ok(())
}

/// `:Todo` — JetBrains-style TODO tool window: ripgrep the tree for TODO / FIXME
/// / HACK / XXX markers (+ Rust `todo!`/`unimplemented!`) and open the pick.
fn fzf_todo(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event == PromptEvent::Validate {
        let cmd = "rg --column --line-number --no-heading --color=never -i \
                   -e '\\b(TODO|FIXME|HACK|XXX)\\b' -e '(todo|unimplemented)!' 2>/dev/null"
            .to_string();
        queue_fzf_cmd(
            cx,
            "Todo",
            "fzf-goto {}",
            cmd,
            vec!["--no-sort".into()],
            false,
        );
    }
    Ok(())
}

/// fzf.vim `:Locate {pattern}` — locate files and open the pick.
fn fzf_locate(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let pat = args.join(" ");
    let pat = pat.trim();
    if pat.is_empty() {
        cx.editor.set_error(":Locate requires a pattern");
        return Ok(());
    }
    let cmd = format!("locate '{}'", pat.replace('\'', "'\\''"));
    queue_fzf_cmd(cx, "Locate", "open {}", cmd, Vec::new(), true);
    Ok(())
}

/// fzf.vim `:BLines` — fuzzy-search lines of the current buffer, jump to the pick.
fn fzf_blines(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let cands: Vec<String> = {
        let (_, doc) = current_ref!(cx.editor);
        let text = doc.text();
        (0..text.len_lines())
            .map(|i| format!("{}: {}", i + 1, text.line(i).to_string().trim_end()))
            .collect()
    };
    queue_fzf(
        cx,
        "BLines",
        "fzf-line {}",
        cands,
        vec!["--no-sort".into()],
        false,
    );
    Ok(())
}

/// fzf.vim `:Colors` — fuzzy-pick a colorscheme, applied live.
fn fzf_colors(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event == PromptEvent::Validate {
        queue_fzf(
            cx,
            "Colors",
            "theme {}",
            all_theme_names(),
            vec!["+m".into()],
            false,
        );
    }
    Ok(())
}

/// fzf.vim `:Buffers` — fuzzy-pick an open buffer by path and switch to it.
fn fzf_buffers(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event == PromptEvent::Validate {
        let cands: Vec<String> = cx
            .editor
            .documents()
            .filter_map(|d| d.path().map(|p| p.to_string_lossy().into_owned()))
            .collect();
        queue_fzf(cx, "Buffers", "buffer {}", cands, Vec::new(), true);
    }
    Ok(())
}

/// fzf.vim `:Commands` — fuzzy-pick a `:` command and run it.
fn fzf_commands(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event == PromptEvent::Validate {
        let mut cands: Vec<String> = TYPABLE_COMMAND_LIST
            .iter()
            .map(|c| c.name.to_string())
            .collect();
        cands.sort();
        queue_fzf(cx, "Commands", "{}", cands, vec!["+m".into()], false);
    }
    Ok(())
}

/// Read all values of a register as candidate lines.
fn register_lines(cx: &compositor::Context, reg: char) -> Vec<String> {
    cx.editor
        .registers
        .read(reg, cx.editor)
        .map(|vals| vals.map(|v| v.to_string()).collect())
        .unwrap_or_default()
}

/// fzf.vim `:History` — fuzzy-pick a recently opened file and open it.
fn fzf_history(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event == PromptEvent::Validate {
        let cands: Vec<String> = crate::recent_files::load_frecent()
            .iter()
            .map(|p| p.to_string_lossy().into_owned())
            .collect();
        queue_fzf(cx, "History", "open {}", cands, Vec::new(), true);
    }
    Ok(())
}

/// fzf.vim `:History:` — fuzzy-pick a past `:` command line and run it.
fn fzf_cmd_history(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event == PromptEvent::Validate {
        let cands = register_lines(cx, ':');
        queue_fzf(cx, "History:", "{}", cands, vec!["+m".into()], false);
    }
    Ok(())
}

/// fzf.vim `:History/` — fuzzy-pick a past search and re-run it.
fn fzf_search_history(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event == PromptEvent::Validate {
        let cands = register_lines(cx, '/');
        queue_fzf(cx, "History/", "search {}", cands, vec!["+m".into()], false);
    }
    Ok(())
}

/// fzf.vim `:Lines` — fuzzy-search lines across ALL open buffers, open the pick.
fn fzf_lines(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let mut cands = Vec::new();
    for doc in cx.editor.documents() {
        let Some(path) = doc.path().map(|p| p.to_string_lossy().into_owned()) else {
            continue;
        };
        let text = doc.text();
        for i in 0..text.len_lines() {
            let l = text.line(i).to_string();
            let l = l.trim_end();
            if !l.is_empty() {
                cands.push(format!("{path}:{}:1:{l}", i + 1));
            }
        }
    }
    queue_fzf(
        cx,
        "Lines",
        "fzf-goto {}",
        cands,
        vec!["--no-sort".into()],
        false,
    );
    Ok(())
}

/// Sink for `:Commits`/`:BCommits` picks (`<sha> subject`) — show the commit.
fn fzf_git_show(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let line = args.join(" ");
    let sha = line.split_whitespace().next().unwrap_or("");
    if sha.is_empty() {
        return Ok(());
    }
    match std::process::Command::new("git")
        .args(["show", "--stat", "-p", sha])
        .output()
    {
        Ok(o) if o.status.success() => {
            super::show_text_in_scratch(cx.editor, &String::from_utf8_lossy(&o.stdout));
        }
        _ => cx.editor.set_error(format!("git show {sha} failed")),
    }
    Ok(())
}

/// fzf.vim `:Commits` — fuzzy-pick a repo commit and show it.
fn fzf_commits(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event == PromptEvent::Validate {
        queue_fzf_cmd(
            cx,
            "Commits",
            "fzf-git-show {}",
            "git log --oneline --color=never".into(),
            vec!["--no-sort".into()],
            false,
        );
    }
    Ok(())
}

/// fzf.vim `:BCommits` — fuzzy-pick a commit touching the current file and show it.
fn fzf_bcommits(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let path = {
        let (_, doc) = current_ref!(cx.editor);
        doc.path().map(|p| p.to_string_lossy().into_owned())
    };
    let Some(path) = path else {
        cx.editor.set_error(":BCommits needs a file");
        return Ok(());
    };
    let cmd = format!(
        "git log --oneline --color=never -- '{}'",
        path.replace('\'', "'\\''")
    );
    queue_fzf_cmd(
        cx,
        "BCommits",
        "fzf-git-show {}",
        cmd,
        vec!["--no-sort".into()],
        false,
    );
    Ok(())
}

/// fzf.vim `:Filetypes` — fuzzy-pick a language and set the buffer's filetype.
fn fzf_filetypes(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event == PromptEvent::Validate {
        let loader: &zmax_core::syntax::Loader = &cx.editor.syn_loader.load();
        let mut cands: Vec<String> = loader
            .language_configs()
            .map(|c| c.language_id.clone())
            .collect();
        cands.sort();
        cands.dedup();
        queue_fzf(
            cx,
            "Filetypes",
            "set-language {}",
            cands,
            vec!["+m".into()],
            false,
        );
    }
    Ok(())
}

/// fzf.vim `:Jumps` — fuzzy-pick an entry from the jumplist and open it.
fn fzf_jumps(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let entries: Vec<(zmax_view::DocumentId, usize)> = {
        let (view, _) = current_ref!(cx.editor);
        view.jumps
            .iter()
            .map(|(id, sel)| (*id, sel.primary().head))
            .collect()
    };
    let mut cands = Vec::new();
    for (id, pos) in entries {
        let Some(doc) = cx.editor.document(id) else {
            continue;
        };
        let Some(path) = doc.path().map(|p| p.to_string_lossy().into_owned()) else {
            continue;
        };
        let text = doc.text();
        let p = pos.min(text.len_chars());
        let line = text.char_to_line(p) + 1;
        let ltext = text.line(line - 1).to_string();
        cands.push(format!("{path}:{line}:1: {}", ltext.trim_end()));
    }
    queue_fzf(
        cx,
        "Jumps",
        "fzf-goto {}",
        cands,
        vec!["--no-sort".into()],
        false,
    );
    Ok(())
}

/// `:LocalHistory` — JetBrains Local History: fuzzy-pick a saved snapshot of the
/// current file (newest first) and open that past version.
fn local_history(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let path = {
        let (_, doc) = current_ref!(cx.editor);
        doc.path().map(|p| p.to_path_buf())
    };
    let Some(path) = path else {
        cx.editor.set_error(":LocalHistory requires a file");
        return Ok(());
    };
    let snaps = crate::local_history::snapshots(&path);
    if snaps.is_empty() {
        cx.editor
            .set_status("no local history yet — snapshots are taken on save");
        return Ok(());
    }
    let cands: Vec<String> = snaps
        .iter()
        .map(|(ts, p)| {
            let age = crate::recent_files::humanize_age(crate::recent_files::age_since(*ts));
            format!("{age}\t{}", p.to_string_lossy())
        })
        .collect();
    queue_fzf(
        cx,
        "LocalHistory",
        "local-history-open {}",
        cands,
        vec!["--no-sort".into()],
        false,
    );
    Ok(())
}

/// Sink for `:LocalHistory` — open the picked snapshot (path is after the tab).
fn local_history_open(
    cx: &mut compositor::Context,
    args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let line = args.join(" ");
    let p = line.rsplit('\t').next().unwrap_or("").trim();
    if !p.is_empty() {
        run_command_line(cx, &format!("open {p}"));
    }
    Ok(())
}

/// `:RecentLocations` — JetBrains Recent Locations (SPC j R): the jump ring shown
/// most-recent-first, deduped by file:line, with each line's text as context;
/// pick one to jump back there.
fn fzf_recent_locations(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let entries: Vec<(zmax_view::DocumentId, usize)> = {
        let (view, _) = current_ref!(cx.editor);
        view.jumps
            .iter()
            .map(|(id, sel)| (*id, sel.primary().head))
            .collect()
    };
    let mut seen = std::collections::HashSet::new();
    let mut cands = Vec::new();
    // Reverse: the jump ring is oldest-first, Recent Locations is newest-first.
    for (id, pos) in entries.into_iter().rev() {
        let Some(doc) = cx.editor.document(id) else {
            continue;
        };
        let Some(path) = doc.path().map(|p| p.to_string_lossy().into_owned()) else {
            continue;
        };
        let text = doc.text();
        let p = pos.min(text.len_chars());
        let line = text.char_to_line(p) + 1;
        if !seen.insert((path.clone(), line)) {
            continue;
        }
        let ltext = text.line(line - 1).to_string();
        cands.push(format!("{path}:{line}:1: {}", ltext.trim_end()));
    }
    queue_fzf(
        cx,
        "RecentLocations",
        "fzf-goto {}",
        cands,
        vec!["--no-sort".into()],
        false,
    );
    Ok(())
}

/// fzf.vim `:Windows` — fuzzy-pick an open window and focus it.
fn fzf_windows(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let docs: Vec<zmax_view::DocumentId> = cx.editor.tree.views().map(|(v, _)| v.doc).collect();
    let cands: Vec<String> = docs
        .iter()
        .enumerate()
        .map(|(i, id)| {
            let name = cx
                .editor
                .document(*id)
                .map(|d| d.display_name().into_owned())
                .unwrap_or_else(|| "[scratch]".into());
            format!("{}: {name}", i + 1)
        })
        .collect();
    queue_fzf(
        cx,
        "Windows",
        "fzf-window {}",
        cands,
        vec!["+m".into()],
        false,
    );
    Ok(())
}

/// Sink for `:Windows` — focus the Nth window (1-based, matching the list order).
fn fzf_window(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let num: String = args
        .join(" ")
        .chars()
        .take_while(|c| c.is_ascii_digit())
        .collect();
    let Ok(n) = num.parse::<usize>() else {
        return Ok(());
    };
    if n == 0 {
        return Ok(());
    }
    let view_ids: Vec<zmax_view::ViewId> = cx.editor.tree.views().map(|(v, _)| v.id).collect();
    if let Some(&id) = view_ids.get(n - 1) {
        cx.editor.focus(id);
    }
    Ok(())
}

/// fzf.vim `:Marks` — fuzzy-pick a mark in the current buffer and jump to it.
fn fzf_marks(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    // Emit every mark as `file:line:col: <mark>  <text>` and jump with the
    // `fzf-goto` sink, so both the current buffer's local marks (a–z) and the
    // editor's global marks (A–Z, persisted in .zmaxinfo, possibly in other
    // files) are listed and jumpable. Previously only local marks were shown, so
    // with only global marks set the candidate list was empty and fzf fell back
    // to its default command (listing files).
    let mut cands: Vec<String> = Vec::new();

    // Local marks of the current buffer (need its on-disk path for cross-file goto).
    {
        let (_, doc) = current_ref!(cx.editor);
        if let Some(path) = doc.path() {
            let path = path.to_string_lossy().into_owned();
            let text = doc.text().slice(..);
            let mut m: Vec<(usize, char)> =
                doc.marks().iter().map(|(&ch, &pos)| (pos, ch)).collect();
            m.sort();
            for (pos, ch) in m {
                let p = pos.min(text.len_chars());
                let coords = zmax_core::coords_at_pos(text, p);
                let ltext = text.line(coords.row).to_string();
                // `file:line:col:` prefix is required by the `fzf-goto` sink but
                // hidden from the display via `--with-nth` (below); field 4 is
                // `<mark>  L<line>  <text>` so the mark name stays visible.
                cands.push(format!(
                    "{path}:{}:{}:{ch}  L{}  {}",
                    coords.row + 1,
                    coords.col + 1,
                    coords.row + 1,
                    ltext.trim_end()
                ));
            }
        }
    }

    // Global marks (A–Z), stored on the editor and persisted in .zmaxinfo.
    {
        let mut g: Vec<(char, zmax_view::GlobalMark)> = cx
            .editor
            .global_marks
            .iter()
            .map(|(&c, m)| (c, m.clone()))
            .collect();
        g.sort_by_key(|(c, _)| *c);
        for (ch, m) in g {
            let path = m.path.to_string_lossy().into_owned();
            // Global marks show the mark, its line, and the file they point to.
            cands.push(format!(
                "{path}:{}:{}:{ch}  L{}  {path}",
                m.line + 1,
                m.col + 1,
                m.line + 1
            ));
        }
    }

    if cands.is_empty() {
        cx.editor.set_status("No marks set");
        return Ok(());
    }

    // Display only field 4+ (`<mark>  L<line>  <text>`) so the mark name is
    // visible instead of a long `file:line:col:` prefix; the sink still receives
    // the full line and `fzf-goto` parses the leading location.
    queue_fzf(
        cx,
        "Marks",
        "fzf-goto {}",
        cands,
        vec![
            "--no-sort".into(),
            "--delimiter=:".into(),
            "--with-nth=4..".into(),
        ],
        false,
    );
    Ok(())
}

/// fzf.vim `:Tags` — ctags across the whole tree; jump to the picked tag.
/// `ctags -x` columns are `name kind line file text…`; awk reorders to
/// `file:line:col: name` so the existing `fzf-goto` sink can open it.
fn fzf_tags(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event == PromptEvent::Validate {
        let cmd = "ctags -x -R . 2>/dev/null | awk '{print $4\":\"$3\":1: \"$1}'".to_string();
        queue_fzf_cmd(
            cx,
            "Tags",
            "fzf-goto {}",
            cmd,
            vec!["--no-sort".into()],
            false,
        );
    }
    Ok(())
}

/// fzf.vim `:BTags` — ctags for the current file only.
fn fzf_btags(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let path = {
        let (_, doc) = current_ref!(cx.editor);
        doc.path().map(|p| p.to_string_lossy().into_owned())
    };
    let Some(path) = path else {
        cx.editor.set_error(":BTags requires a file on disk");
        return Ok(());
    };
    let cmd = format!(
        "ctags -x '{}' 2>/dev/null | awk '{{print $4\":\"$3\":1: \"$1}}'",
        path.replace('\'', "'\\''")
    );
    queue_fzf_cmd(
        cx,
        "BTags",
        "fzf-goto {}",
        cmd,
        vec!["--no-sort".into()],
        false,
    );
    Ok(())
}

/// fzf.vim `:Snippets` — fuzzy-pick a snippet trigger and insert its body.
fn fzf_snippets(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let store = crate::snippet_store::load();
    let cands: Vec<String> = store
        .snippets
        .iter()
        .map(|s| format!("{}\t{}\t{}", s.trigger, s.scope, s.description))
        .collect();
    queue_fzf(
        cx,
        "Snippets",
        "fzf-snippet {}",
        cands,
        vec!["+m".into()],
        false,
    );
    Ok(())
}

/// Sink for `:Snippets` — insert the picked snippet's body at the cursor.
fn fzf_snippet(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let line = args.join(" ");
    let trigger = line.split('\t').next().unwrap_or("").trim();
    if trigger.is_empty() {
        return Ok(());
    }
    let store = crate::snippet_store::load();
    let (view, doc) = current!(cx.editor);
    let lang = doc.language_name().map(|s| s.to_string());
    let Some(snip) = store.find_trigger(lang.as_deref(), trigger) else {
        return Ok(());
    };
    let body: zmax_core::Tendril = snip.body.clone().into();
    let sel = doc.selection(view.id).clone();
    let tx = zmax_core::Transaction::change_by_selection(doc.text(), &sel, |r| {
        (r.from(), r.to(), Some(body.clone()))
    });
    doc.apply(&tx, view.id);
    Ok(())
}

/// fzf.vim `:Maps` — fuzzy-browse the live keymaps (`mode  keys  command`). The
/// keymap lives on EditorView (compositor), so candidates are gathered in a
/// callback that then hands the fzf request to the editor.
fn fzf_maps(cx: &mut compositor::Context, _args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let call: job::Callback = job::Callback::EditorCompositor(Box::new(
        move |editor: &mut Editor, compositor: &mut Compositor| {
            use zmax_view::document::Mode;
            let Some(view) = compositor.find::<crate::ui::EditorView>() else {
                return;
            };
            let maps = view.keymaps.map();
            let mut cands = Vec::new();
            for mode in [Mode::Normal, Mode::Insert, Mode::Select] {
                let Some(trie) = maps.get(&mode) else {
                    continue;
                };
                let mut rows: Vec<(String, String)> = trie
                    .reverse_map()
                    .iter()
                    .flat_map(|(name, binds)| {
                        let name = name.clone();
                        binds.iter().map(move |b| {
                            (
                                b.iter()
                                    .map(|k| k.key_sequence_format())
                                    .collect::<String>(),
                                name.clone(),
                            )
                        })
                    })
                    .collect();
                rows.sort();
                for (keys, name) in rows {
                    cands.push(format!("{mode:?}\t{keys}\t{name}"));
                }
            }
            editor.pending_fzf = Some(zmax_view::editor::FzfRequest {
                candidates: cands,
                prompt: "Maps".to_string(),
                sink: "fzf-map {}".to_string(),
                options: vec!["--no-sort".into()],
                preview: false,
                command: None,
            });
        },
    ));
    cx.jobs.callback(async move { Ok(call) });
    Ok(())
}

/// Sink for `:Maps` — echo the picked mapping (discovery; zmax doesn't replay
/// key chords the way Vim's `:Maps` re-executes them).
fn fzf_map(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let line = args.join(" ");
    if !line.trim().is_empty() {
        cx.editor.set_status(line.replace('\t', "  "));
    }
    Ok(())
}

/// fzf.vim `:Helptags` — fuzzy-pick a help tag (command / `:typable` / topic)
/// and open the inline Help browser pre-filtered to it.
fn fzf_helptags(
    cx: &mut compositor::Context,
    _args: Args,
    event: PromptEvent,
) -> anyhow::Result<()> {
    if event == PromptEvent::Validate {
        let cands = crate::ui::help::HelpPanel::new().entry_titles();
        queue_fzf(
            cx,
            "Helptags",
            "fzf-helptag {}",
            cands,
            vec!["+m".into()],
            false,
        );
    }
    Ok(())
}

/// Sink for `:Helptags` — open the Help browser filtered to the picked tag.
fn fzf_helptag(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let title = args.join(" ").trim().to_string();
    if title.is_empty() {
        return Ok(());
    }
    let call: job::Callback = job::Callback::EditorCompositor(Box::new(
        move |_editor: &mut Editor, compositor: &mut Compositor| {
            compositor.push(Box::new(
                crate::ui::preferences::PreferencesPanel::new_help(title.clone()),
            ));
        },
    ));
    cx.jobs.callback(async move { Ok(call) });
    Ok(())
}

/// vim `:helpgrep {pattern}` / `:lhelpgrep` — search the help. zmax opens its
/// inline Help browser filtered to `{pattern}` (over all commands / keys /
/// topics) rather than grepping raw help-file text into a quickfix / location
/// list, so this is a partial port of a different model.
fn help_grep(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
    if event != PromptEvent::Validate {
        return Ok(());
    }
    let pat = args.join(" ").trim().to_string();
    if pat.is_empty() {
        bail!("usage: :helpgrep {{pattern}}");
    }
    let call: job::Callback = job::Callback::EditorCompositor(Box::new(
        move |_editor: &mut Editor, compositor: &mut Compositor| {
            compositor.push(Box::new(
                crate::ui::preferences::PreferencesPanel::new_help(pat.clone()),
            ));
        },
    ));
    cx.jobs.callback(async move { Ok(call) });
    Ok(())
}

/// Shared body of the `:map`-family typable commands: reconstruct the Vim
/// command line and either record a mapping (then re-apply the overlay) or —
/// when there's no rhs — list the current bindings for the command's modes,
/// exactly as vim does.
fn vim_map_cmd(cx: &mut compositor::Context, word: &str, args: &Args) -> anyhow::Result<()> {
    use crate::keymap::vim_map::MapOutcome;
    let line = format!("{word} {}", args.join(" "));
    match crate::keymap::vim_map::register_map_line(line.trim()) {
        Ok(MapOutcome::Applied(desc)) => {
            cx.editor
                .config_events
                .0
                .send(ConfigEvent::ApplyUserMappings)?;
            cx.editor.set_status(format!("map: {desc}"));
            Ok(())
        }
        Ok(MapOutcome::List(modes)) => {
            list_keybinds(cx, modes);
            Ok(())
        }
        Err(e) => Err(anyhow!("{e}")),
    }
}

/// Display the current keybindings for the given editor modes in a scratch
/// buffer — the target of a no-rhs `:map`/`:nmap`/`:vmap` (vim lists mappings).
fn list_keybinds(cx: &mut compositor::Context, modes: Vec<zmax_view::document::Mode>) {
    let call: job::Callback = job::Callback::EditorCompositor(Box::new(
        move |editor: &mut Editor, compositor: &mut Compositor| {
            let Some(view) = compositor.find::<crate::ui::EditorView>() else {
                return;
            };
            let maps = view.keymaps.map();
            let mut out = String::new();
            for mode in &modes {
                let Some(trie) = maps.get(mode) else { continue };
                let mut rows: Vec<(String, String)> = trie
                    .reverse_map()
                    .iter()
                    .flat_map(|(name, binds)| {
                        let name = name.clone();
                        binds.iter().map(move |b| {
                            (
                                b.iter()
                                    .map(|k| k.key_sequence_format())
                                    .collect::<String>(),
                                name.clone(),
                            )
                        })
                    })
                    .collect();
                rows.sort();
                out.push_str(&format!(
                    "--- {mode:?} mode — {} bindings ---\n",
                    rows.len()
                ));
                for (keys, name) in rows {
                    out.push_str(&format!("{keys:<22} {name}\n"));
                }
                out.push('\n');
            }
            if out.is_empty() {
                out.push_str("(no bindings)\n");
            }
            super::show_text_in_scratch(editor, &out);
        },
    ));
    cx.jobs.callback(async move { Ok(call) });
}

macro_rules! vim_map_typable {
    ($fn:ident, $word:literal) => {
        fn $fn(cx: &mut compositor::Context, args: Args, event: PromptEvent) -> anyhow::Result<()> {
            if event != PromptEvent::Validate {
                return Ok(());
            }
            vim_map_cmd(cx, $word, &args)
        }
    };
}

vim_map_typable!(vim_map_map, "map");
vim_map_typable!(vim_map_noremap, "noremap");
vim_map_typable!(vim_map_nmap, "nmap");
