        assert_eq!(parse_int_any("255"), Some(255));
        assert_eq!(parse_int_any("0xff"), Some(255));
        assert_eq!(parse_int_any("0b11111111"), Some(255));
        assert_eq!(parse_int_any("0o377"), Some(255));
